-- ----------------------------
-- Table structure for batch_jobs
-- ----------------------------
DROP TABLE IF EXISTS "public"."batch_jobs";
CREATE TABLE "public"."batch_jobs" (
  "id" int8 NOT NULL DEFAULT nextval('batch_jobs_id_seq'::regclass),
  "job_no" text COLLATE "pg_catalog"."default" NOT NULL,
  "task_name" text COLLATE "pg_catalog"."default",
  "capability" "public"."Capability" NOT NULL,
  "status" "public"."BatchJobStatus" NOT NULL DEFAULT 'PENDING'::"BatchJobStatus",
  "source_type" text COLLATE "pg_catalog"."default" NOT NULL,
  "total_count" int4 NOT NULL DEFAULT 0,
  "success_count" int4 NOT NULL DEFAULT 0,
  "failed_count" int4 NOT NULL DEFAULT 0,
  "params_snapshot" jsonb NOT NULL,
  "created_at" timestamp(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "started_at" timestamp(3),
  "finished_at" timestamp(3),
  "export_status" "public"."ExportStatus" NOT NULL DEFAULT 'IDLE'::"ExportStatus",
  "export_file_id" int8,
  "folder_name" text COLLATE "pg_catalog"."default" NOT NULL,
  "style_key" text COLLATE "pg_catalog"."default"
)
;
COMMENT ON COLUMN "public"."batch_jobs"."id" IS '主键ID。';
COMMENT ON COLUMN "public"."batch_jobs"."job_no" IS '批任务编号（业务唯一）。';
COMMENT ON COLUMN "public"."batch_jobs"."task_name" IS '任务名称（可选）。';
COMMENT ON COLUMN "public"."batch_jobs"."capability" IS '图片能力类型。';
COMMENT ON COLUMN "public"."batch_jobs"."status" IS '批任务执行状态。';
COMMENT ON COLUMN "public"."batch_jobs"."source_type" IS '提示词来源类型（text/csv/xlsx/docx/md/txt）。';
COMMENT ON COLUMN "public"."batch_jobs"."total_count" IS '子任务总数。';
COMMENT ON COLUMN "public"."batch_jobs"."success_count" IS '成功子任务数量。';
COMMENT ON COLUMN "public"."batch_jobs"."failed_count" IS '失败子任务数量。';
COMMENT ON COLUMN "public"."batch_jobs"."params_snapshot" IS '任务参数快照（JSON，含模型参数与 template_config）。';
COMMENT ON COLUMN "public"."batch_jobs"."created_at" IS '创建时间。';
COMMENT ON COLUMN "public"."batch_jobs"."started_at" IS '开始执行时间。';
COMMENT ON COLUMN "public"."batch_jobs"."finished_at" IS '结束时间。';
COMMENT ON COLUMN "public"."batch_jobs"."export_status" IS '导出状态。';
COMMENT ON COLUMN "public"."batch_jobs"."export_file_id" IS '关联导出文件ID（唯一，可空）。';
COMMENT ON COLUMN "public"."batch_jobs"."folder_name" IS '任务输出文件夹名称。';
COMMENT ON COLUMN "public"."batch_jobs"."style_key" IS '批次默认风格预设键，作为 job_items.style_key 的兜底来源。';
COMMENT ON TABLE "public"."batch_jobs" IS '批量任务表：记录一次批量图片生成任务的汇总状态。';

