INSERT INTO "public"."batch_jobs" VALUES (42, 'BJ202604271606152DNW', NULL, 'PORTRAIT', 'SUCCESS', 'text', 1, 1, 0, '{"params": {"cfg": 7, "size": "1024x1536", "count": 1, "steps": 30, "negative_prompt": "text, letters, words, characters, calligraphy, handwriting, watermark, logo, signature, label, caption, subtitle, annotation, numbers, digits, symbols, emoji, barcode, qr code, stamp, seal, ui elements, frame, border, speech bubble, callout, info panel, typography on clothing, text on props, readable patterns, extra limbs, extra fingers, missing fingers, deformed hands, blurry, low resolution, pixelated, noise, artifacts"}, "model_key": "midj_default", "task_name": null, "capability": "PORTRAIT", "template_config": {"mode": "template", "preset": "PORTRAIT", "defaults": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。画面严禁出现任何文字、字母、数字、书法、印章、水印、logo、签名、标签、标注、UI 元素、边框、说明框或注释；角色服装、配饰、道具上也不得出现可辨识的文字图案或符号。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "", "part4": ""}, "language_mode": "zh_with_en_reference"}}', '2026-04-27 16:06:15.954', '2026-04-27 16:06:20.991', '2026-04-27 16:09:20.584', 'IDLE', NULL, 'batch-output', NULL);
