INSERT INTO "public"."batch_jobs" VALUES (19, 'BJ202604240419356G78', NULL, 'THREE_VIEW', 'RUNNING', 'docx', 5, 0, 5, '{"params": {"size": "1920x1080", "view_set": ["front", "side", "back"]}, "model_key": "midj_default", "task_name": null, "capability": "THREE_VIEW", "template_config": {"mode": "template", "preset": "THREE_VIEW", "defaults": {"part1": "基于人物定妆照生成人物三视图\n（16：9）面部占满左区，五官 / 发型 / 配饰清晰，无身体入镜、无遮挡变形；右区：标准角色设定三视图，横向排列（侧视图、正视图、背视图），三个视图严格呈现侧视、正视和背视，从头到脚完整无遮挡；核心约束：特写与三视图为同一角色，五官 / 服装 / 配饰 / 体态 100% 一致；右区尺寸：三视图角色高度画面高度的 80%，三视图高度统一；无多余元素的浅灰色背景，角色无阴影；超高清分辨率，统一85mm焦距，无畸变，角色无动作，平视；中性表情（无喜怒哀乐），眼神平静，自然站立，双手自然下垂。", "part2": "", "part4": ""}, "language_mode": "zh_with_en_reference"}}', '2026-04-24 04:19:34.71', '2026-04-24 04:23:23.061', NULL, 'IDLE', NULL, 'batch-output', NULL);
INSERT INTO "public"."batch_jobs" VALUES (11, 'BJ20260424033733ER1K', NULL, 'PORTRAIT', 'SUCCESS', 'docx', 5, 5, 0, '{"params": {"cfg": 7, "size": "1024x1536", "count": 1, "steps": 30}, "model_key": "midj_default", "task_name": null, "capability": "PORTRAIT", "template_config": {"mode": "template", "preset": "PORTRAIT", "defaults": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "", "part4": ""}, "language_mode": "zh_with_en_reference"}}', '2026-04-24 03:37:32.586', '2026-04-24 03:39:01.801', '2026-04-24 11:41:40.887', 'IDLE', NULL, 'batch-output', NULL);
