INSERT INTO "public"."batch_jobs" VALUES (22, 'BJ202604240444233N20', NULL, 'THREE_VIEW', 'SUCCESS', 'docx', 5, 5, 0, '{"params": {"size": "1920x1080", "view_set": ["front", "side", "back"]}, "model_key": "Nano Banana Pro", "task_name": null, "capability": "THREE_VIEW", "template_config": {"mode": "template", "preset": "THREE_VIEW", "defaults": {"part1": "基于人物定妆照生成人物三视图\n（16：9）面部占满左区，五官 / 发型 / 配饰清晰，无身体入镜、无遮挡变形；右区：标准角色设定三视图，横向排列（侧视图、正视图、背视图），三个视图严格呈现侧视、正视和背视，从头到脚完整无遮挡；核心约束：特写与三视图为同一角色，五官 / 服装 / 配饰 / 体态 100% 一致；右区尺寸：三视图角色高度画面高度的 80%，三视图高度统一；无多余元素的浅灰色背景，角色无阴影；超高清分辨率，统一85mm焦距，无畸变，角色无动作，平视；中性表情（无喜怒哀乐），眼神平静，自然站立，双手自然下垂。", "part2": "", "part4": ""}, "language_mode": "zh_with_en_reference"}}', '2026-04-24 04:44:22.919', '2026-04-24 04:44:23.767', '2026-04-24 16:29:00.011', 'IDLE', NULL, 'test-2', NULL);
