-- ----------------------------
-- Table structure for export_files
-- ----------------------------
DROP TABLE IF EXISTS "public"."export_files";
CREATE TABLE "public"."export_files" (
  "id" int8 NOT NULL DEFAULT nextval('export_files_id_seq'::regclass),
  "status" "public"."ExportStatus" NOT NULL DEFAULT 'PENDING'::"ExportStatus",
  "file_name" text COLLATE "pg_catalog"."default" NOT NULL,
  "file_size" int8,
  "nas_provider" text COLLATE "pg_catalog"."default" NOT NULL,
  "nas_container" text COLLATE "pg_catalog"."default" NOT NULL,
  "nas_object_key" text COLLATE "pg_catalog"."default" NOT NULL,
  "access_url" text COLLATE "pg_catalog"."default",
  "error_message" text COLLATE "pg_catalog"."default",
  "created_at" timestamp(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "updated_at" timestamp(3) NOT NULL
)
;
COMMENT ON COLUMN "public"."export_files"."id" IS '主键ID。';
COMMENT ON COLUMN "public"."export_files"."status" IS '导出状态。';
COMMENT ON COLUMN "public"."export_files"."file_name" IS '导出文件名。';
COMMENT ON COLUMN "public"."export_files"."file_size" IS '导出文件大小（字节）。';
COMMENT ON COLUMN "public"."export_files"."nas_provider" IS 'NAS 存储提供方（如 synology/s3/webdav/local）。';
COMMENT ON COLUMN "public"."export_files"."nas_container" IS 'NAS 存储容器（桶名/共享目录）。';
COMMENT ON COLUMN "public"."export_files"."nas_object_key" IS 'NAS 对象键或相对路径。';
COMMENT ON COLUMN "public"."export_files"."access_url" IS '导出文件访问地址（可为空）。';
COMMENT ON COLUMN "public"."export_files"."error_message" IS '导出失败错误信息。';
COMMENT ON COLUMN "public"."export_files"."created_at" IS '导出记录创建时间。';
COMMENT ON COLUMN "public"."export_files"."updated_at" IS '导出记录更新时间（由应用层维护）。';
COMMENT ON TABLE "public"."export_files" IS '导出文件表：记录批任务导出的 ZIP 文件信息。';

-- ----------------------------
-- Records of export_files
-- ----------------------------
