-- ----------------------------
-- Table structure for image_results
-- ----------------------------
DROP TABLE IF EXISTS "public"."image_results";
CREATE TABLE "public"."image_results" (
  "id" int8 NOT NULL DEFAULT nextval('image_results_id_seq'::regclass),
  "batch_job_id" int8 NOT NULL,
  "job_item_id" int8 NOT NULL,
  "capability" "public"."Capability" NOT NULL,
  "view_type" text COLLATE "pg_catalog"."default",
  "variant_index" int4 NOT NULL,
  "format" text COLLATE "pg_catalog"."default" NOT NULL,
  "width" int4 NOT NULL,
  "height" int4 NOT NULL,
  "file_size" int8 NOT NULL,
  "sha256" text COLLATE "pg_catalog"."default" NOT NULL,
  "nas_provider" text COLLATE "pg_catalog"."default" NOT NULL,
  "nas_container" text COLLATE "pg_catalog"."default" NOT NULL,
  "nas_object_key" text COLLATE "pg_catalog"."default" NOT NULL,
  "access_url" text COLLATE "pg_catalog"."default",
  "created_at" timestamp(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "is_selected_portrait" bool NOT NULL DEFAULT false,
  "selected_at" timestamptz(6)
)
;
COMMENT ON COLUMN "public"."image_results"."id" IS '主键ID。';
COMMENT ON COLUMN "public"."image_results"."batch_job_id" IS '所属批任务ID。';
COMMENT ON COLUMN "public"."image_results"."job_item_id" IS '所属子任务ID。';
COMMENT ON COLUMN "public"."image_results"."capability" IS '图片能力类型。';
COMMENT ON COLUMN "public"."image_results"."view_type" IS '三视图视角类型（front/side/back，可空）。';
COMMENT ON COLUMN "public"."image_results"."variant_index" IS '同一子任务下的结果序号。';
COMMENT ON COLUMN "public"."image_results"."format" IS '图片格式（png/jpg/webp）。';
COMMENT ON COLUMN "public"."image_results"."width" IS '图片宽度。';
COMMENT ON COLUMN "public"."image_results"."height" IS '图片高度。';
COMMENT ON COLUMN "public"."image_results"."file_size" IS '图片大小（字节）。';
COMMENT ON COLUMN "public"."image_results"."sha256" IS '图片内容哈希（SHA-256）。';
COMMENT ON COLUMN "public"."image_results"."nas_provider" IS 'NAS 存储提供方。';
COMMENT ON COLUMN "public"."image_results"."nas_container" IS 'NAS 存储容器（桶名/共享目录）。';
COMMENT ON COLUMN "public"."image_results"."nas_object_key" IS 'NAS 对象键或相对路径（唯一）。';
COMMENT ON COLUMN "public"."image_results"."access_url" IS '图片访问地址（可空）。';
COMMENT ON COLUMN "public"."image_results"."created_at" IS '记录创建时间。';
COMMENT ON COLUMN "public"."image_results"."is_selected_portrait" IS '是否被选中作为定妆照（仅 capability=PORTRAIT 的图片有意义）。';
COMMENT ON COLUMN "public"."image_results"."selected_at" IS '该图片被选中作为定妆照的时间。is_selected_portrait=false 时应为 NULL。';
COMMENT ON TABLE "public"."image_results" IS '图片结果表：记录子任务产出的图片文件及 NAS 存储信息。';

