-- ----------------------------
-- Table structure for import_files
-- ----------------------------
DROP TABLE IF EXISTS "public"."import_files";
CREATE TABLE "public"."import_files" (
  "id" int8 NOT NULL DEFAULT nextval('import_files_id_seq'::regclass),
  "batch_job_id" int8,
  "file_name" text COLLATE "pg_catalog"."default" NOT NULL,
  "file_type" text COLLATE "pg_catalog"."default" NOT NULL,
  "file_size" int8 NOT NULL,
  "parse_status" "public"."ImportTaskStatus" NOT NULL DEFAULT 'QUEUED'::"ImportTaskStatus",
  "parse_error" text COLLATE "pg_catalog"."default",
  "created_at" timestamp(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "submit_mode" "public"."ImportSubmitMode" NOT NULL DEFAULT 'PARSE_ONLY'::"ImportSubmitMode",
  "result_payload" jsonb,
  "batch_payload" jsonb,
  "source_text" text COLLATE "pg_catalog"."default",
  "source_file_bytes" bytea,
  "retry_count" int4 NOT NULL DEFAULT 0,
  "max_retry" int4 NOT NULL DEFAULT 3,
  "next_retry_at" timestamptz(6),
  "error_code" text COLLATE "pg_catalog"."default",
  "worker_id" text COLLATE "pg_catalog"."default",
  "started_at" timestamptz(6),
  "finished_at" timestamptz(6),
  "locked_at" timestamptz(6)
)
;
COMMENT ON COLUMN "public"."import_files"."id" IS '主键ID。';
COMMENT ON COLUMN "public"."import_files"."batch_job_id" IS '关联批任务ID（可空）。';
COMMENT ON COLUMN "public"."import_files"."file_name" IS '导入文件名。';
COMMENT ON COLUMN "public"."import_files"."file_type" IS '文件类型（csv/xlsx/docx/md/txt 等）。';
COMMENT ON COLUMN "public"."import_files"."file_size" IS '文件大小（字节）。';
COMMENT ON COLUMN "public"."import_files"."parse_status" IS '导入任务状态。';
COMMENT ON COLUMN "public"."import_files"."parse_error" IS '错误信息。';
COMMENT ON COLUMN "public"."import_files"."created_at" IS '导入记录创建时间。';
COMMENT ON COLUMN "public"."import_files"."submit_mode" IS '提交模式：仅解析或解析后自动创建批任务。';
COMMENT ON COLUMN "public"."import_files"."result_payload" IS '解析结果快照（JSON）。';
COMMENT ON COLUMN "public"."import_files"."batch_payload" IS '自动建批所需参数快照（JSON）。';
COMMENT ON COLUMN "public"."import_files"."source_text" IS '文本导入时保存的原始文本。';
COMMENT ON COLUMN "public"."import_files"."source_file_bytes" IS '文件导入时保存的原始文件字节。';
COMMENT ON COLUMN "public"."import_files"."retry_count" IS '当前重试次数。';
COMMENT ON COLUMN "public"."import_files"."max_retry" IS '最大允许重试次数。';
COMMENT ON COLUMN "public"."import_files"."next_retry_at" IS '下次可重试时间。';
COMMENT ON COLUMN "public"."import_files"."error_code" IS '错误码。';
COMMENT ON COLUMN "public"."import_files"."worker_id" IS '处理该任务的 worker 标识。';
COMMENT ON COLUMN "public"."import_files"."started_at" IS '开始处理时间。';
COMMENT ON COLUMN "public"."import_files"."finished_at" IS '结束处理时间。';
COMMENT ON COLUMN "public"."import_files"."locked_at" IS '任务锁定时间。';
COMMENT ON TABLE "public"."import_files" IS '导入文件表：记录导入文件解析过程与状态。';

