INSERT INTO "public"."import_files" VALUES (5, NULL, 'inline-text.txt', 'text', 340, 'BATCH_CREATED', NULL, '2026-04-23 10:23:07.03', 'CREATE_BATCH', '{"errors": [], "prompts": [{"prompt": "Sophie, a 5-year-old Caucasian girl, resembling actress Brooklynn Prince, extremely pale almost translucent paper-thin skin with faint blue veins visible beneath, delicate child-like facial features, soft round cheeks, wide innocent eyes\n\n风格：A raw, hyper-realistic cinematic three-quarter portrait shot, movie-grade photorealism, shallow depth of field, natural soft diffused lighting, film-grain texture, 85mm lens, 8K resolution\n\n参考风格：\ncharacter design reference sheet feel, neutral simple background, muted cool color palette emphasizing the pale translucent skin, ultra-detailed skin texture, subtle subsurface scattering on skin, cinematic color grading", "line_no": 1, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "Sophie, a 5-year-old Caucasian girl, resembling actress Brooklynn Prince, extremely pale almost translucent paper-thin skin with faint blue veins visible beneath, delicate child-like facial features, soft round cheeks, wide innocent eyes", "part2": "A raw, hyper-realistic cinematic three-quarter portrait shot, movie-grade photorealism, shallow depth of field, natural soft diffused lighting, film-grain texture, 85mm lens, 8K resolution", "part4": "character design reference sheet feel, neutral simple background, muted cool color palette emphasizing the pale translucent skin, ultra-detailed skin texture, subtle subsurface scattering on skin, cinematic color grading"}, "negative_prompt": null}], "raw_count": 2, "source_type": "text", "valid_count": 1, "invalid_count": 0}', '{"dedupe": false, "params": {}, "task_name": null, "capability": "PORTRAIT", "parse_mode": "claude", "folder_name": "test", "submit_mode": "CREATE_BATCH", "idempotency_key": null, "template_config": {"mode": "template", "preset": "PORTRAIT", "defaults": {}, "langua