INSERT INTO "public"."import_files" VALUES (6, NULL, 'character-text.txt', 'txt', 5188, 'BATCH_CREATED', NULL, '2026-04-23 10:23:35.242', 'CREATE_BATCH', '{"errors": [], "prompts": [{"prompt": "A raw, hyper-realistic cinematic three-quarter portrait shot of Sophie, a 5-year-old Caucasian girl, resembling actress Brooklynn Prince, sitting in a decaying bedroom\n\n风格：Extremely pale, almost translucent paper-thin skin with faint blue veins visible beneath. Lips are a heart-wrenching cyanotic purple due to oxygen deprivation. Thin, wispy, lackluster dull flaxen blonde short hair, looking dry and sparse from malnutrition. Large, clear light blue eyes set in slightly sunken sockets, filled with a melancholy and timid grown-up wisdom. Tiny frail frame completely swallowed by multiple layers of thick, heavy, pilled wool blankets with visible stains. Underneath, an oversized, coarse, faded old sweater with sleeves so long they cover her hands. One small hand instinctively clutching a silver cross necklace like holding onto a lifeline. Mouth slightly open, gasping for breath with visible effort in her chest. Brow slightly furrowed in an anxious, sorry-to-be-a-burden expression\n\n参考风格：\nCold, dim, decaying bedroom background with peeling paint, heavily blurred and out of focus. Shot on 35mm film, visible grain, Arri Alexa 65 aesthetic, melancholic dim lighting, muted desaturated palette. --ar 2:3 --v 7.0 --style raw", "line_no": 1, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "A raw, hyper-realistic cinematic three-quarter portrait shot of Sophie, a 5-year-old Caucasian girl, resembling actress Brooklynn Prince, sitting in a decaying bedroom", "part2": "Extremely pale, almost translucent paper-thin skin with faint blue veins visible beneath. Lips are a heart-wrenching cyanotic purple due to oxygen deprivation. Thin, wispy, lackluster dull flaxen blonde short hair, looking dry and sparse from malnutrition. Large, clear light blue eyes set in slightly sunken sockets, filled with a melancholy and timid grown-up wisdom. Tiny frail frame completely swallowed by multiple layers of thick, heavy, pilled wool blankets with visible stains. Underneath, an oversized, coarse, faded old sweater with sleeves so long they cover her hands. One small hand instinctively clutching a silver cross necklace like holding onto a lifeline. Mouth slightly open, gasping for breath with visible effort in her chest. Brow slightly furrowed in an anxious, sorry-to-be-a-burden expression", "part4": "Cold, dim, decaying bedroom background with peeling paint, heavily blurred and out of focus. Shot on 35mm film, visible grain, Arri Alexa 65 aesthetic, melancholic dim lighting, muted desaturated palette. --ar 2:3 --v 7.0 --style raw"}, "negative_prompt": null}, {"prompt": "A raw, hyper-realistic cinematic three-quarter portrait of Elena Voss, a 26-year-old Caucasian mixed-race woman, exuding the lethal elegance of a Bengal leopard cat, an apex predator wielding intelligence and allure as weapons\n\n风格：Warm olive-toned skin, striking frost-grey cat-shaped eyes with an unwavering razor-sharp gaze. Thick, voluminous, dark black curly hair cascading past her shoulders. Full sensuous M-shaped lips in a muted rose tone, sculpted high cheekbones, classic hourglass figure. Wearing a Valentino scarlet red haute couture open-back gown that clings to her silhouette, a delicate silver cross necklace resting at her collarbone. Expression is calm and decisive with a faint knowing smirk — the look of someone awakened from victimhood into calculated, seductive control. One hand lightly touching her necklace, posture poised and commanding\n\n参考风格：\nDimly lit opulent manor interior background with dark mahogany paneling and deep velvet textures, heavily blurred and out of focus. Shot on 35mm film, visible grain, Arri Alexa 65 aesthetic, dramatic chiaroscuro lighting with warm amber key light and cold blue shadow. --ar 2:3 --v 7.0 --style raw", "line_no":