INSERT INTO "public"."import_files" VALUES (29, 24, 'inline-text.txt', 'text', 1621, 'BATCH_CREATED', NULL, '2026-04-24 05:18:17.445', 'CREATE_BATCH', '{"errors": [], "prompts": [{"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：角色名：陆观。31岁中国男性，身高178cm，身形消瘦偏瘦长，面容清俊书卷气。黑色眼睛，目光沉稳内敛带一丝坚定。黑色短发，发丝间夹杂数缕醒目的银白色发丝，形成独特的黑白相间视觉标记。肤色偏白。表情自然克制，略带内敛沉思感。身穿一件深灰色立领外套，面料略显磨旧但干净整洁，立领设计贴合颈部，外套版型修身偏窄，衬托消瘦体型；内搭深色简约衬衫或高领内衣。下身搭配深色长裤、深色系带靴。无夸张饰品，整体造型简洁朴素，带有书生气质与末世生存感并存的风格。\n\n参考风格：\n画风：写实偏影视质感，半身至全身均可，光线柔和冷调，突出银白发丝与深灰外套的色彩对比，背景浅灰纯色。", "line_no": 1, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色名：陆观。31岁中国男性，身高178cm，身形消瘦偏瘦长，面容清俊书卷气。黑色眼睛，目光沉稳内敛带一丝坚定。黑色短发，发丝间夹杂数缕醒目的银白色发丝，形成独特的黑白相间视觉标记。肤色偏白。表情自然克制，略带内敛沉思感。身穿一件深灰色立领外套，面料略显磨旧但干净整洁，立领设计贴合颈部，外套版型修身偏窄，衬托消瘦体型；内搭深色简约衬衫或高领内衣。下身搭配深色长裤、深色系带靴。无夸张饰品，整体造型简洁朴素，带有书生气质与末世生存感并存的风格。", "part4": "画风：写实偏影视质感，半身至全身均可，光线柔和冷调，突出银白发丝与深灰外套的色彩对比，背景浅灰纯色。"}, "character_name": null, "negative_prompt": null}, {"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：角色名：安德烈。35岁北欧/斯拉夫裔男性，身高190cm，身形魁梧厚实如熊，肩宽体壮，肌肉线条明显。面容刚毅棱角分明如石刻，颧骨高挺，下颌线锋利。蓝色眼睛深邃冰冷，目光具有压迫感。金色短发整齐利落，发型偏军事风格。肤色偏白略带寒原粗粝感，可有轻微胡茬。表情冷峻威严，嘴角紧抿。身穿一件深蓝色军装式外套，版型硬挺合体，肩部有肩章结构，胸前及领口佩戴数枚象征战功的金属勋章，勋章质感为黄铜/银色金属，做工精细；外套纽扣为金属扣，腰部系军用皮带，皮带扣有纹章图案。下身搭配深色军装长裤、黑色高筒军靴。整体造型充满北境军事强权气质，威压感强烈。\n\n参考风格：\n画风：写实偏影视质感，全身或四分之三身，光线冷硬，侧光强调面部棱角与金属勋章高光，深蓝色军装与金色短发形成对比，背景浅灰偏冷色纯色。", "line_no": 2, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色名：安德烈。35岁北欧/斯拉夫裔男性，身高190cm，身形魁梧厚实如熊，肩宽体壮，肌肉线条明显。面容刚毅棱角分明如石刻，颧骨高挺，下颌线锋利。蓝色眼睛深邃冰冷，目光具有压迫感。金色短发整齐利落，发型偏军事风格。肤色偏白略带寒原粗粝感，可有轻微胡茬。表情冷峻威严，嘴角紧抿。身穿一件深蓝色军装式外套，版型硬挺合体，肩部有肩章结构，胸前及领口佩戴数枚象征战功的金属勋章，勋章质感为黄铜/银色金属，做工精细；外套纽扣为金属扣，腰部系军用皮带，皮带扣有纹章图案。下身搭配深色军装长裤、黑色高筒军靴。整体造型充满北境军事强权气质，威压感强烈。", "part4": "画风：写实偏影视质感，全身或四分之三身，光线冷硬，侧光强调面部棱角与金属勋章高光，深蓝色军装与金色短发形成对比，背景浅灰偏冷色纯色。"}, "character_name": null, "negative_prompt": null}, {"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：角色名：千岛凛。28岁日本女性，身高165cm，身形纤细修长如柳，体态挺拔，腰肢细窄。面容清冷似霜，五官精致偏冷感，眉目间透出锐利肃杀之气。黑色眼睛锐利如刀，瞳色深黑。黑色长发丝滑顺直，束成一丝不苟的高马尾，马尾垂于脑后，发丝服帖无碎发，额前无刘海或仅有极简利落的侧分。肤色白皙。表情冷淡克制，嘴唇微抿，几乎无笑意。身穿一套黑色改良制服，整体为黑色基调，制服上身为立领或小翻领短款外衣，裁剪利落贴身，袖口收紧；下身搭配黑色修身长裤或制服裙裤，腰间系窄带。腰侧配挂一柄古朴武士刀，刀鞘为深色木质或漆面，刀柄缠绕传统菱形编织绳，刀镡（护手）为简朴铁制圆形。足蹬黑色低跟短靴。整体造型极简肃穆，兼具学者冷峻与武士锋锐。\n\n参考风格：\n画风：写实偏影视质感，全身构图，光线冷净偏侧光，突出黑色制服的面料层次与武士刀细节，背景浅灰偏暖白纯色，衬托角色全黑造型轮廓。", "line_no": 3, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色名：千岛凛。28岁日本女性，身高165cm，身形纤细修长如柳，体态挺拔，腰肢细窄。面容清冷似霜，五官精致偏冷感，眉目间透出锐利肃杀之气。黑色眼睛锐利如刀，瞳色深黑。黑色长发丝滑顺直，束成一丝不苟的高马尾，马尾垂于脑后，发丝服帖无碎发，额前无刘海或仅有极简利落的侧分。肤色白皙。表情冷淡克制，嘴唇微抿，几乎无笑意。身穿一套黑色改良制服，整体为黑色基调，制服上身为立领或小翻领短款外衣，裁剪利落贴身，袖口收紧；下身搭配黑色修身长裤或制服裙裤，腰间系窄带。腰侧配挂一柄古朴武士刀，刀鞘为深色木质或漆面，刀柄缠绕传统菱形编织绳，刀镡（护手）为简朴铁制圆形。足蹬黑色低跟短靴。整体造型极简肃穆，兼具学者冷峻与武士锋锐。", "part4": "画风：写实偏影视质感，全身构图，光线冷净偏侧光，突出黑色制服的面料层次与武士刀细节，背景浅灰偏暖白纯色，衬托角色全黑造型轮廓。"}, "character_name": null, "negative_prompt": null}, {"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：角色名：阿米尔。40岁南亚/印度裔男性，身高175cm，身形匀称稳健，体态端正从容，既不魁梧也不纤细，带有成熟儒雅的稳重感。面容温和，眉目舒展，常带淡淡笑意，面部轮廓柔和但不失骨感，鼻梁挺直。棕色眼睛温润深沉，充满睿智洞察之感。黑色卷发中长，自然卷曲蓬松，发间已染有几缕银丝，银黑交织显出智者气质。肤色为温暖的小麦棕色。头戴一顶绣金头巾，头巾为浅金色或米白色织物，边缘与正面饰有精致金线刺绣纹样，包裹方式为传统南亚贵族式缠法，露出额头上方部分卷发。身穿白色亚麻长袍，面料为天然亚麻质感，略有纹理但整洁，长袍至脚踝，领口与袖口有细密金线暗纹装饰，腰间以一条绣金织带束腰。足蹬浅棕色皮质凉鞋或软底鞋。手部可佩戴一枚古朴金属指环。整体造型温和尊贵，兼具外交官的儒雅与古老贵族的沉稳底蕴。\n\n参考风格：\n画风：写实偏影视质感，全身构图，光线温暖柔和，侧顺光突出白色亚麻长袍的面料质感与绣金头巾细节，背景浅灰偏暖调纯色，衬托角色温润气质。", "line_no": 4, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色名：阿米尔。40岁南亚/印度裔男性，身高175cm，身形匀称稳健，体态端正从容，既不魁梧也不纤细，带有成熟儒雅的稳重感。面容温和，眉目舒展，常带淡淡笑意，面部轮廓柔和但不失骨感，鼻梁挺直。棕色眼睛温润深沉，充满睿智洞察之感。黑色卷发中长，自然卷曲蓬松，发间已染有几缕银丝，银黑交织显出智者气质。肤色为温暖的小麦棕色。头戴一顶绣金头巾，头巾为浅金色或米白色织物，边缘与正面饰有精致金线刺绣纹样，包裹方式为传统南亚贵族式缠法，露出额头上方部分卷发。身穿白色亚麻长袍，面料为天然亚麻质感，略有纹理但整洁，长袍至脚踝，领口与袖口有细密金线暗纹装饰，腰间以一条绣金织带束腰。足蹬浅棕色皮质凉鞋或软底鞋。手部可佩戴一枚古朴金属指环。整体造型温和尊贵，兼具外交官的儒雅与古老贵族的沉稳底蕴。", "part4": "画风：写实偏影视质感，全身构图，光线温暖柔和，侧顺光突出白色亚麻长袍的面料质感与绣金头巾细节，背景浅灰偏暖调纯色，衬托角色温润气质。"}, "character_name": null, "negative_prompt": null}], "raw_count": 1, "source_type": "text", "valid_count": 4, "invalid_count": 0}', '{"dedupe": true, "params": {"count": 2}, "task_name": "", "capability": "PORTRAIT", "parse_mode": "claude", "folder_name": "test-3", "submit_mode": "CREATE_BATCH", "idempotency_key": null, "template_config": {"mode": "template", "preset": "PORTRAIT", "defaults": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "", "part4": ""}, "language_mode": "zh_with_en_reference"}}', '主角——陆观31岁，地理系学生，身高178cm，身形消瘦，面容清俊，黑色眼睛，黑色短发中夹杂着几缕银白色发丝。常穿着一件略显破旧但干净的深灰色立领外套，穿越后决心帮助大夏重振国威。北境同盟代表——安德烈35岁，北境同盟军事代表，身高190cm，身形魁梧如熊，面容刚毅如石刻，蓝色眼睛深邃冰冷，金色短发整齐利落。常穿着一件深蓝色军装式外套，佩戴着象征战功的金属勋章。他出身北境寒原的军事世家，自幼接受严酷训练，目的是在帝王擂台上以绝对武力碾压对手，为同盟夺取能源配额与土地权限，巩固北境在全球的霸权地位。樱花代表——千岛凛28岁，樱花精英学者兼武士，身高165cm，身形纤细如柳，面容清冷似霜，黑色眼睛锐利如刀，黑色长发束成一丝不苟的高马尾。常穿着一套黑色改良制服，配戴一柄古朴武士刀。她来自学阀高层家族，精通历史与战术，目的是通过帝王擂台召唤樱花历史中的强者，赢得科技密钥以提升学阀实力，并暗中抹除其他文明的历史痕迹。天竺代表——阿米尔40岁，天竺联邦外交官兼智者，身高175cm，身形匀称稳健，面容温和带笑，棕色眼睛充满睿智，黑色卷发间已染几缕银丝。常穿着白色亚麻长袍，头戴绣金头巾。他出身天竺古老贵族，深谙历史哲学，目的是在擂台上召唤联邦帝王，竞争能源配额，同时借此机会修复天竺被篡改的历史记忆，重塑联邦文明尊严。', NULL, 0, 3, NULL, NULL, NULL, '2026-04-24 13:18:49.397926+08', '2026-04-24 13:19:50.388+08', NULL);
INSERT INTO "public"."import_files" VALUES (22, 17, '7f576edd-675a-4912-a1a9-47b07f29e90a.docx', 'docx', 11294, 'BATCH_CREATED', NULL, '2026-04-24 03:38:53.41', 'CREATE_BATCH', '{"errors": [], "prompts": [{"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：Evelyn Carter, 26-year-old female, New York investigative journalist. Caucasian, sharp and determined facial features, high cheekbones, defined jawline, intelligent piercing eyes with a faint silver glint in the pupils hinting at latent supernatural heritage. Medium-length dark brown hair with subtle silver-tipped ends, slightly tousled and natural, parted to one side. Light natural makeup, minimal eyeshadow, nude lips, a few small scratches or healing marks on her temple suggesting recent ordeal. Expression resolute, composed, with underlying emotional intensity. Wearing a fitted dark olive green field jacket over a black crew-neck top, slim dark jeans, brown leather ankle boots with low heels. Around her neck a delicate antique silver pendant necklace (her mother''s heirloom) with faint engraved rune-like patterns. A leather crossbody messenger bag slung at her hip. Hands with short practical nails, one wrist bearing a simple watch. Overall style is modern urban practical with a touch of gothic undertone, grounded and realistic. European-American dark fantasy aesthetic, cinematic realism, muted cool color palette with desaturated greens and blacks.\n\n人设：伊芙琳·卡特（Evelyn Carter）\n\n参考风格：\n欧美暗黑奇幻风格，参考《暮光之城》《吸血鬼日记》氛围。26岁纽约女记者，理性倔强，因调查姐姐塞琳娜失踪来到银溪镇。银血家族最后的继承人，拥有支配狼人意志的觉醒之力。从受害者妹妹成长为觉醒女王，最终以自身之血封印恶魔。瞳孔带淡淡银光，母亲遗留的古银项链是关键道具。", "line_no": 1, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "Evelyn Carter, 26-year-old female, New York investigative journalist. Caucasian, sharp and determined facial features, high cheekbones, defined jawline, intelligent piercing eyes with a faint silver glint in the pupils hinting at latent supernatural heritage. Medium-length dark brown hair with subtle silver-tipped ends, slightly tousled and natural, parted to one side. Light natural makeup, minimal eyeshadow, nude lips, a few small scratches or healing marks on her temple suggesting recent ordeal. Expression resolute, composed, with underlying emotional intensity. Wearing a fitted dark olive green field jacket over a black crew-neck top, slim dark jeans, brown leather ankle boots with low heels. Around her neck a delicate antique silver pendant necklace (her mother''s heirloom) with faint engraved rune-like patterns. A leather crossbody messenger bag slung at her hip. Hands with short practical nails, one wrist bearing a simple watch. Overall style is modern urban practical with a touch of gothic undertone, grounded and realistic. European-American dark fantasy aesthetic, cinematic realism, muted cool color palette with desaturated greens and blacks.", "part3": "伊芙琳·卡特（Evelyn Carter）", "part4": "欧美暗黑奇幻风格，参考《暮光之城》《吸血鬼日记》氛围。26岁纽约女记者，理性倔强，因调查姐姐塞琳娜失踪来到银溪镇。银血家族最后的继承人，拥有支配狼人意志的觉醒之力。从受害者妹妹成长为觉醒女王，最终以自身之血封印恶魔。瞳孔带淡淡银光，母亲遗留的古银项链是关键道具。"}, "character_name": null, "negative_prompt": null}, {"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：Lucas Blackwood, 30-year-old male, werewolf clan heir and alpha''s son. Tall, powerfully built athletic frame with broad shoulders, approximately 6''2\". Strikingly handsome in a brooding, dangerous way. Sharp angular face, strong brow ridge, defined cheekbones, square jaw with light stubble. Deep-set eyes with an intense sapphire-blue hue that carries an unnatural, faintly luminous quality, suggesting inhuman nature. Thick dark black hair, slightly long, swept back with a few strands falling over his forehead, textured and layered. Pale complexion with a slightly weathered quality. Expression cold, guarded, suppressed pain behind stoic composure. Wearing a tailored long black wool coat over a dark charcoal henley shirt, black fitted trousers, heavy black leather boots. A thick silver signet ring on his right hand engraved with the Blackwood family crest (wolf head motif). Subtle scars on his knuckles and forearms hinting at past battles. Fingernails slightly longer and sharper than normal, suggesting lupine transformation capability. Overall aesthetic is dark aristocratic gothic, blending old-world nobility with predatory danger. European-American dark fantasy cinematic realism, cold desaturated color palette with deep blacks, charcoals, and steel blues.\n\n人设：卢卡斯·布莱克伍德（Lucas Blackwood）\n\n参考风格：\n欧美暗黑奇幻风格，参考《暮光之城》《真爱如血》氛围。30岁，布莱克伍德家族继承人，狼人族长之子。冷峻、压抑、危险的悲情守护者。曾与伊芙琳的姐姐塞琳娜相爱三年，塞琳娜被达米安杀害后一直隐忍复仇。可变身为前所未有巨大的黑狼。眼神幽蓝带非人光芒，指甲可变为尖锐利爪。", "line_no": 2, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "Lucas Blackwood, 30-year-old male, werewolf clan heir and alpha''s son. Tall, powerfully built athletic frame with broad shoulders, approximately 6''2\". Strikingly handsome in a brooding, dangerous way. Sharp angular face, strong brow ridge, defined cheekbones, square jaw with light stubble. Deep-set eyes with an intense sapphire-blue hue that carries an unnatural, faintly luminous quality, suggesting inhuman nature. Thick dark black hair, slightly long, swept back with a few strands falling over his forehead, textured and layered. Pale complexion with a slightly weathered quality. Expression cold, guarded, suppressed pain behind stoic composure. Wearing a tailored long black wool coat over a dark charcoal henley shirt, black fitted trousers, heavy black leather boots. A thick silver signet ring on his right hand engraved with the Blackwood family crest (wolf head motif). Subtle scars on his knuckles and forearms hinting at past battles. Fingernails slightly longer and sharper than normal, suggesting lupine transformation capability. Overall aesthetic is dark aristocratic gothic, blending old-world nobility with predatory danger. European-American dark fantasy cinematic realism, cold desaturated color palette with deep blacks, charcoals, and steel blues.", "part3": "卢卡斯·布莱克伍德（Lucas Blackwood）", "part4": "欧美暗黑奇幻风格，参考《暮光之城》《真爱如血》氛围。30岁，布莱克伍德家族继承人，狼人族长之子。冷峻、压抑、危险的悲情守护者。曾与伊芙琳的姐姐塞琳娜相爱三年，塞琳娜被达米安杀害后一直隐忍复仇。可变身为前所未有巨大的黑狼。眼神幽蓝带非人光芒，指甲可变为尖锐利爪。"}, "character_name": null, "negative_prompt": null}, {"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：Damien Grey, 28-year-old male, half-brother of Lucas Blackwood, werewolf pack traitor and ambitious schemer. Tall and lean, slightly less bulky than Lucas but equally striking. Devilishly handsome with a charismatic, seductive quality. Refined angular features, high cheekbones, narrow predatory eyes with amber-gold irises that suggest cunning and danger. A charming yet unsettling smile, perfectly symmetrical face. Dark auburn-brown hair, medium length, slicked back with a polished sophisticated style. Clean-shaven, immaculate grooming. Skin slightly warmer-toned than Lucas, with a subtle golden undertone. Expression composed with a knowing smirk, radiating controlled menace beneath surface charm. Wearing an impeccably tailored dark burgundy three-piece suit with black satin lapels, crisp white dress shirt, thin black silk tie, polished black Oxford shoes. A dark leather glove on one hand, the other hand bare revealing sharp manicured nails. A small silver bullet pendant hanging from his vest pocket chain as a provocative accessory. Overall aesthetic is refined dark elegance, the charismatic villain archetype, blending aristocratic sophistication with predatory edge. European-American dark fantasy cinematic realism, warm-dark color palette with deep burgundies, blacks, and golds.\n\n人设：达米安·格雷（Damien Grey）\n\n参考风格：\n欧美暗黑奇幻风格，参考《吸血鬼日记》反派氛围。28岁，卢卡斯同父异母兄长，野心勃勃的魅力反派。狼群中的叛徒，杀害塞琳娜以夺取狼群领导权，勾结圣银骑士团猎人组织。最终召唤远古血魔禁忌之术，化为双翼恶魔形态。表面迷人优雅，内心冷酷算计，给伊芙琳银色子弹实为布局。", "line_no": 3, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "Damien Grey, 28-year-old male, half-brother of Lucas Blackwood, werewolf pack traitor and ambitious schemer. Tall and lean, slightly less bulky than Lucas but equally striking. Devilishly handsome with a charismatic, seductive quality. Refined angular features, high cheekbones, narrow predatory eyes with amber-gold irises that suggest cunning and danger. A charming yet unsettling smile, perfectly symmetrical face. Dark auburn-brown hair, medium length, slicked back with a polished sophisticated style. Clean-shaven, immaculate grooming. Skin slightly warmer-toned than Lucas, with a subtle golden undertone. Expression composed with a knowing smirk, radiating controlled menace beneath surface charm. Wearing an impeccably tailored dark burgundy three-piece suit with black satin lapels, crisp white dress shirt, thin black silk tie, polished black Oxford shoes. A dark leather glove on one hand, the other hand bare revealing sharp manicured nails. A small silver bullet pendant hanging from his vest pocket chain as a provocative accessory. Overall aesthetic is refined dark elegance, the charismatic villain archetype, blending aristocratic sophistication with predatory edge. European-American dark fantasy cinematic realism, warm-dark color palette with deep burgundies, blacks, and golds.", "part3": "达米安·格雷（Damien Grey）", "part4": "欧美暗黑奇幻风格，参考《吸血鬼日记》反派氛围。28岁，卢卡斯同父异母兄长，野心勃勃的魅力反派。狼群中的叛徒，杀害塞琳娜以夺取狼群领导权，勾结圣银骑士团猎人组织。最终召唤远古血魔禁忌之术，化为双翼恶魔形态。表面迷人优雅，内心冷酷算计，给伊芙琳银色子弹实为布局。"}, "character_name": null, "negative_prompt": null}, {"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：Selena Carter, late 20s female, elder sister of Evelyn Carter, deceased former fiancée of Lucas Blackwood. Strikingly similar facial features to Evelyn — they look nearly identical as sisters — same high cheekbones, defined jawline, and intelligent eyes, but Selena has a softer, more ethereal and romantic quality. Gentle warm brown eyes without the silver glint, conveying warmth and vulnerability. Long flowing dark brown hair, slightly wavy, reaching past her shoulders, styled in a soft romantic manner. Fair luminous skin with a delicate porcelain quality. Expression serene, gentle, with an underlying sadness, as if captured in a beautiful memory. Soft natural makeup with a touch of rose on lips and cheeks. Wearing a flowing ivory-white dress with delicate lace detailing at the neckline and sleeves, mid-calf length, cinched at the waist with a thin silver chain belt. Simple silver stud earrings, bare neck (the mother''s pendant necklace was passed to Evelyn). Soft brown leather flats. Hands graceful with slender fingers. Overall aesthetic is ethereal romantic gothic, the tragically beautiful figure, a ghostly angelic quality suggesting someone preserved in memory. European-American dark fantasy cinematic realism, warm-soft color palette with ivory whites, pale golds, and muted roses against cool undertones.\n\n人设：塞琳娜·卡特（Selena Carter）\n\n参考风格：\n欧美暗黑奇幻风格。伊芙琳失踪的姐姐，与伊芙琳长得几乎一模一样。卢卡斯的前未婚妻，与卢卡斯相爱三年。银血家族后裔，在血月之夜被达米安杀害，其血被用于祭祀古老仪式。真相的关键人物，贯穿全剧的悲剧核心。生年1998，卒于2024年。", "line_no": 4, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "Selena Carter, late 20s female, elder sister of Evelyn Carter, deceased former fiancée of Lucas Blackwood. Strikingly similar facial features to Evelyn — they look nearly identical as sisters — same high cheekbones, defined jawline, and intelligent eyes, but Selena has a softer, more ethereal and romantic quality. Gentle warm brown eyes without the silver glint, conveying warmth and vulnerability. Long flowing dark brown hair, slightly wavy, reaching past her shoulders, styled in a soft romantic manner. Fair luminous skin with a delicate porcelain quality. Expression serene, gentle, with an underlying sadness, as if captured in a beautiful memory. Soft natural makeup with 