INSERT INTO "public"."import_files" VALUES (4, NULL, 'inline-text.txt', 'text', 340, 'BATCH_CREATED', NULL, '2026-04-23 10:20:54.569', 'CREATE_BATCH', '{"errors": [], "prompts": [{"prompt": "A raw, hyper-realistic cinematic three-quarter portrait shot, movie-level photorealistic style, character design reference sheet, natural cinematic lighting, shallow depth of field\n\n风格：Sophie, a 5-year-old Caucasian girl, resembling actress Brooklynn Prince, extremely pale almost translucent paper-thin skin with faint blue veins visible beneath, delicate childlike features, innocent wide eyes, soft fine hair, small rounded face\n\n参考风格：\nultra-detailed skin texture, subsurface scattering on skin, fine film grain, 8K resolution, cinematic color grading, neutral background for character reference", "line_no": 1, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "A raw, hyper-realistic cinematic three-quarter portrait shot, movie-level photorealistic style, character design reference sheet, natural cinematic lighting, shallow depth of field", "part2": "Sophie, a 5-year-old Caucasian girl, resembling actress Brooklynn Prince, extremely pale almost translucent paper-thin skin with faint blue veins visible beneath, delicate childlike features, innocent wide eyes, soft fine hair, small rounded face", "part4": "ultra-detailed skin texture, subsurface scattering on skin, fine film grain, 8K resolution, cinematic color grading, neutral background for character reference"}, "negative_prompt": null}], "raw_count": 2, "source_type": "text", "valid_count": 1, "invalid_count": 0}', '{"dedupe": false, "params": {}, "task_name": null, "capability": "PORTRAIT", "parse_mode": "claude", "folder_name": "test", "submit_mode": "CREATE_BATCH", "idempotency_key": null, "template_config": {"mode": "template", "preset": "PORTRAIT", "defaults": {}, "language_mode": "zh_with_en_reference"}}', '基于下面（或附件）的人设生成主角的设定图，电影级写实风格，参考提示词：
A raw, hyper-realistic cinematic three-quarter portrait shot of Sophie, a 5-year-old Caucasian girl, resembling actress Brooklynn Prince. She has extremely pale, almost translucent paper-thin skin with faint blue veins visible beneath', NULL, 0, 3, NULL, NULL, NULL, '2026-04-23 18:20:59.588513+08', '2026-04-23 18:21:41.125+08', NULL);
INSERT INTO "public"."import_files" VALUES (32, 26, 'inline-text.txt', 'text', 1621, 'BATCH_CREATED', NULL, '2026-04-24 07:54:44.3', 'CREATE_BATCH', '{"errors": [], "prompts": [{"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：角色名：陆观。31岁中国男性，地理系学生气质。身高178cm，身形消瘦修长，面容清俊端正，五官线条利落，颧骨微显，下颌线清晰。黑色眼睛，眼神沉稳内敛，略带忧郁的书卷气。黑色短发，发丝间夹杂数缕明显的银白色发丝，形成独特的黑白相间纹理，发型自然微乱但不邋遢。肤色偏白偏淡，面部干净无须。上身穿着一件深灰色立领外套，面料微显磨损泛旧但干净整洁，立领略高，扣合整齐，外套剪裁修身贴合消瘦身形，袖口微有磨白痕迹。内搭深色素色衬衫或薄针织衫。下身搭配深色直筒长裤，脚穿深色低帮平底鞋，整体穿着朴素低调，具有现代都市书生感与末世生存感的混合气质。双手自然垂于身侧，手指修长。\n\n参考风格：\nsemi-realistic style, character concept art, clean linework, muted cool color palette, soft studio lighting, full-body character sheet, high detail, sharp focus, grey gradient background", "line_no": 1, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色名：陆观。31岁中国男性，地理系学生气质。身高178cm，身形消瘦修长，面容清俊端正，五官线条利落，颧骨微显，下颌线清晰。黑色眼睛，眼神沉稳内敛，略带忧郁的书卷气。黑色短发，发丝间夹杂数缕明显的银白色发丝，形成独特的黑白相间纹理，发型自然微乱但不邋遢。肤色偏白偏淡，面部干净无须。上身穿着一件深灰色立领外套，面料微显磨损泛旧但干净整洁，立领略高，扣合整齐，外套剪裁修身贴合消瘦身形，袖口微有磨白痕迹。内搭深色素色衬衫或薄针织衫。下身搭配深色直筒长裤，脚穿深色低帮平底鞋，整体穿着朴素低调，具有现代都市书生感与末世生存感的混合气质。双手自然垂于身侧，手指修长。", "part4": "semi-realistic style, character concept art, clean linework, muted cool color palette, soft studio lighting, full-body character sheet, high detail, sharp focus, grey gradient background"}, "character_name": null, "negative_prompt": null}, {"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：角色名：安德烈。35岁北欧/斯拉夫白人男性，北境同盟军事代表。身高190cm，身形极为魁梧壮硕如熊，肩宽胸阔，肌肉线条厚实有力。面容刚毅粗犷如石刻，颧骨高耸，下颌方正宽阔，眉骨突出，鼻梁高挺。蓝色眼睛深邃冰冷，目光锐利如鹰，瞳色为寒冰般的钴蓝色。金色短发整齐利落，偏军人式短寸，两鬓剃短。肤色偏白略带寒原日晒的粗粝感，面部有细微风霜痕迹。穿着一件深蓝色（近藏青色）军装式立领外套，肩部有硬质肩章结构，胸前与衣襟处佩戴数枚金属质感的战功勋章，勋章造型古朴厚重带有北境风格纹饰。外套剪裁硬朗笔挺，面料厚实，腰部束以宽皮带，带扣为金属方扣。下身搭配深色军装长裤，裤线笔直，脚穿黑色高帮军靴，靴面有金属扣件。双手可自然握拳或一手置于腰带旁，整体气场威压强烈。\n\n参考风格：\nsemi-realistic style, character concept art, strong volumetric lighting, cold blue-grey tone, military aesthetic, full-body character sheet, high detail, sharp focus, neutral dark gradient background", "line_no": 2, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色名：安德烈。35岁北欧/斯拉夫白人男性，北境同盟军事代表。身高190cm，身形极为魁梧壮硕如熊，肩宽胸阔，肌肉线条厚实有力。面容刚毅粗犷如石刻，颧骨高耸，下颌方正宽阔，眉骨突出，鼻梁高挺。蓝色眼睛深邃冰冷，目光锐利如鹰，瞳色为寒冰般的钴蓝色。金色短发整齐利落，偏军人式短寸，两鬓剃短。肤色偏白略带寒原日晒的粗粝感，面部有细微风霜痕迹。穿着一件深蓝色（近藏青色）军装式立领外套，肩部有硬质肩章结构，胸前与衣襟处佩戴数枚金属质感的战功勋章，勋章造型古朴厚重带有北境风格纹饰。外套剪裁硬朗笔挺，面料厚实，腰部束以宽皮带，带扣为金属方扣。下身搭配深色军装长裤，裤线笔直，脚穿黑色高帮军靴，靴面有金属扣件。双手可自然握拳或一手置于腰带旁，整体气场威压强烈。", "part4": "semi-realistic style, character concept art, strong volumetric lighting, cold blue-grey tone, military aesthetic, full-body character sheet, high detail, sharp focus, neutral dark gradient background"}, "character_name": null, "negative_prompt": null}, {"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高