INSERT INTO "public"."import_files" VALUES (14, 8, 'inline-text.txt', 'text', 4, 'BATCH_CREATED', NULL, '2026-04-23 11:53:41.941', 'CREATE_BATCH', '{"errors": [], "prompts": [{"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：公元2112年未来世界角色，年轻成年人，中性偏冷的面部轮廓，五官精致锐利，瞳孔带有淡蓝色微光科技植入痕迹，短发或利落中长发，发色为银白渐变至冷蓝色，发丝质感光滑带微弱荧光。身穿未来主义功能性紧身外套，面料为哑光深灰色纳米织物，肩部与前臂有嵌入式薄型护甲模块，胸口区域有微型全息投影徽章，腰部配备极简金属扣环腰带，下身为修身高腰机能长裤，膝盖处有隐藏式关节增强结构，脚穿无鞋带磁吸式中筒靴，靴面有细微发光线条。手腕佩戴半透明全息手环装置，颈部有一道细窄的钛合金颈环。整体配色以深灰、银白、冷蓝为主，科技感强烈但不浮夸，造型干净利落，兼具实用与未来美学。\n\n参考风格：\n超高清，8K细节，未来科幻风格，硬表面材质精细渲染，冷色调高级光影，角色定妆照，全身像，concept art quality，clean background", "line_no": 1, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "公元2112年未来世界角色，年轻成年人，中性偏冷的面部轮廓，五官精致锐利，瞳孔带有淡蓝色微光科技植入痕迹，短发或利落中长发，发色为银白渐变至冷蓝色，发丝质感光滑带微弱荧光。身穿未来主义功能性紧身外套，面料为哑光深灰色纳米织物，肩部与前臂有嵌入式薄型护甲模块，胸口区域有微型全息投影徽章，腰部配备极简金属扣环腰带，下身为修身高腰机能长裤，膝盖处有隐藏式关节增强结构，脚穿无鞋带磁吸式中筒靴，靴面有细微发光线条。手腕佩戴半透明全息手环装置，颈部有一道细窄的钛合金颈环。整体配色以深灰、银白、冷蓝为主，科技感强烈但不浮夸，造型干净利落，兼具实用与未来美学。", "part4": "超高清，8K细节，未来科幻风格，硬表面材质精细渲染，冷色调高级光影，角色定妆照，全身像，concept art quality，clean background"}, "character_name": null, "negative_prompt": null}], "raw_count": 1, "source_type": "text", "valid_count": 1, "invalid_count": 0}', '{"dedupe": true, "params": {"count": 1}, "task_name": "1", "capability": "PORTRAIT", "parse_mode": "claude", "folder_name": "batch-output", "submit_mode": "CREATE_BATCH", "idempotency_key": null, "template_config": {"mod