INSERT INTO "public"."import_files" VALUES (31, 25, 'inline-text.txt', 'text', 8111, 'BATCH_CREATED', NULL, '2026-04-24 05:27:56.884', 'CREATE_BATCH', '{"errors": [], "prompts": [{"prompt": "基于人物定妆照生成人物角色设定三视图。\n\n【画面整体】严格16:9横版构图，画面分为左区和右区两部分。\n\n【左区——面部特写】面部占满左区整个区域，五官/发型/配饰清晰可辨，无身体入镜，无遮挡，无变形，面部居中填满。\n\n【右区——标准角色设定三视图】标准角色设定三视图严格横向排列，从左到右依次为：侧视图（左侧面90度）、正视图（正面0度）、背视图（背面180度）。三个视图必须严格呈现侧视、正视和背视三个角度，从头顶到脚底完整呈现全身，无裁切无遮挡。\n\n【核心一致性约束】左区面部特写与右区三视图必须为完全相同的同一角色，五官/服装/配饰/体态/发型/配色100%一致，不允许出现任何差异。\n\n【右区尺寸规范】三视图中每个角色的高度为画面高度的80%，三个视图高度严格统一对齐，角色间距均匀。\n\n【背景与光影】纯净浅灰色背景，无多余元素，无装饰，无文字，无标注；角色无阴影，无地面投影，无环境反光。\n\n【镜头与分辨率】超高清分辨率，统一85mm焦距，无透视畸变，无广角变形，平视角度（镜头与角色视平线齐平）。\n\n【角色姿态与表情】中性表情（无喜怒哀乐），眼神平静直视前方，自然站立姿势，双手自然下垂贴于身体两侧，无任何动作，无转头无倾斜。\n\n风格：【角色名称】陆观\n【性别/年龄】男性，31岁\n【身高/体型】178cm，身形消瘦\n【面部特征】面容清俊，黑色眼睛，中性表情\n【发型/发色】黑色短发，发丝中夹杂几缕银白色发丝\n【服装】一件略显破旧但干净的深灰色立领外套，内搭简洁深色衣物，下身深色长裤，深色鞋\n【配饰】无\n【整体气质】清瘦书生气质，沉稳内敛", "line_no": 1, "ext_params": {}, "source_mode": "template", "prompt_blocks": {"part1": "基于人物定妆照生成人物角色设定三视图。\n\n【画面整体】严格16:9横版构图，画面分为左区和右区两部分。\n\n【左区——面部特写】面部占满左区整个区域，五官/发型/配饰清晰可辨，无身体入镜，无遮挡，无变形，面部居中填满。\n\n【右区——标准角色设定三视图】标准角色设定三视图严格横向排列，从左到右依次为：侧视图（左侧面90度）、正视图（正面0度）、背视图（背面180度）。三个视图必须严格呈现侧视、正视和背视三个角度，从头顶到脚底完整呈现全身，无裁切无遮挡。\n\n【核心一致性约束】左区面部特写与右区三视图必须为完全相同的同一角色，五官/服装/配饰/体态/发型/配色100%一致，不允许出现任何差异。\n\n【右区尺寸规范】三视图中每个角色的高度为画面高度的80%，三个视图高度严格统一对齐，角色间距均匀。\n\n【背景与光影】纯净浅灰色背景，无多余元素，无装饰，无文字，无标注；角色无阴影，无地面投影，无环境反光。\n\n【镜头与分辨率】超高清分辨率，统一85mm焦距，无透视畸变，无广角变形，平视角度（镜头与角色视平线齐平）。\n\n【角色姿态与表情】中性表情（无喜怒哀乐），眼神平静直视前方，自然站立姿势，双手自然下垂贴于身体两侧，无任何动作，无转头无倾斜。", "part2": "【角色名称】陆观\n【性别/年龄】男性，31岁\n【身高/体型】178cm，身形消瘦\n【面部特征】面容清俊，黑色眼睛，中性表情\n【发型/发色】黑色短发，发丝中夹杂几缕银白色发丝\n【服装】一件略显破旧但干净的深灰色立领外套，内搭简洁深色衣物，下身深色长裤，深色鞋\n【配饰】无\n【整体气质】清瘦书生气质，沉稳内敛", "part4": ""}, "character_name": null, "negative_prompt": null}, {"prompt": "基于人物定妆照生成人物角色设定三视图。\n\n【画面整体】严格16:9横版构图，画面分为左区和右区两部分。\n\n【左区——面部特写】面部占满左区整个区域，五官/发型/配饰清晰可辨，无身体入镜，无遮挡，无变形，面部居中填满。\n\n【右区——标准角色设定三视图】标准角色设定三视图严格横向排列，从左到右依次为：侧视图（左侧面90度）、正视图（正面0度）、背视图（背面180度）。三个视图必须严格呈现侧视、正视和背视三个角度，从头顶到脚底完整呈现全身，无裁切无遮