INSERT INTO "public"."import_files" VALUES (34, NULL, 'inline-text.txt', 'text', 1621, 'PARSE_SUCCESS', NULL, '2026-04-24 07:56:02.987', 'PARSE_ONLY', '{"errors": [], "prompts": [{"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：中国男性，31岁，身高178cm，身形消瘦修长，面容清俊，五官轮廓清晰偏文气，黑色眼睛沉稳有神，黑色短发中夹杂几缕明显的银白色发丝，形成黑白交杂的独特发色。表情内敛沉着，目光坚定。穿着一件深灰色立领外套，外套面料略显陈旧磨损但整洁干净，立领设计紧贴颈部，增添几分利落感。内搭深色简单衬衣或高领内衫，下装为深色长裤，脚穿深色简洁靴子。整体气质为清隽内敛的青年学者，带有一丝历经风霜的沉稳。\n\n参考风格：\n主角角色。注意银白发丝需自然地混杂在黑色短发中，不是整片挑染而是零星分布的几缕。外套强调''略旧但干净''质感，面料可有轻微褪色和磨痕但无破洞污渍。整体色调偏冷灰调。", "line_no": 1, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "中国男性，31岁，身高178cm，身形消瘦修长，面容清俊，五官轮廓清晰偏文气，黑色眼睛沉稳有神，黑色短发中夹杂几缕明显的银白色发丝，形成黑白交杂的独特发色。表情内敛沉着，目光坚定。穿着一件深灰色立领外套，外套面料略显陈旧磨损但整洁干净，立领设计紧贴颈部，增添几分利落感。内搭深色简单衬衣或高领内衫，下装为深色长裤，脚穿深色简洁靴子。整体气质为清隽内敛的青年学者，带有一丝历经风霜的沉稳。", "part4": "主角角色。注意银白发丝需自然地混杂在黑色短发中，不是整片挑染而是零星分布的几缕。外套强调''略旧但干净''质感，面料可有轻微褪色和磨痕但无破洞污渍。整体色调偏冷灰调。"}, "character_name": "陆观", "negative_prompt": null}, {"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：北欧/斯拉夫白人男性，35岁，身高190cm，身形极其魁梧壮硕如熊，肩宽体厚，肌肉轮廓明显。面容刚毅深刻如石刻般棱角分明，颧骨与下颌线条硬朗，蓝色眼睛深邃冰冷，目光锐利如鹰，金色短发整齐利落，偏军人式的干净短发。表情严肃冷峻，带有压迫感。穿着一件深蓝色军装式外套，军装剪裁考究，双排扣或立领设计，肩章结构清晰，胸前佩戴数枚象征战功的金属勋章，勋章造型精致有金属光泽。内搭深色高领衬衣，下装为深蓝色军装长裤，脚穿黑色军靴，腰间或有军用腰带。整体气质为强势威压的军事精英。\n\n参考风格：\n北境同盟代表角色。勋章需有明确金属质感和精致造型，数量2-4枚，分布在左胸位置。军装整体风格偏近未来科幻感的军事制服，非现实任何国家军装。蓝色眼睛需突出冰冷深邃感。体型需明显大于普通人比例以体现190cm魁梧设定。", "line_no": 2, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "北欧/斯拉夫白人男性，35岁，身高190cm，身形极其魁梧壮硕如熊，肩宽体厚，肌肉轮廓明显。面容刚毅深刻如石刻般棱角分明，颧骨与下颌线条硬朗，蓝色眼睛深邃冰冷，目光锐利如鹰，金色短发整齐利落，偏军人式的干净短发。表情严肃冷峻，带有压迫感。穿着一件深蓝色军装式外套，军装剪裁考究，双排扣或立领设计，肩章结构清晰，胸前佩戴数枚象征战功的金属勋章，勋章造型精致有金属光泽。内搭深色高领衬衣，下装为深蓝色军装长裤，脚穿黑色军靴，腰间或有军用腰带。整体气质为强势威压的军事精英。", "part4": "北境同盟代表角色。勋章需有明确金属质感和精致造型，数量2-4枚，分布在左胸位置。军装整体风格偏近未来科幻感的军事制服，非现实任何国家军装。蓝色眼睛需突出冰冷深邃感。体型需明显大于普通人比例以体现190cm魁梧设定。"}, "character_name": "安德烈", "negative_prompt": null}, {"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：日本女性，28岁，身高165cm，身形纤细修长如柳，体态优雅但暗含力量感。面容清冷精致似霜，五官线条利落，黑色眼睛锐利如刀，眼神冷峻，黑色长发束成一丝不苟的高马尾，发丝顺滑服帖，马尾高高束起干净利落。表情冷淡疏离，嘴唇微抿。穿着一套黑色改良制服，融合现代制服剪裁与和风元素，立领或小翻领设计，修身收腰，袖口与衣摆可有暗纹或细节线条，面料质感挺括。腰间配戴一柄古朴武士刀，刀鞘色泽沉稳，刀柄缠绕传统编织。下装为黑色修身长裤或及膝裙配长靴，脚穿黑色短靴或及膝靴。整体气质为冷厉精密的武士学者。\n\n参考风格：\n樱花代表角色。改良制服强调黑色主色调，可有极少量暗红或银色细节点缀。武士刀需完整呈现，刀鞘古朴有木纹或漆面质感，佩戴位置在腰侧。高马尾发型需扎紧无碎发，突出干练气质。整体风格为写实偏美型，不走二次元风。", "line_no": 3, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "日本女性，28岁，身高165cm，身形纤细修长如柳，体态优雅但暗含力量感。面容清冷精致似霜，五官线条利落，黑色眼睛锐利如刀，眼神冷峻，黑色长发束成一丝不苟的高马尾，发丝顺滑服帖，马尾高高束起干净利落。表情冷淡疏离，嘴唇微抿。穿着一套黑色改良制服，融合现代制服剪裁与和风元素，立领或小翻领设计，修身收腰，袖口与衣摆可有暗纹或细节线条，面料质感挺括。腰间配戴一柄古朴武士刀，刀鞘色泽沉稳，刀柄缠绕传统编织。下装为黑色修身长裤或及膝裙配长靴，脚穿黑色短靴或及膝靴。整体气质为冷厉精密的武士学者。", "part4": "樱花代表角色。改良制服强调黑色主色调，可有极少量暗红或银色细节点缀。武士刀需完整呈现，刀鞘古朴有木纹或漆面质感，佩戴位置在腰侧。高马尾发型需扎紧无碎发，突出干练气质。整体风格为写实偏美型，不走二次元风。"}, "character_name": "千岛凛", "negative_prompt": null}, {"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：南亚/印度男性，40岁，身高175cm，身形匀称稳健，体态端正从容，既不瘦弱也不壮硕。面容温和慈祥带有微笑，五官深邃立体，棕色眼睛温暖而充满睿智洞察力，黑色卷发自然蓬松，发间已染有几缕银丝，显露阅历。皮肤为温暖的小麦棕色。表情温和可亲但目光深远。穿着白色亚麻长袍，长袍垂至脚踝，面料质感柔软透气有自然褶皱纹理，剪裁宽松优雅。头戴一顶绣金头巾，头巾面料考究，缝有精致金线刺绣纹样，包裹方式庄重。脚穿浅色皮质便鞋或凉鞋。可配有简朴的手环或指环等小饰品。整体气质为儒雅通达的外交智者与贵族学人。\n\n参考风格：\n天竺联邦代表角色。白色亚麻长袍需突出面料的自然亚麻质感与垂坠感。绣金头巾为关键辨识元素，金色刺绣纹样需精致可辨，可融合传统印度纹样风格。卷发中的银丝需自然分布。整体色调以白色与金色为主，温暖高雅。微笑需温和而不失威严感。", "line_no": 4, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "南亚/印度男性，40岁，身高175cm，身形匀称稳健，体态端正从容，既不瘦弱也不壮硕。面容温和慈祥带有微笑，五官深邃立体，棕色眼睛温暖而充满睿智洞察力，黑色卷发自然蓬松，发间已染有几缕银丝，显露阅历。皮肤为温暖的小麦棕色。表情温和可亲但目光深远。穿着白色亚麻长袍，长袍垂至脚踝，面料质感柔软透气有自然褶皱纹理，剪裁宽松优雅。头戴一顶绣金头巾，头巾面料考究，缝有精致金线刺绣纹样，包裹方式庄重。脚穿浅色皮质便鞋或凉鞋。可配有简朴的手环或指环等小饰品。整体气质为儒雅通达的外交智者与贵族学人。", "part4": "天竺联邦代表角色。白色亚麻长袍需突出面料的自然亚麻质感与垂坠感。绣金头巾为关键辨识元素，金色刺绣纹样需精致可辨，可融合传统印度纹样风格。卷发中的银丝需自然分布。整体色调以白色与金色为主，温暖高雅。微笑需温和而不失威严感。"}, "character_name": "阿米尔", "negative_prompt": null}], "raw_count": 1, "source_type": "text", "valid_count": 4, "invalid_count": 0}', '{"dedupe": true, "params": {}, "task_name": null, "capability": null, "parse_mode": "claude", "folder_name": null, "submit_mode": "PARSE_ONLY", "idempotency_key": null, "template_config": {"mode": "template", "preset": "PORTRAIT", "defaults": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "", "part4": ""}, "language_mode": "zh_with_en_reference"}}', '主角——陆观31岁，地理系学生，身高178cm，身形消瘦，面容清俊，黑色眼睛，黑色短发中夹杂着几缕银白色发丝。常穿着一件略显破旧但干净的深灰色立领外套，穿越后决心帮助大夏重振国威。北境同盟代表——安德烈35岁，北境同盟军事代表，身高190cm，身形魁梧如熊，面容刚毅如石刻，蓝色眼睛深邃冰冷，金色短发整齐利落。常穿着一件深蓝色军装式外套，佩戴着象征战功的金属勋章。他出身北境寒原的军事世家，自幼接受严酷训练，目的是在帝王擂台上以绝对武力碾压对手，为同盟夺取能源配额与土地权限，巩固北境在全球的霸权地位。樱花代表——千岛凛28岁，樱花精英学者兼武士，身高165cm，身形纤细如柳，面容清冷似霜，黑色眼睛锐利如刀，黑色长发束成一丝不苟的高马尾。常穿着一套黑色改良制服，配戴一柄古朴武士刀。她来自学阀高层家族，精通历史与战术，目的是通过帝王擂台召唤樱花历史中的强者，赢得科技密钥以提升学阀实力，并暗中抹除其他文明的历史痕迹。天竺代表——阿米尔40岁，天竺联邦外交官兼智者，身高175cm，身形匀称稳健，面容温和带笑，棕色眼睛充满睿智，黑色卷发间已染几缕银丝。常穿着白色亚麻长袍，头戴绣金头巾。他出身天竺古老贵族，深谙历史哲学，目的是在擂台上召唤联邦帝王，竞争能源配额，同时借此机会修复天竺被篡改的历史记忆，重塑联邦文明尊严。', NULL, 0, 3, NULL, NULL, NULL, '2026-04-24 15:56:04.313491+08', '2026-04-24 15:57:04.344+08', NULL);
INSERT INTO "public"."import_files" VALUES (36, NULL, 'inline-text.txt', 'text', 1621, 'PARSE_SUCCESS', NULL, '2026-04-24 18:07:43.882', 'PARSE_ONLY', '{"errors": [], "prompts": [{"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：角色：陆观，31岁男性，中国青年学者气质。身高178cm，身形消瘦修长，面容清俊，五官线条分明但不凌厉，带有书卷气与内敛感。黑色眼睛，目光沉静坚定。黑色短发，发丝间夹杂几缕明显的银白色发丝，形成黑银交错的独特发色细节，发型自然略显凌乱但不邋遢。肤色偏白，面部轮廓清瘦，颧骨微显。穿着一件略显破旧但整洁干净的深灰色立领外套，立领设计挺括，外套面料有轻微磨损与使用痕迹，纽扣与缝线细节可见。内搭深色简洁衬衫或薄内衣。下身深色长裤，鞋履为朴素深色平底鞋。整体造型朴素克制，气质介于现代学生与穿越者之间，透出一种沉稳内敛但暗藏决心的精神面貌。\n\n参考风格：\n画风：写实偏影视概念设定风格，光影柔和干净，色调以灰调、冷色为主，突出角色清冷消瘦的气质。注意银白发丝与黑发的对比细节，立领外套的面料磨损质感需真实可辨。", "line_no": 1, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色：陆观，31岁男性，中国青年学者气质。身高178cm，身形消瘦修长，面容清俊，五官线条分明但不凌厉，带有书卷气与内敛感。黑色眼睛，目光沉静坚定。黑色短发，发丝间夹杂几缕明显的银白色发丝，形成黑银交错的独特发色细节，发型自然略显凌乱但不邋遢。肤色偏白，面部轮廓清瘦，颧骨微显。穿着一件略显破旧但整洁干净的深灰色立领外套，立领设计挺括，外套面料有轻微磨损与使用痕迹，纽扣与缝线细节可见。内搭深色简洁衬衫或薄内衣。下身深色长裤，鞋履为朴素深色平底鞋。整体造型朴素克制，气质介于现代学生与穿越者之间，透出一种沉稳内敛但暗藏决心的精神面貌。", "part4": "画风：写实偏影视概念设定风格，光影柔和干净，色调以灰调、冷色为主，突出角色清冷消瘦的气质。注意银白发丝与黑发的对比细节，立领外套的面料磨损质感需真实可辨。"}, "character_name": "角色1", "negative_prompt": null}, {"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：角色：安德烈，35岁男性，北境斯拉夫系军人气质。身高190cm，身形魁梧厚重如熊，肩宽体壮，肌肉感明显但被军装包裹。面容刚毅如石刻，下颌线硬朗方正，颧骨高耸，面部棱角分明。蓝色眼睛深邃冰冷，目光带有压迫感与审视感。金色短发整齐利落，近似军人板寸但略长，发色明亮。肤色偏白略带粗粝感，面部可有淡淡的伤疤或风霜痕迹。穿着一件深蓝色军装式外套，外套为高领双排扣设计，肩部有肩章结构，衣身剪裁合体，面料厚实带有军事制服质感。胸前左侧佩戴数枚金属勋章，勋章造型精致可辨，象征战功荣誉。腰间系深色军用皮带，下身深蓝色军裤，脚穿黑色高筒军靴。双手自然垂放或一手背于身后，整体姿态挺拔威严。\n\n参考风格：\n画风：写实偏影视概念设定风格，光影偏冷硬，色调以深蓝、钢灰、金属色为主，突出角色军人的威压感与北境寒原硬朗气质。注意勋章的金属反光质感与军装面料的厚实纹理。", "line_no": 2, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色：安德烈，35岁男性，北境斯拉夫系军人气质。身高190cm，身形魁梧厚重如熊，肩宽体壮，肌肉感明显但被军装包裹。面容刚毅如石刻，下颌线硬朗方正，颧骨高耸，面部棱角分明。蓝色眼睛深邃冰冷，目光带有压迫感与审视感。金色短发整齐利落，近似军人板寸但略长，发色明亮。肤色偏白略带粗粝感，面部可有淡淡的伤疤或风霜痕迹。穿着一件深蓝色军装式外套，外套为高领双排扣设计，肩部有肩章结构，衣身剪裁合体，面料厚实带有军事制服质感。胸前左侧佩戴数枚金属勋章，勋章造型精致可辨，象征战功荣誉。腰间系深色军用皮带，下身深蓝色军裤，脚穿黑色高筒军靴。双手自然垂放或一手背于身后，整体姿态挺拔威严。", "part4": "画风：写实偏影视概念设定风格，光影偏冷硬，色调以深蓝、钢灰、金属色为主，突出角色军人的威压感与北境寒原硬朗气质。注意勋章的金属反光质感与军装面料的厚实纹理。"}, "character_name": "角色2", "negative_prompt": null}, {"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：角色：千岛凛，28岁女性，日系精英武士学者气质。身高165cm，身形纤细如柳，体态修长轻盈但不显柔弱，隐含武者的紧绷与力量感。面容清冷似霜，五官精致锐利，下巴尖削，唇线薄而紧抿，表情冷淡克制。黑色眼睛锐利如刀，目光冷厉有穿透力。黑色长发浓密顺滑，束成一丝不苟的高马尾，马尾高扎利落，发丝整齐无散乱，额前无碎发遮挡。肤色白皙细腻。穿着一套黑色改良制服，上衣为立领收腰设计，融合日式学院制服与武士装束元素，衣身剪裁利落贴身，面料哑光黑色，袖口与领口有细密纹样暗纹。腰间系有窄带，左侧腰间配戴一柄古朴武士刀，刀鞘深色漆面，刀柄缠绳细节可见。下身黑色修身长裤或裙裤，脚穿黑色短靴。整体造型黑色系为主，干练、锐利、冷傲。\n\n参考风格：\n画风：写实偏影视概念设定风格，光影冷锐干净，色调以纯黑、冷白、暗灰为主，突出角色清冷凌厉的武士学者气质。注意高马尾的发丝光泽、武士刀的古朴金属与缠绳质感，以及改良制服的暗纹细节。", "line_no": 3, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色：千岛凛，28岁女性，日系精英武士学者气质。身高165cm，身形纤细如柳，体态修长轻盈但不显柔弱，隐含武者的紧绷与力量感。面容清冷似霜，五官精致锐利，下巴尖削，唇线薄而紧抿，表情冷淡克制。黑色眼睛锐利如刀，目光冷厉有穿透力。黑色长发浓密顺滑，束成一丝不苟的高马尾，马尾高扎利落，发丝整齐无散乱，额前无碎发遮挡。肤色白皙细腻。穿着一套黑色改良制服，上衣为立领收腰设计，融合日式学院制服与武士装束元素，衣身剪裁利落贴身，面料哑光黑色，袖口与领口有细密纹样暗纹。腰间系有窄带，左侧腰间配戴一柄古朴武士刀，刀鞘深色漆面，刀柄缠绳细节可见。下身黑色修身长裤或裙裤，脚穿黑色短靴。整体造型黑色系为主，干练、锐利、冷傲。", "part4": "画风：写实偏影视概念设定风格，光影冷锐干净，色调以纯黑、冷白、暗灰为主，突出角色清冷凌厉的武士学者气质。注意高马尾的发丝光泽、武士刀的古朴金属与缠绳质感，以及改良制服的暗纹细节。"}, "character_name": "角色3", "negative_prompt": null}, {"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：角色：阿米尔，40岁男性，南亚贵族智者外交官气质。身高175cm，身形匀称稳健，体态从容端正，不胖不瘦，带有成熟男性的沉稳体格。面容温和带有淡淡笑意，五官深邃立体，鼻梁高挺，眉骨微隆，面部线条柔和而有智慧感。棕色眼睛温润深沉，充满睿智与洞察力。黑色卷发中长，卷曲自然蓬松，发间夹杂几缕银丝，显示成熟阅历。肤色为温暖的小麦棕色。穿着一件白色亚麻长袍，长袍质地轻柔飘逸，面料纹理自然，剪裁宽松但不邋遢，衣身有细密的暗纹或边缘刺绣装饰。头戴绣金头巾，头巾以白色或米色为底，边缘与正面有精致的金线刺绣纹样，包裹方式端正传统。脚穿浅色皮质凉鞋或平底鞋。可配戴手腕处的串珠或指环等细节饰品。整体造型素雅庄重，散发古老文明的智慧与尊严感。\n\n参考风格：\n画风：写实偏影视概念设定风格，光影温暖柔和，色调以暖白、米金、棕色为主，突出角色温厚睿智的贵族学者气质。注意白色亚麻长袍的面料垂坠纹理、绣金头巾的金线刺绣细节，以及卷发中银丝的自然过渡。", "line_no": 4, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色：阿米尔，40岁男性，南亚贵族智者外交官气质。身高175cm，身形匀称稳健，体态从容端正，不胖不瘦，带有成熟男性的沉稳体格。面容温和带有淡淡笑意，五官深邃立体，鼻梁高挺，眉骨微隆，面部线条柔和而有智慧感。棕色眼睛温润深沉，充满睿智与洞察力。黑色卷发中长，卷曲自然蓬松，发间夹杂几缕银丝，显示成熟阅历。肤色为温暖的小麦棕色。穿着一件白色亚麻长袍，长袍质地轻柔飘逸，面料纹理自然，剪裁宽松但不邋遢，衣身有细密的暗纹或边缘刺绣装饰。头戴绣金头巾，头巾以白色或米色为底，边缘与正面有精致的金线刺绣纹样，包裹方式端正传统。脚穿浅色皮质凉鞋或平底鞋。可配戴手腕处的串珠或指环等细节饰品。整体造型素雅庄重，散发古老文明的智慧与尊严感。", "part4": "画风：写实偏影视概念设定风格，光影温暖柔和，色调以暖白、米金、棕色为主，突出角色温厚睿智的贵族学者气质。注意白色亚麻长袍的面料垂坠纹理、绣金头巾的金线刺绣细节，以及卷发中银丝的自然过渡。"}, "character_name": "角色4", "negative_prompt": null}], "raw_count": 1, "source_type": "text", "valid_count": 4, "invalid_count": 0}', '{"dedupe": true, "params": {}, "task_name": null, "capability": null, "parse_mode": "claude", "folder_name": null, "submit_mode": "PARSE_ONLY", "idempotency_key": null, "template_config": {"mode": "template", "preset": "PORTRAIT", "defaults": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "", "part4": ""}, "language_mode": "zh_with_en_reference"}}', '主角——陆观31岁，地理系学生，身高178cm，身形消瘦，面容清俊，黑色眼睛，黑色短发中夹杂着几缕银白色发丝。常穿着一件略显破旧但干净的深灰色立领外套，穿越后决心帮助大夏重振国威。北境同盟代表——安德烈35岁，北境同盟军事代表，身高190cm，身形魁梧如熊，面容刚毅如石刻，蓝色眼睛深邃冰冷，金色短发整齐利落。常穿着一件深蓝色军装式外套，佩戴着象征战功的金属勋章。他出身北境寒原的军事世家，自幼接受严酷训练，目的是在帝王擂台上以绝对武力碾压对手，为同盟夺取能源配额与土地权限，巩固北境在全球的霸权地位。樱花代表——千岛凛28岁，樱花精英学者兼武士，身高165cm，身形纤细如柳，面容清冷似霜，黑色眼睛锐利如刀，黑色长发束成一丝不苟的高马尾。常穿着一套黑色改良制服，配戴一柄古朴武士刀。她来自学阀高层家族，精通历史与战术，目的是通过帝王擂台召唤樱花历史中的强者，赢得科技密钥以提升学阀实力，并暗中抹除其他文明的历史痕迹。天竺代表——阿米尔40岁，天竺联邦外交官兼智者，身高175cm，身形匀称稳健，面容温和带笑，棕色眼睛充满睿智，黑色卷发间已染几缕银丝。常穿着白色亚麻长袍，头戴绣金头巾。他出身天竺古老贵族，深谙历史哲学，目的是在擂台上召唤联邦帝王，竞争能源配额，同时借此机会修复天竺被篡改的历史记忆，重塑联邦文明尊严。', NULL, 0, 3, NULL, NULL, NULL, '2026-04-24 18:07:44.116118+08', '2026-04-24 18:08:40.212+08', NULL);
INSERT INTO "public"."import_files" VALUES (30, NULL, 'inline-text.txt', 'text', 8111, 'PARSE_SUCCESS', NULL, '2026-04-24 05:27:50.193', 'PARSE_ONLY', '{"errors": [], "prompts": [{"prompt": "基于人物定妆照生成人物角色设定三视图。\n\n【画面整体】严格16:9横版构图，画面分为左区和右区两部分。\n\n【左区——面部特写】面部占满左区整个区域，五官/发型/配饰清晰可辨，无身体入镜，无遮挡，无变形，面部居中填满。\n\n【右区——标准角色设定三视图】标准角色设定三视图严格横向排列，从左到右依次为：侧视图（左侧面90度）、正视图（正面0度）、背视图（背面180度）。三个视图必须严格呈现侧视、正视和背视三个角度，从头顶到脚底完整呈现全身，无裁切无遮挡。\n\n【核心一致性约束】左区面部特写与右区三视图必须为完全相同的同一角色，五官/服装/配饰/体态/发型/配色100%一致，不允许出现任何差异。\n\n【右区尺寸规范】三视图中每个角色的高度为画面高度的80%，三个视图高度严格统一对齐，角色间距均匀。\n\n【背景与光影】纯净浅灰色背景，无多余元素，无装饰，无文字，无标注；角色无阴影，无地面投影，无环境反光。\n\n【镜头与分辨率】超高清分辨率，统一85mm焦距，无透视畸变，无广角变形，平视角度（镜头与角色视平线齐平）。\n\n【角色姿态与表情】中性表情（无喜怒哀乐），眼神平静直视前方，自然站立姿势，双手自然下垂贴于身体两侧，无任何动作，无转头无倾斜。\n\n风格：【角色名称】陆观\n【性别/年龄】男性，31岁\n【身高/体型】178cm，身形消瘦\n【面部特征】面容清俊，黑色眼睛，眼神沉稳\n【发型/发色】黑色短发，发丝中夹杂几缕银白色发丝\n【服装】一件略显破旧但干净的深灰色立领外套，内搭简朴衣物，整体朴素整洁\n【配饰】无明显配饰\n【风格关键词】东方青年、清瘦书生气质、朴素低调、现代穿越者", "line_no": 1, "ext_params": {}, "source_mode": "template", "prompt_blocks": {"part1": "基于人物定妆照生成人物角色设定三视图。\n\n【画面整体】严格16:9横版构图，画面分为左区和右区两部分。\n\n【左区——面部特写】面部占满左区整个区域，五官/发型/配饰清晰可辨，无身体入镜，无遮挡，无变形，面部居中填满。\n\n【右区——标准角色设定三视图】标准角色设定三视图严格横向排列，从左到右依次为：侧视图（左侧面90度）、正视图（正面0度）、背视图（背面180度）。三个视图必须严格呈现侧视、正视和背视三个角度，从头顶到脚底完整呈现全身，无裁切无遮挡。\n\n【核心一致性约束】左区面部特写与右区三视图必须为完全相同的同一角色，五官/服装/配饰/体态/发型/配色100%一致，不允许出现任何差异。\n\n【右区尺寸规范】三视图中每个角色的高度为画面高度的80%，三个视图高度严格统一对齐，角色间距均匀。\n\n【背景与光影】纯净浅灰色背景，无多余元素，无装饰，无文字，无标注；角色无阴影，无地面投影，无环境反光。\n\n【镜头与分辨率】超高清分辨率，统一85mm焦距，无透视畸变，无广角变形，平视角度（镜头与角色视平线齐平）。\n\n【角色姿态与表情】中性表情（无喜怒哀乐），眼神平静直视前方，自然站立姿势，双手自然下垂贴于身体两侧，无任何动作，无转头无倾斜。", "part2": "【角色名称】陆观\n【性别/年龄】男性，31岁\n【身高/体型】178cm，身形消瘦\n【面部特征】面容清俊，黑色眼睛，眼神沉稳\n【发型/发色】黑色短发，发丝中夹杂几缕银白色发丝\n【服装】一件略显破旧但干净的深灰色立领外套，内搭简朴衣物，整体朴素整洁\n【配饰】无明显配饰\n【风格关键词】东方青年、清瘦书生气质、朴素低调、现代穿越者", "part4": ""}, "character_name": null, "negative_prompt": null}, {"prompt": "基于人物定妆照生成人物角色设定三视图。\n\n【画面整体】严格16:9横版构图，画面分为左区和右区两部分。\n\n【左区——面部特写】面部占满左区整个区域，五官/发型/配饰清晰可辨，无身体入镜，无遮挡，无变形，面部居中填满。\n\n【右区——标准角色设定三视图】标准角色设定三视图严格横向排列，从左到右依次为：侧视图（左侧面90度）、正视图（正面0度）、背视图（背面180度）。三个视图必须严格呈现侧视、正视和背视三个角