INSERT INTO "public"."import_files" VALUES (17, 11, '7f576edd-675a-4912-a1a9-47b07f29e90a.docx', 'docx', 11294, 'BATCH_CREATED', NULL, '2026-04-24 02:59:58.297', 'CREATE_BATCH', '{"errors": [], "prompts": [{"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：角色名：伊芙琳·卡特（Evelyn Carter）。26岁年轻女性，纽约记者，欧美白人面孔，五官精致立体，眉骨高挑，眼神锐利而倔强，透出理性与坚韧。中长发，深棕色偏栗色发色，自然微卷，发丝质感细腻。面容清秀但带有硬朗线条感，唇色自然偏暗粉，淡妆，不浓艳。体型纤细但不瘦弱，身姿挺拔有力。身穿深色修身皮夹克，内搭深灰色高领针织衫，下穿深蓝色修身牛仔裤，脚踏深棕色短筒靴。颈间佩戴一条精致的银色古旧项链（母亲遗物），手腕处戴简约银色手表。整体造型偏现代都市干练风格，带有记者/调查者的职业气质，兼具暗黑奇幻世界观下的女主气场。瞳孔为深棕色，后期可带淡淡银光变体。\n\n人设：欧美暗黑奇幻风格，参考《暮光之城》《吸血鬼日记》《真爱如血》氛围，色调偏冷调暗蓝与深棕，质感写实偏电影级仿真人画风，光影带微弱月光冷蓝调辅助光。\n\n参考风格：\n仿真人风格，电影级质感，高清细节，冷色调为主，暗黑奇幻基调。", "line_no": 1, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色名：伊芙琳·卡特（Evelyn Carter）。26岁年轻女性，纽约记者，欧美白人面孔，五官精致立体，眉骨高挑，眼神锐利而倔强，透出理性与坚韧。中长发，深棕色偏栗色发色，自然微卷，发丝质感细腻。面容清秀但带有硬朗线条感，唇色自然偏暗粉，淡妆，不浓艳。体型纤细但不瘦弱，身姿挺拔有力。身穿深色修身皮夹克，内搭深灰色高领针织衫，下穿深蓝色修身牛仔裤，脚踏深棕色短筒靴。颈间佩戴一条精致的银色古旧项链（母亲遗物），手腕处戴简约银色手表。整体造型偏现代都市干练风格，带有记者/调查者的职业气质，兼具暗黑奇幻世界观下的女主气场。瞳孔为深棕色，后期可带淡淡银光变体。", "part3": "欧美暗黑奇幻风格，参考《暮光之城》《吸血鬼日记》《真爱如血》氛围，色调偏冷调暗蓝与深棕，质感写实偏电影级仿真人画风，光影带微弱月光冷蓝调辅助光。", "part4": "仿真人风格，电影级质感，高清细节，冷色调为主，暗黑奇幻基调。"}, "character_name": null, "negative_prompt": null}, {"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：角色名：卢卡斯·布莱克伍德（Lucas Blackwood）。30岁男性，布莱克伍德狼人家族继承人、族长之子，欧美白人面孔，面容英俊冷峻，轮廓深邃，颧骨分明，下颌线锐利，眉骨高，浓眉，眼神幽蓝透出非人的冷冽光芒，瞳孔为深幽蓝色。短发偏中长，黑色发色，微微后梳带自然碎发纹理，发质浓密。面部带有淡淡疤痕（左颧骨处一道细长旧伤疤），胡茬极淡，整体气质压抑、危险、隐忍。体格高大健壮，肩宽背厚，肌肉线条明显但不过度夸张。身穿深黑色长款羊毛大衣，内搭深灰色V领毛衣，下穿黑色修身长裤，脚踏黑色皮质长靴。手指修长有力，指甲微尖暗示狼人特质。腰间别有一枚古铜色家族纹章扣饰。整体造型偏哥特贵族与暗黑守护者风格，带有压抑悲情的孤狼气质。\n\n人设：欧美暗黑奇幻风格，参考《暮光之城》《吸血鬼日记》《真爱如血》氛围，色调偏冷黑与深蓝，质感写实偏电影级仿真人画风，光影带微弱冷蓝月光辅助光。\n\n参考风格：\n仿真人风格，电影级质感，高清细节，冷色调为主，暗黑奇幻基调。", "line_no": 2, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色名：卢卡斯·布莱克伍德（Lucas Blackwood）。30岁男性，布莱克伍德狼人家族继承人、族长之子，欧美白人面孔，面容英俊冷峻，轮廓深邃，颧骨分明，下颌线锐利，眉骨高，浓眉，眼神幽蓝透出非人的冷冽光芒，瞳孔为深幽蓝色。短发偏中长，黑色发色，微微后梳带自然碎发纹理，发质浓密。面部带有淡淡疤痕（左颧骨处一道细长旧伤疤），胡茬极淡，整体气质压抑、危险、隐忍。体格高大健壮，肩宽背厚，肌肉线条明显但不过度夸张。身穿深黑色长款羊毛大衣，内搭深灰色V领毛衣，下穿黑色修身长裤，脚踏黑色皮质长靴。手指修长有力，指甲微尖暗示狼人特质。腰间别有一枚古铜色家族纹章扣饰。整体造型偏哥特贵族与暗黑守护者风格，带有压抑悲情的孤狼气质。", "part3": "欧美暗黑奇幻风格，参考《暮光之城》《吸血鬼日记》《真爱如血》氛围，色调偏冷黑与深蓝，质感写实偏电影级仿真人画风，光影带微弱冷蓝月光辅助光。", "part4": "仿真人风格，电影级质感，高清细节，冷色调为主，暗黑奇幻基调。"}, "character_name": null, "negative_prompt": null}, {"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：角色名：达米安·格雷（Damien Grey）。28岁男性，卢卡斯同父异母的兄长，狼群中的叛徒，欧美白人面孔，外表英俊迷人但带有危险的邪魅气质。五官深邃精致，眼窝略深，瞳孔为琥珀金色偏暗，眼神中透出算计与野心，嘴角常挂一抹玩味微笑。发色为深金棕色，中长发型，自然后梳露出额头，发梢微卷搭在颈侧，造型精致考究。面部线条比卢卡斯更柔和但更具欺骗性，下巴尖削，唇形饱满。体格修长挺拔，略瘦于卢卡斯但气场强势。身穿深酒红色天鹅绒西装外套，内搭黑色丝质衬衫微敞领口，下穿黑色修身西裤，脚踏酒红色尖头皮鞋。手指佩戴暗金色狼头戒指，胸口别针为银色蛇形胸针。整体造型偏华丽暗黑贵公子风格，魅力反派气质突出，精致中透出阴谋与危险。\n\n人设：欧美暗黑奇幻风格，参考《暮光之城》《吸血鬼日记》《真爱如血》氛围，色调偏暗红与深金，质感写实偏电影级仿真人画风，光影带微弱暖金侧光衬托邪魅感。\n\n参考风格：\n仿真人风格，电影级质感，高清细节，暗红金色调为主，暗黑奇幻基调。", "line_no": 3, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色名：达米安·格雷（Damien Grey）。28岁男性，卢卡斯同父异母的兄长，狼群中的叛徒，欧美白人面孔，外表英俊迷人但带有危险的邪魅气质。五官深邃精致，眼窝略深，瞳孔为琥珀金色偏暗，眼神中透出算计与野心，嘴角常挂一抹玩味微笑。发色为深金棕色，中长发型，自然后梳露出额头，发梢微卷搭在颈侧，造型精致考究。面部线条比卢卡斯更柔和但更具欺骗性，下巴尖削，唇形饱满。体格修长挺拔，略瘦于卢卡斯但气场强势。身穿深酒红色天鹅绒西装外套，内搭黑色丝质衬衫微敞领口，下穿黑色修身西裤，脚踏酒红色尖头皮鞋。手指佩戴暗金色狼头戒指，胸口别针为银色蛇形胸针。整体造型偏华丽暗黑贵公子风格，魅力反派气质突出，精致中透出阴谋与危险。", "part3": "欧美暗黑奇幻风格，参考《暮光之城》《吸血鬼日记》《真爱如血》氛围，色调偏暗红与深金，质感写实偏电影级仿真人画风，光影带微弱暖金侧光衬托邪魅感。", "part4": "仿真人风格，电影级质感，高清细节，暗红金色调为主，暗黑奇幻基调。"}, "character_name": null, "negative_prompt": null}, {"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：角色名：塞琳娜·卡特（Selena Carter）。约26岁女性（1998年生），伊芙琳的姐姐，卢卡斯的已故未婚妻，银血家族后裔，欧美白人面孔。与伊芙琳长相极为相似但气质更柔和温婉，五官精致秀美，眼神温柔带有淡淡忧郁，瞳孔为浅棕偏蜜色。长发，深棕色偏栗色发色，长至肩下，自然大卷波浪，发丝柔顺飘逸。面容比伊芙琳更圆润柔和，唇色偏玫瑰粉，肤色白皙。体型纤细柔美，气质温和优雅。身穿米白色雪纺长裙，裙摆及脚踝，腰间束有细银腰带，外搭浅灰色针织披肩。脚穿浅棕色平底绑带凉鞋。颈间佩戴与伊芙琳同款的银色古旧项链（姐妹信物）。整体造型偏温柔古典风格，带有一丝悲剧命运感与银血家族的高洁气质，如同月光下的幽灵般清丽。\n\n人设：欧美暗黑奇幻风格，参考《暮光之城》《吸血鬼日记》《真爱如血》氛围，色调偏冷白与淡银蓝，质感写实偏电影级仿真人画风，光影带柔和月光散射质感，营造悲美氛围。\n\n参考风格：\n仿真人风格，电影级质感，高清细节，冷白银蓝色调为主，暗黑奇幻基调，悲美气质。", "line_no": 4, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰