INSERT INTO "public"."import_files" VALUES (19, 12, '7f576edd-675a-4912-a1a9-47b07f29e90a.docx', 'docx', 11294, 'BATCH_CREATED', NULL, '2026-04-24 03:29:51.967', 'CREATE_BATCH', '{"errors": [], "prompts": [{"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：伊芙琳·卡特（Evelyn Carter），26岁女性，纽约记者，白人，理性倔强的气质。中长棕色头发，略带自然卷，发丝细腻有光泽。面容清秀坚毅，眉骨略高，眼神锐利且带有倔强感，浅绿色或灰蓝色瞳孔，后期瞳孔带有淡淡银光。淡妆，自然唇色，肤色白皙偏冷。身材匀称偏瘦，身高中等。穿着现代都市风格——深色皮夹克内搭简约黑色高领毛衣，修身深色牛仔裤，踝靴，肩挎一个棕色记者包。颈间佩戴母亲遗留的古银项链（关键道具），造型简洁利落，符合独立女记者身份。整体氛围偏冷调现代感，暗黑奇幻美剧风格。\n\n人设：欧美暗黑奇幻风格，仿真人AI短剧角色，参考《暮光之城》《吸血鬼日记》氛围，电影级质感，高清细腻", "line_no": 1, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "伊芙琳·卡特（Evelyn Carter），26岁女性，纽约记者，白人，理性倔强的气质。中长棕色头发，略带自然卷，发丝细腻有光泽。面容清秀坚毅，眉骨略高，眼神锐利且带有倔强感，浅绿色或灰蓝色瞳孔，后期瞳孔带有淡淡银光。淡妆，自然唇色，肤色白皙偏冷。身材匀称偏瘦，身高中等。穿着现代都市风格——深色皮夹克内搭简约黑色高领毛衣，修身深色牛仔裤，踝靴，肩挎一个棕色记者包。颈间佩戴母亲遗留的古银项链（关键道具），造型简洁利落，符合独立女记者身份。整体氛围偏冷调现代感，暗黑奇幻美剧风格。", "part3": "欧美暗黑奇幻风格，仿真人AI短剧角色，参考《暮光之城》《吸血鬼日记》氛围，电影级质感，高清细腻", "part4": ""}, "character_name": null, "negative_prompt": null}, {"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：卢卡斯·布莱克伍德（Lucas Blackwood），30岁男性，狼人族长之子，白人，冷峻压抑危险的气质。深黑色短发，略长于耳际，发型微乱但有型，发丝浓密。面部轮廓深邃，高颧骨，棱角分明的下颚线，浓眉，幽蓝色瞳孔带有非人的微光，眼神深沉内敛带压抑的悲伤。唇形薄而紧抿，面色偏苍白。身材高大健壮但不过分粗犷，约185cm，肩宽体壮。穿着暗黑贵族风格——黑色长款大衣（哥特式剪裁），内搭深灰高领衫，黑色修身长裤，黑色皮靴。手指修长有力，指甲略尖暗示狼人特征。无明显饰品，整体造型暗沉内敛、贵族气质浓重。欧美暗黑奇幻悲情守护者形象。\n\n人设：欧美暗黑奇幻风格，仿真人AI短剧角色，参考《暮光之城》《吸血鬼日记》氛围，电影级质感，高清细腻", "line_no": 2, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "卢卡斯·布莱克伍德（Lucas Blackwood），30岁男性，狼人族长之子，白人，冷峻压抑危险的气质。深黑色短发，略长于耳际，发型微乱但有型，发丝浓密。面部轮廓深邃，高颧骨，棱角分明的下颚线，浓眉，幽蓝色瞳孔带有非人的微光，眼神深沉内敛带压抑的悲伤。唇形薄而紧抿，面色偏苍白。身材高大健壮但不过分粗犷，约185cm，肩宽体壮。穿着暗黑贵族风格——黑色长款大衣（哥特式剪裁），内搭深灰高领衫，黑色修身长裤，黑色皮靴。手指修长有力，指甲略尖暗示狼人特征。无明显饰品，整体造型暗沉内敛、贵族气质浓重。欧美暗黑奇幻悲情守护者形象。", "part3": "欧美暗黑奇幻风格，仿真人AI短剧角色，参考《暮光之城》《吸血鬼日记》氛围，电影级质感，高清细腻", "part4": ""}, "character_name": null, "negative_prompt": null}, {"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：达米安·格雷（Damien Grey），28岁男性，卢卡斯同父异母的兄长，白人，野心勃勃的魅力反派。深棕偏红色头发，向后梳理的利落发型，鬓角修饰整齐，发丝带有微微光泽。面容英俊但带有危险的锐利感，高挺鼻梁，薄唇常带似笑非笑的弧度，琥珀色瞳孔带有狡黠与野心的光芒，眼神自信且带有攻击性。肤色比卢卡斯略暖，下颌轮廓锋利。身材修长挺拔，约183cm，体型精瘦有力。穿着暗黑时尚贵族风——深红色丝绒西装外套，内搭黑色衬衫微敞领口，黑色修身西裤，尖头黑色皮鞋。手上戴一枚古老的家族银戒。整体造型介于优雅与邪恶之间，危险的魅力型反派形象。\n\n人设：欧美暗黑奇幻风格，仿真人AI短剧角色，参考《暮光之城》《吸血鬼日记》《真爱如血》氛围，电影级质感，高清细腻", "line_no": 3, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过