INSERT INTO "public"."import_files" VALUES (23, NULL, '7f576edd-675a-4912-a1a9-47b07f29e90a.docx', 'docx', 11294, 'BATCH_CREATE_FAILED', 'THREE_VIEW params.view_set must contain front/side/back.', '2026-04-24 04:07:51.045', 'CREATE_BATCH', '{"errors": [], "prompts": [{"prompt": "基于人物定妆照生成人物三视图\n（16：9）面部占满左区，五官 / 发型 / 配饰清晰，无身体入镜、无遮挡变形；右区：标准角色设定三视图，横向排列（侧视图、正视图、背视图），三个视图严格呈现侧视、正视和背视，从头到脚完整无遮挡；核心约束：特写与三视图为同一角色，五官 / 服装 / 配饰 / 体态 100% 一致；右区尺寸：三视图角色高度画面高度的 80%，三视图高度统一；无多余元素的浅灰色背景，角色无阴影；超高清分辨率，统一85mm焦距，无畸变，角色无动作，平视；中性表情（无喜怒哀乐），眼神平静，自然站立，双手自然下垂。\n\n风格：一位26岁欧美白人女性，纽约记者；中长波浪深棕色头发，发梢带有隐约银色光泽；面容精致坚毅，高颧骨，薄唇，浅绿色瞳孔中隐约带有银色微光；身材匀称偏瘦，身高约170cm；穿着深灰色修身皮夹克，内搭黑色高领毛衣，深蓝色修身牛仔裤，黑色短靴；颈部佩戴一条古旧银质项链（椭圆形吊坠，母亲遗物）；整体气质理性干练，带有倔强不屈的锋芒；欧美暗黑奇幻写实风格。\n\n参考风格：\n角色名：伊芙琳·卡特（Evelyn Carter），26岁，纽约记者，银血家族最后的继承人，因调查姐姐塞琳娜失踪来到银溪镇，后觉醒银血之力。与姐姐塞琳娜容貌极为相似但气质更刚毅。", "line_no": 1, "ext_params": {}, "source_mode": "template", "prompt_blocks": {"part1": "基于人物定妆照生成人物三视图\n（16：9）面部占满左区，五官 / 发型 / 配饰清晰，无身体入镜、无遮挡变形；右区：标准角色设定三视图，横向排列（侧视图、正视图、背视图），三个视图严格呈现侧视、正视和背视，从头到脚完整无遮挡；核心约束：特写与三视图为同一角色，五官 / 服装 / 配饰 / 体态 100% 一致；右区尺寸：三视图角色高度画面高度的 80%，三视图高度统一；无多余元素的浅灰色背景，角色无阴影；超高清分辨率，统一85mm焦距，无畸变，角色无动作，平视；中性表情（无喜怒哀乐），眼神平静，自然站立，双手自然下垂。", "part2": "一位26岁欧美白人女性，纽约记者；中长波浪深棕色头发，发梢带有隐约银色光泽；面容精致坚毅，高颧骨，薄唇，浅绿色瞳孔中隐约带有银色微光；身材匀称偏瘦，身高约170cm；穿着深灰色修身皮夹克，内搭黑色高领毛衣，深蓝色修身牛仔裤，黑色短靴；颈部佩戴一条古旧银质项链（椭圆形吊坠，母亲遗物）；整体气质理性干练，带有倔强不屈的锋芒；欧美暗黑奇幻写实风格。", "part4": "角色名：伊芙琳·卡特（Evelyn Carter），26岁，纽约记者，银血家族最后的继承人，因调查姐姐塞琳娜失踪来到银溪镇，后觉醒银血之力。与姐姐塞琳娜容貌极为相似但气质更刚毅。"}, "character_name": null, "negative_prompt": null}, {"prompt": "基于人物定妆照生成人物三视图\n（16：9）面部占满左区，五官 / 发型 / 配饰清晰，无身体入镜、无遮挡变形；右区：标准角色设定三视图，横向排列（侧视图、正视图、背视图），三个视图严格呈现侧视、正视和背视，从头到脚完整无遮挡；核心约束：特写与三视图为同一角色，五官 / 服装 / 配饰 / 体态 100% 一致；右区尺寸：三视图角色高度画面高度的 80%，三视图高度统一；无多余元素的浅灰色背景，角色无阴影；超高清分辨率，统一85mm焦距，无畸变，角色无动作，平视；中性表情（无喜怒哀乐），眼神平静，自然站立，双手自然下垂。\n\n风格：一位30岁欧美白人男性，狼人贵族继承人；黑色短发微卷，鬓角利落；面容冷峻棱角分明，浓眉深目，瞳孔呈幽蓝色带有非人的冷冽微光，下颚线条刚硬，薄唇紧抿；身材高大健壮约190cm，肩宽体阔；穿着黑色长款羊毛大衣，内搭深灰色高领衫，黑色修身长裤，黑色皮靴；无明显配饰；整体气质冷峻压抑而危险，古堡贵族继承人的暗沉优雅与野性并存；欧美暗黑奇幻写实风格。\n\n参考风格：\n角色名：卢卡斯·布莱克伍德（Lucas 