INSERT INTO "public"."import_files" VALUES (51, 48, 'inline-text.txt', 'text', 1621, 'BATCH_CREATED', NULL, '2026-04-27 18:15:39.566', 'CREATE_BATCH', '{"errors": [], "prompts": [{"prompt": "主角，陆观，31岁男性，地理系学生，穿越者\n\n风格：身高178cm，身形消瘦，面容清俊，黑色眼睛，黑色短发中夹杂几缕银白色发丝，穿着一件略显破旧但干净的深灰色立领外套\n\n参考风格：\n穿越到异世界，决心帮助大夏重振国威，气质沉稳内敛，眼神中透着坚定与书卷气", "line_no": 1, "ext_params": {}, "source_mode": "template", "prompt_blocks": {"part1": "主角，陆观，31岁男性，地理系学生，穿越者", "part2": "身高178cm，身形消瘦，面容清俊，黑色眼睛，黑色短发中夹杂几缕银白色发丝，穿着一件略显破旧但干净的深灰色立领外套", "part4": "穿越到异世界，决心帮助大夏重振国威，气质沉稳内敛，眼神中透着坚定与书卷气"}, "character_name": "角色1", "negative_prompt": null}, {"prompt": "北境同盟代表，安德烈，35岁男性，北境同盟军事代表\n\n风格：身高190cm，身形魁梧如熊，面容刚毅如石刻，蓝色眼睛深邃冰冷，金色短发整齐利落，穿着深蓝色军装式外套，胸前佩戴象征战功的金属勋章\n\n参考风格：\n出身北境寒原军事世家，自幼接受严酷训练，目的是在帝王擂台上以绝对武力碾压对手，为同盟夺取能源配额与土地权限，气场威压强大", "line_no": 2, "ext_params": {}, "source_mode": "template", "prompt_blocks": {"part1": "北境同盟代表，安德烈，35岁男性，北境同盟军事代表", "part2": "身高190cm，身形魁梧如熊，面容刚毅如石刻，蓝色眼睛深邃冰冷，金色短发整齐利落，穿着深蓝色军装式外套，胸前佩戴象征战功的金属勋章", "part4": "出身北境寒原军事世家，自幼接受严酷训练，目的是在帝王擂台上以绝对武力碾压对手，为同盟夺取能源配额与土地权限，气场威压强大"}, "character_name": "角色2", "negative_prompt": null}, {"prompt": "樱花代表，千岛凛，28岁女性，樱花精英学者兼武士\n\n风格：身高165cm，身形纤细如柳，面容清冷似霜，黑色眼睛锐利如刀，黑色长发束成一丝不苟的高马尾，穿着一套黑色改良制服，腰间配戴一柄古朴武士刀\n\n参考风格：\n来自学阀高层家族，精通历史与战术，目的是通过帝王擂台召唤樱花历史中的强者赢得科技密钥，暗中图谋抹除其他文明的历史痕迹，气质冷峻凌厉", "line_no": 3, "ext_params": {}, "source_mode": "template", "prompt_blocks": {"part1": "樱花代表，千岛凛，28岁女性，樱花精英学者兼武士", "part2": "身高165cm，身形纤细如柳，面容清冷似霜，黑色眼睛锐利如刀，黑色长发束成一丝不苟的高马尾，穿着一套黑色改良制服，腰间配戴一柄古朴武士刀", "part4": "来自学阀高层家族，精通历史与战术，目的是通过帝王擂台召唤樱花历史中的强者赢得科技密钥，暗中图谋抹除其他文明的历史痕迹，气质冷峻凌厉"}, "character_name": "角色3", "negative_prompt": null}, {"prompt": "天竺代表，阿米尔，40岁男性，天竺联邦外交官兼智者\n\n风格：身高175cm，身形匀称稳健，面容温和带笑，棕色眼睛充满睿智，黑色卷发间已染几缕银丝，穿着白色亚麻长袍，头戴绣金头巾\n\n参考风格：\n出身天竺古老贵族，深谙历史哲学，目的是在擂台上召唤联邦帝王竞争能源配额，同时借机修复天竺被篡改的历史记忆、重塑联邦文明尊严，气质从容睿智", "line_no": 4, "ext_params": {}, "source_mode": "template", "prompt_blocks": {"part1": "天竺代表，阿米尔，40岁男性，天竺联邦外交官兼智者", "part2": "身高175cm，身形匀称稳健，面容温和带笑，棕色眼睛充满睿智，黑色卷发间已染几缕银丝，穿着白色亚麻长袍，头戴绣金头巾", "part4": "出身天竺古老贵族，深谙历史哲学，目的是在擂台上召唤联邦帝王竞争能源配额，同时借机修复天竺被篡改的历史记忆、重塑联邦文明尊严，气质从容睿智"}, "character_name": "角色4", "negative_prompt": null}], "raw_count": 1, "source_type": "text", "valid_count": 4, "invalid_count": 0}', '{"dedupe": true, "params": {"count": 1}, "style_key": null, "task_name": "", "capability": "PORTRAIT", "parse_mode": "claude", "folder_name": "batch-output", "submit_mode": "CREATE_BATCH", "idempotency_key": null}', '主角——陆观31岁，地理系学生，身高178cm，身形消瘦，面容清俊，黑色眼睛，黑色短发中夹杂着几缕银白色发丝。常穿着一件略显破旧但干净的深灰色立领外套，穿越后决心帮助大夏重振国威。北境同盟代表——安德烈35岁，北境同盟军事代表，身高190cm，身形魁梧如熊，面容刚毅如石刻，蓝色眼睛深邃冰冷，金色短发整齐利落。常穿着一件深蓝色军装式外套，佩戴着象征战功的金属勋章。他出身北境寒原的军事世家，自幼接受严酷训练，目的是在帝王擂台上以绝对武力碾压对手，为同盟夺取能源配额与土地权限，巩固北境在全球的霸权地位。樱花代表——千岛凛28岁，樱花精英学者兼武士，身高165cm，身形纤细如柳，面容清冷似霜，黑色眼睛锐利如刀，黑色长发束成一丝不苟的高马尾。常穿着一套黑色改良制服，配戴一柄古朴武士刀。她来自学阀高层家族，精通历史与战术，目的是通过帝王擂台召唤樱花历史中的强者，赢得科技密钥以提升学阀实力，并暗中抹除其他文明的历史痕迹。天竺代表——阿米尔40岁，天竺联邦外交官兼智者，身高175cm，身形匀称稳健，面容温和带笑，棕色眼睛充满睿智，黑色卷发间已染几缕银丝。常穿着白色亚麻长袍，头戴绣金头巾。他出身天竺古老贵族，深谙历史哲学，目的是在擂台上召唤联邦帝王，竞争能源配额，同时借此机会修复天竺被篡改的历史记忆，重塑联邦文明尊严。', NULL, 0, 3, NULL, NULL, NULL, '2026-04-27 18:16:13.136934+08', '2026-04-27 18:16:39.989+08', NULL);
INSERT INTO "public"."import_files" VALUES (20, 14, '7f576edd-675a-4912-a1a9-47b07f29e90a.docx', 'docx', 11294, 'BATCH_CREATED', NULL, '2026-04-24 03:31:16.191', 'CREATE_BATCH', '{"errors": [], "prompts": [{"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：Evelyn Carter（伊芙琳·卡特），26岁女性，纽约记者，理性倔强的现代都市女性。白人面孔，五官精致而坚毅，眉眼间透出聪慧与不屈，眼瞳深棕色、带淡淡银光暗示（银血血脉觉醒特征），肤色白皙偏冷调。中长发深棕色、发尾带有隐约银色挑染，发型干练利落、微带自然卷弧。妆容淡雅偏冷色系，唇色自然偏玫瑰色。表情冷静克制、眼神坚定有力。身材中等偏瘦、身姿挺拔。着装为现代都市风格——深色修身皮夹克、内搭深灰色高领毛衣、深色修身牛仔裤、黑色短靴，腰间系细皮带。脖子上佩戴一条银色古朴项链（母亲遗物，关键道具），手腕佩戴简洁银色手链。整体气质是都市职业女性的干练与暗黑奇幻世界女主的神秘感融合。\n\n人设：欧美暗黑奇幻风格，参考《暮光之城》《吸血鬼日记》《真爱如血》的视觉氛围，色调偏冷暗、银灰蓝调为主，带有哥特浪漫质感。写实仿真人风格，高精度角色资产图。", "line_no": 1, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "Evelyn Carter（伊芙琳·卡特），26岁女性，纽约记者，理性倔强的现代都市女性。白人面孔，五官精致而坚毅，眉眼间透出聪慧与不屈，眼瞳深棕色、带淡淡银光暗示（银血血脉觉醒特征），肤色白皙偏冷调。中长发深棕色、发尾带有隐约银色挑染，发型干练利落、微带自然卷弧。妆容淡雅偏冷色系，唇色自然偏玫瑰色。表情冷静克制、眼神坚定有力。身材中等偏瘦、身姿挺拔。着装为现代都市风格——深色修身皮夹克、内搭深灰色高领毛衣、深色修身牛仔裤、黑色短靴，腰间系细皮带。脖子上佩戴一条银色古朴项链（母亲遗物，关键道具），手腕佩戴简洁银色手链。整体气质是都市职业女性的干练与暗黑奇幻世界女主的神秘感融合。", "part3": "欧美暗黑奇幻风格，参考《暮光之城》《吸血鬼日记》《真爱如血》的视觉氛围，色调偏冷暗、银灰蓝调为主，带有哥特浪漫质感。写实仿真人风格，高精度角色资产图。", "part4": ""}, "character_name": null, "negative_prompt": null}, {"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：Lucas Blackwood（卢卡斯·布莱克伍德），30岁男性，布莱克伍德家族继承人、狼人族长之子，冷峻压抑而危险。白人面孔，五官深邃立体、棱角分明，颧骨高、下颌线条锐利，眼瞳为幽蓝色、带有非人的微微荧光感，瞳色深邃迷人。黑色短发微长、略显凌乱地向后梳理，鬓角利落，发质粗硬。面部有淡淡胡茬，皮肤偏苍白带冷调。表情冷峻内敛、眉头微蹙，眼神中藏着深沉的悲痛与压抑。身材高大健壮、肩宽体魄强悍，身高约188cm。着装为暗黑贵族风——黑色长款羊毛大衣、内搭深灰色立领衬衫、黑色修身长裤、黑色皮质短靴，大衣领口微立。手指修长有力、指节粗壮，右手无名指佩戴一枚暗银色家族纹章戒指。整体气质是欧美暗黑奇幻中悲情守护者的冷峻贵族感，危险而迷人。\n\n人设：欧美暗黑奇幻风格，参考《暮光之城》《吸血鬼日记》《真爱如血》的视觉氛围，色调偏冷暗、以黑灰深蓝为主色调，哥特浪漫气质。写实仿真人风格，高精度角色资产图。", "line_no": 2, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "Lucas Blackwood（卢卡斯·布莱克伍德），30岁男性，布莱克伍德家族继承人、狼人族长之子，冷峻压抑而危险。白人面孔，五官深邃立体、棱角分明，颧骨高、下颌线条锐利，眼瞳为幽蓝色、带有非人的微微荧光感，瞳色深邃迷人。黑色短发微长、略显凌乱地向后梳理，鬓角利落，发质粗硬。面部有淡淡胡茬，皮肤偏苍白带冷调。表情冷峻内敛、眉头微蹙，眼神中藏着深沉的悲痛与压抑。身材高大健壮、肩宽体魄强悍，身高约188cm。着装为暗黑贵族风——黑色长款羊毛大衣、内搭深灰色立领衬衫、黑色修身长裤、黑色皮质短靴，大衣领口微立。手指修长有力、指节粗壮，右手无名指佩戴一枚暗银色家族纹章戒指。整体气质是欧美暗黑奇幻中悲情守护者的冷峻贵族感，危险而迷人。", "part3": "欧美暗黑奇幻风格，参考《暮光之城》《吸血鬼日记》《真爱如血》的视觉氛围，色调偏冷暗、以黑灰深蓝为主色调，哥特浪漫气质。写实仿真人风格，高精度角色资产图。", "part4": ""}, "character_name": null, "negative_prompt": null}, {"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：Damien Grey（达米安·格雷），28岁男性，卢卡斯同父异母的兄长，野心勃勃的狼群叛徒，魅力型反派。白人面孔，五官英俊而带有邪魅感，嘴角常挂一抹似笑非笑的弧度，眼瞳琥珀色偏金、带有掠食者般的锐利光芒。棕色偏深的头发中长、整齐向后梳理、发型精致考究，露出饱满额头。面容干净无胡茬，皮肤质感好偏暖调。表情自信而带有危险的从容，眼神中透出算计与野心。身材高挑修长但结实、身高约185cm，姿态优雅而张扬。着装为暗色精致贵公子风——深酒红色丝绒西装外套、内搭黑色V领衬衫（领口微敞露出锁骨）、黑色修身西裤、黑色尖头皮鞋，胸口口袋别一枚暗金色狼头胸针。双手佩戴多枚暗色调戒指，手指修长。整体气质是危险的魅力型反派，优雅中藏着毁灭性的野心与残忍。\n\n人设：欧美暗黑奇幻风格，参考《暮光之城》《吸血鬼日记》《真爱如血》的视觉氛围，色调偏暗但带有酒红暗金的华丽邪魅感，哥特浪漫与暗黑贵族质感。写实仿真人风格，高精度角色资产图。", "line_no": 3, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "Damien Grey（达米安·格雷），28岁男性，卢卡斯同父异母的兄长，野心勃勃的狼群叛徒，魅力型反派。白人面孔，五官英俊而带有邪魅感，嘴角常挂一抹似笑非笑的弧度，眼瞳琥珀色偏金、带有掠食者般的锐利光芒。棕色偏深的头发中长、整齐向后梳理、发型精致考究，露出饱满额头。面容干净无胡茬，皮肤质感好偏暖调。表情自信而带有危险的从容，眼神中透出算计与野心。身材高挑修长但结实、身高约185cm，姿态优雅而张扬。着装为暗色精致贵公子风——深酒红色丝绒西装外套、内搭黑色V领衬衫（领口微敞露出锁骨）、黑色修身西裤、黑色尖头皮鞋，胸口口袋别一枚暗金色狼头胸针。双手佩戴多枚暗色调戒指，手指修长。整体气质是危险的魅力型反派，优雅中藏着毁灭性的野心与残忍。", "part3": "欧美暗黑奇幻风格，参考《暮光之城》《吸血鬼日记》《真爱如血》的视觉氛围，色调偏暗但带有酒红暗金的华丽邪魅感，哥特浪漫与暗黑贵族质感。写实仿真人风格，高精度角色资产图。", "part4": ""}, "character_name": null, "negative_prompt": null}, {"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：Selena Carter（塞琳娜·卡特），伊芙琳的姐姐，真相的关键人物，已故角色但需要在回忆与幻象中出现。白人女性，约28岁容貌，五官与伊芙琳高度相似但更柔和温婉，面容精致秀美、气质更为内敛柔和。眼瞳深棕偏暖色调，眼神温柔而带有淡淡忧伤。长发深棕色、长度过肩至胸口、自然柔顺的波浪卷发，发质柔亮。肤色白皙偏暖调，妆容柔美自然、唇色偏粉。表情温柔平静、嘴角带有淡淡微笑。身材纤细优雅。着装为柔美浪漫风格——象牙白色丝质长裙、微V领、裙摆及脚踝，外搭一件浅灰色薄开衫，脚穿裸色平底绑带凉鞋。脖子上同样佩戴与伊芙琳相同款式的银色古朴项链（姐妹对应道具）。整体气质是温婉美好却注定悲剧的角色，纯净而带有幽灵般的空灵感。\n\n人设：欧美暗黑奇幻风格，参考《暮光之城》《吸血鬼日记》的视觉氛围，但塞琳娜本身色调偏柔和暖白、带有回忆滤镜般的朦胧梦幻感，与整体暗黑基调形成对比。写实仿真人风格，高精度角色资产图。", "line_no": 4, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且