INSERT INTO "public"."import_files" VALUES (18, 15, '7f576edd-675a-4912-a1a9-47b07f29e90a.docx', 'docx', 11294, 'BATCH_CREATED', NULL, '2026-04-24 03:04:43.313', 'CREATE_BATCH', '{"errors": [], "prompts": [{"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：角色名：伊芙琳·卡特（Evelyn Carter）。26岁白人女性，纽约调查记者。面容精致而坚毅，高颧骨，下颌线条利落，眉形英气，双眼深邃带有警觉与倔强神色，瞳孔呈灰绿色并隐约泛银光。中长棕色直发，发尾微微内卷，几缕碎发自然垂在额侧，发质略显干涩体现风尘仆仆的记者气质。肤色白皙偏冷调，淡妆，裸色唇妆。穿深卡其色修身风衣，内搭黑色高领针织衫，腰间系窄皮带，下身深色修身牛仔裤，脚穿棕色低跟切尔西短靴。左手腕佩戴简约银色手表，右手食指戴一枚古旧银戒指。颈间佩戴一条继承自母亲的古老银链坠饰（月牙形吊坠，刻有神秘符文）。整体气质理性干练、城市感强，兼具脆弱与坚韧的双重张力。欧美暗黑奇幻风格，仿真人写实质感。", "line_no": 1, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色名：伊芙琳·卡特（Evelyn Carter）。26岁白人女性，纽约调查记者。面容精致而坚毅，高颧骨，下颌线条利落，眉形英气，双眼深邃带有警觉与倔强神色，瞳孔呈灰绿色并隐约泛银光。中长棕色直发，发尾微微内卷，几缕碎发自然垂在额侧，发质略显干涩体现风尘仆仆的记者气质。肤色白皙偏冷调，淡妆，裸色唇妆。穿深卡其色修身风衣，内搭黑色高领针织衫，腰间系窄皮带，下身深色修身牛仔裤，脚穿棕色低跟切尔西短靴。左手腕佩戴简约银色手表，右手食指戴一枚古旧银戒指。颈间佩戴一条继承自母亲的古老银链坠饰（月牙形吊坠，刻有神秘符文）。整体气质理性干练、城市感强，兼具脆弱与坚韧的双重张力。欧美暗黑奇幻风格，仿真人写实质感。", "part4": ""}, "character_name": null, "negative_prompt": null}, {"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：角色名：卢卡斯·布莱克伍德（Lucas Blackwood）。30岁白人男性，布莱克伍德狼人家族继承人、族长之子。身材高大健硕，约185cm，肩宽体壮但身形修长不臃肿。面部轮廓深邃锐利，高鼻梁，浓眉紧锁，颌骨线条分明如刀削，薄唇微抿，面部带有一道从左眉尾延伸至太阳穴的淡旧疤痕。双瞳呈幽蓝色，带有非人的冷冽微光。黑色短发，侧面剃短，顶部中等长度向后梳理，几缕不羁发丝落在额前，发色纯黑带微冷光泽。肤色偏白但带有常年户外的健康冷调。穿黑色长款羊毛大衣，内搭深灰色V领针织衫，下身黑色修身西裤，脚穿黑色皮质系带军靴。左手无名指戴一枚家族纹章黑钢戒指（狼头徽记），右手腕有一条编织皮绳手链。大衣领口微露锁骨处一组古老图腾纹身。整体气质冷峻压抑、危险且带有深沉忧郁的悲情感，如暗夜中的孤狼。欧美暗黑奇幻风格，仿真人写实质感。", "line_no": 2, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色名：卢卡斯·布莱克伍德（Lucas Blackwood）。30岁白人男性，布莱克伍德狼人家族继承人、族长之子。身材高大健硕，约185cm，肩宽体壮但身形修长不臃肿。面部轮廓深邃锐利，高鼻梁，浓眉紧锁，颌骨线条分明如刀削，薄唇微抿，面部带有一道从左眉尾延伸至太阳穴的淡旧疤痕。双瞳呈幽蓝色，带有非人的冷冽微光。黑色短发，侧面剃短，顶部中等长度向后梳理，几缕不羁发丝落在额前，发色纯黑带微冷光泽。肤色偏白但带有常年户外的健康冷调。穿黑色长款羊毛大衣，内搭深灰色V领针织衫，下身黑色修身西裤，脚穿黑色皮质系带军靴。左手无名指戴一枚家族纹章黑钢戒指（狼头徽记），右手腕有一条编织皮绳手链。大衣领口微露锁骨处一组古老图腾纹身。整体气质冷峻压抑、危险且带有深沉忧郁的悲情感，如暗夜中的孤狼。欧美暗黑奇幻风格，仿真人写实质感。", "part4": ""}, "character_name": null, "negative_prompt": null}, {"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：角色名：达米安·格雷（Damien Grey）。28岁白人男性，卢卡斯同父异母兄长，狼群叛徒，野心勃勃的魅力反派。身材修长匀称，约180cm，体态优雅而带有掠食者般的从容。面容英俊迷人，五官比卢卡斯更精致柔和，高挺鼻梁，嘴角常挂一抹意味深长的微笑，双眼呈琥珀金色，瞳孔深处藏有危险的算计。中长深棕色头发，微卷，自然散落在耳际与后颈，造型考究但不刻意，带有浪荡贵公子的不羁感。肤色象牙白，面部光洁无疤。穿深酒红色丝绒西装外套，黑色缎面衬衫微解两颗扣子，领口别一枚古银狼牙胸针，下身黑色修身西裤，脚穿酒红色尖头皮鞋。左手中指佩戴一枚暗金色蛇形戒指，右手腕戴黑表盘金边机械腕表。指甲修剪整齐但指尖微长暗示非人特征。整体气质优雅危险、如毒蛇般魅惑，表面彬彬有礼实则冷酷无情。欧美暗黑奇幻风格，仿真人写实质感。", "line_no": 3, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型