INSERT INTO "public"."import_files" VALUES (15, 9, 'inline-text.txt', 'text', 1621, 'BATCH_CREATED', NULL, '2026-04-23 11:54:33.258', 'CREATE_BATCH', '{"errors": [], "prompts": [{"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：陆观，31岁男性，中国人面孔，地理系学生气质，身高178cm，身形消瘦修长，面容清俊儒雅，黑色眼睛明亮有神，黑色短发中夹杂着几缕醒目的银白色发丝，形成独特的黑银交织发色。表情自然克制，带有一丝沉稳坚毅的气质。穿着一件略显破旧但干净整洁的深灰色立领外套，外套面料有轻微磨损痕迹但保持整洁，立领设计利落干练，内搭简素，整体着装朴素但不邋遢，透出书生气与隐忍坚韧感。\n\n参考风格：\n东方清俊书生气质男性，消瘦身形，黑银交织短发，深灰色立领旧外套，干净朴素，沉稳坚毅", "line_no": 1, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "陆观，31岁男性，中国人面孔，地理系学生气质，身高178cm，身形消瘦修长，面容清俊儒雅，黑色眼睛明亮有神，黑色短发中夹杂着几缕醒目的银白色发丝，形成独特的黑银交织发色。表情自然克制，带有一丝沉稳坚毅的气质。穿着一件略显破旧但干净整洁的深灰色立领外套，外套面料有轻微磨损痕迹但保持整洁，立领设计利落干练，内搭简素，整体着装朴素但不邋遢，透出书生气与隐忍坚韧感。", "part4": "东方清俊书生气质男性，消瘦身形，黑银交织短发，深灰色立领旧外套，干净朴素，沉稳坚毅"}, "character_name": null, "negative_prompt": null}, {"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：安德烈，35岁白人男性，北境同盟军事代表，身高190cm，身形魁梧壮硕如熊，肩宽体厚，肌肉感明显，面容刚毅棱角分明如石刻般硬朗，蓝色眼睛深邃冰冷带有压迫感，金色短发整齐利落一丝不苟。表情严肃冷峻，气场强大威压。穿着一件深蓝色军装式外套，军装剪裁挺括合体，肩章、纽扣等军装细节齐全，胸前佩戴着数枚象征战功的金属勋章，勋章金属质感光泽清晰可辨，整体造型充满北境军事强权的威严感与压迫力。\n\n参考风格：\n北欧硬汉军事强人，魁梧如熊，金发蓝眼，石刻般刚毅面容，深蓝色军装外套，金属战功勋章，冰