INSERT INTO "public"."import_files" VALUES (21, 16, '7f576edd-675a-4912-a1a9-47b07f29e90a.docx', 'docx', 11294, 'BATCH_CREATED', NULL, '2026-04-24 03:33:13.352', 'CREATE_BATCH', '{"errors": [], "prompts": [{"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：一位26岁的美国年轻女性，纽约记者身份，面容精致而坚韧，轮廓分明带有欧美混血感，高颧骨，下颌线条利落。深棕色长发自然微卷披散至肩下，发梢带有隐约的银色光泽暗示银血觉醒潜质。瞳孔为深琥珀色，眼神锐利而倔强，透出理性与不屈。肤色白皙偏暖，淡妆自然，唇色偏玫瑰粉。身材匀称修长，气质兼具都市女性的干练与隐藏的神秘感。身穿深色修身皮夹克，内搭灰黑色高领针织衫，下身黑色紧身牛仔裤，脚踩深棕色切尔西短靴。颈间佩戴一条银色古老项链（母亲遗物），造型简约但有精细的古老符文纹样。手腕戴一枚简约银色手表。整体风格为现代都市暗黑调，色调以深灰、黑、银为主。\n\n参考风格：\n欧美暗黑奇幻风格，仿真人写实质感，电影级高完成度角色设定图，参考《暮光之城》《吸血鬼日记》人物造型氛围，冷调高级色彩，皮肤质感真实细腻，服装面料质感清晰可辨", "line_no": 1, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "一位26岁的美国年轻女性，纽约记者身份，面容精致而坚韧，轮廓分明带有欧美混血感，高颧骨，下颌线条利落。深棕色长发自然微卷披散至肩下，发梢带有隐约的银色光泽暗示银血觉醒潜质。瞳孔为深琥珀色，眼神锐利而倔强，透出理性与不屈。肤色白皙偏暖，淡妆自然，唇色偏玫瑰粉。身材匀称修长，气质兼具都市女性的干练与隐藏的神秘感。身穿深色修身皮夹克，内搭灰黑色高领针织衫，下身黑色紧身牛仔裤，脚踩深棕色切尔西短靴。颈间佩戴一条银色古老项链（母亲遗物），造型简约但有精细的古老符文纹样。手腕戴一枚简约银色手表。整体风格为现代都市暗黑调，色调以深灰、黑、银为主。", "part4": "欧美暗黑奇幻风格，仿真人写实质感，电影级高完成度角色设定图，参考《暮光之城》《吸血鬼日记》人物造型氛围，冷调高级色彩，皮肤质感真实细腻，服装面料质感清晰可辨"}, "character_name": "伊芙琳·卡特 / Evelyn Carter", "negative_prompt": null}, {"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：一位30岁的欧美男性，布莱克伍德狼人家族继承人、族长之子。面容英俊冷峻，五官深邃立体，浓眉深目，高挺鼻梁，下颌轮廓锋利如刀刻，面部带有微微的沧桑感与压抑的危险气息。黑色短发略长，微乱地向后梳拢，鬓角修剪整齐，发质浓密带有微光。瞳色为深邃的幽蓝色，带有非人类的冷冽光泽，眼神阴郁克制却深藏暗涌。肤色偏冷白，下巴有淡淡的胡茬。身材高大健壮，肩宽体魄雄伟，肌肉线条隐约可见但不过度夸张。身穿黑色长款大衣，面料厚重质感如羊毛呢，内搭深灰色V领衬衫，领口微开，露出锁骨处一道古老的疤痕。下身黑色修身西裤，脚踩黑色皮质系带长靴。左手无名指佩戴一枚深色古铜家族戒指，戒面刻有狼首纹章。整体风格为暗黑哥特贵族感，色调以黑色、深灰、暗蓝为主，气质冷峻、压抑、危险且带有悲情守护者的深沉感。\n\n参考风格：\n欧美暗黑奇幻风格，仿真人写实质感，电影级高完成度角色设定图，参考《暮光之城》《吸血鬼日记》《真爱如血》男主造型氛围，冷调暗黑高级色彩，皮肤质感真实，服装面料质感精细可辨，狼人贵族气质", "line_no": 2, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "一位30岁的欧美男性，布莱克伍德狼人家族继承人、族长之子。面容英俊冷峻，五官深邃立体，浓眉深目，高挺鼻梁，下颌轮廓锋利如刀刻，面部带有微微的沧桑感与压抑的危险气息。黑色短发略长，微乱地向后梳拢，鬓角修剪整齐，发质浓密带有微光。瞳色为深邃的幽蓝色，带有非人类的冷冽光泽，眼神阴郁克制却深藏暗涌。肤色偏冷白，下巴有淡淡的胡茬。身材高大健壮，肩宽体魄雄伟，肌肉线条隐约可见但不过度夸张。身穿黑色长款大衣，面料厚重质感如羊毛呢，内搭深灰色V领衬衫，领口微开，露出锁骨处一道古老的疤痕。下身黑色修身西裤，脚踩黑色皮质系带长靴。左手无名指佩戴一枚深色古铜家族戒指，戒面刻有狼首纹章。整体风格为暗黑哥特贵族感，色调以黑色、深灰、暗蓝为主，气质冷峻、压抑、危险且带有悲情守护者的深沉感。", "part4": "欧美暗黑奇幻风格，仿真人写实质感，电影级高完成度角色设定图，参考《暮光之城》《吸血鬼日记》《真爱如血》男主造型氛围，冷调暗黑高级色彩，皮肤质感真实，服装面料质感精细可辨，狼人贵族气质"}, "character_name": "卢卡斯·布莱克伍德 / Lucas Blackwood", "negative_prompt": null}, {"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：一位28岁的欧美男性，卢卡斯同父异母的兄长，狼群中的叛徒与野心家。面容英俊但带有邪魅之气，五官精致略带阴柔，薄唇微勾似笑非笑，笑容迷人却令人不寒而栗。深棕色头发向后梳理得一丝不苟，两侧剃短，顶部较长，发型精致考究。瞳色为琥珀偏金色，眼神狡黠锐利，带有掠食者般的审视感。肤色白皙偏冷，面部轮廓略比卢卡斯柔和但更具攻击性。身材修长精干，体态优雅从容，举止带有贵族式的傲慢。身穿深酒红色丝绒西装外套，剪裁贴身精致，内搭黑色高领打底衫，下身黑色修身西裤，脚踩光面黑色尖头皮鞋。右手佩戴一枚暗红宝石戒指，左手腕戴一条细