INSERT INTO "public"."import_files" VALUES (24, NULL, '7f576edd-675a-4912-a1a9-47b07f29e90a.docx', 'docx', 11294, 'BATCH_CREATE_FAILED', 'THREE_VIEW params.view_set must contain front/side/back.', '2026-04-24 04:11:59.684', 'CREATE_BATCH', '{"errors": [], "prompts": [{"prompt": "基于人物定妆照生成人物三视图\n（16：9）面部占满左区，五官 / 发型 / 配饰清晰，无身体入镜、无遮挡变形；右区：标准角色设定三视图，横向排列（侧视图、正视图、背视图），三个视图严格呈现侧视、正视和背视，从头到脚完整无遮挡；核心约束：特写与三视图为同一角色，五官 / 服装 / 配饰 / 体态 100% 一致；右区尺寸：三视图角色高度画面高度的 80%，三视图高度统一；无多余元素的浅灰色背景，角色无阴影；超高清分辨率，统一85mm焦距，无畸变，角色无动作，平视；中性表情（无喜怒哀乐），眼神平静，自然站立，双手自然下垂。\n\n风格：角色名：伊芙琳·卡特（Evelyn Carter）；26岁白人女性，纽约调查记者；身高约168cm，身材纤细而结实；深棕色中长直发，自然垂落至锁骨下方，发尾略带自然弧度；琥珀色眼眸（觉醒后瞳孔边缘带淡银光），目光锐利坚定；轮廓清晰的椭圆脸型，直挺小巧鼻梁，薄唇，轻微雀斑；穿着深灰色修身机车皮夹克，内搭黑色V领薄针织衫，深蓝色修身牛仔裤，黑色低跟短踝靴；左手腕佩戴银色简约金属手表；颈部佩戴母亲遗留的银质古董项链，吊坠为新月形；整体气质理性、倔强、现代都市感，与姐姐塞琳娜面容一模一样但穿搭偏干练实用。\n\n参考风格：\n欧美暗黑奇幻风格，参考《暮光之城》《吸血鬼日记》《真爱如血》视觉氛围；电影级超写实仿真人质感；冷蓝灰色调为主，光影对比强烈，戏剧化打光；角色设定图风格统一，专业概念艺术级别。", "line_no": 1, "ext_params": {}, "source_mode": "template", "prompt_blocks": {"part1": "基于人物定妆照生成人物三视图\n（16：9）面部占满左区，五官 / 发型 / 配饰清晰，无身体入镜、无遮挡变形；右区：标准角色设定三视图，横向排列（侧视图、正视图、背视图），三个视图严格呈现侧视、正视和背视，从头到脚完整无遮挡；核心约束：特写与三视图为同一角色，五官 / 服装 / 配饰 / 体态 100% 一致；右区尺寸：三视图角色高度画面高度的 80%，三视图高度统一；无多余元素的浅灰色背景，角色无阴影；超高清分辨率，统一85mm焦距，无畸变，角色无动作，平视；中性表情（无喜怒哀乐），眼神平静，自然站立，双手自然下垂。", "part2": "角色名：伊芙琳·卡特（Evelyn Carter）；26岁白人女性，纽约调查记者；身高约168cm，身材纤细而结实；深棕色中长直发，自然垂落至锁骨下方，发尾略带自然弧度；琥珀色眼眸（觉醒后瞳孔边缘带淡银光），目光锐利坚定；轮廓清晰的椭圆脸型，直挺小巧鼻梁，薄唇，轻微雀斑；穿着深灰色修身机车皮夹克，内搭黑色V领薄针织衫，深蓝色修身牛仔裤，黑色低跟短踝靴；左手腕佩戴银色简约金属手表；颈部佩戴母亲遗留的银质古董项链，吊坠为新月形；整体气质理性、倔强、现代都市感，与姐姐塞琳娜面容一模一样但穿搭偏干练实用。", "part4": "欧美暗黑奇幻风格，参考《暮光之城》《吸血鬼日记》《真爱如血》视觉氛围；电影级超写实仿真人质感；冷蓝灰色调为主，光影对比强烈，戏剧化打光；角色设定图风格统一，专业概念艺术级别。"}, "character_name": null, "negative_prompt": null}, {"prompt": "基于人物定妆照生成人物三视图\n（16：9）面部占满左区，五官 / 发型 / 配饰清晰，无身体入镜、无遮挡变形；右区：标准角色设定三视图，横向排列（侧视图、正视图、背视图），三个视图严格呈现侧视、正视和背视，从头到脚完整无遮挡；核心约束：特写与三视图为同一角色，五官 / 服装 / 配饰 / 体态 100% 一致；右区尺寸：三视图角色高度画面高度的 80%，三视图高度统一；无多余元素的浅灰色背景，角色无阴影；超高清分辨率，统一85mm焦距，无畸变，角色无动作，平视；中性表情（无喜怒哀乐），眼神平静，自然站立，双手自然下垂。\n\n风格：角色名：卢卡斯·布莱克伍德（Lucas Blackwood）；30岁白人男性，布莱克伍德狼人家族