INSERT INTO "public"."import_files" VALUES (27, 22, '7f576edd-675a-4912-a1a9-47b07f29e90a.docx', 'docx', 11294, 'BATCH_CREATED', NULL, '2026-04-24 04:42:35.97', 'CREATE_BATCH', '{"errors": [], "prompts": [{"prompt": "基于人物定妆照生成人物三视图\n（16：9）面部占满左区，五官 / 发型 / 配饰清晰，无身体入镜、无遮挡变形；右区：标准角色设定三视图，横向排列（侧视图、正视图、背视图），三个视图严格呈现侧视、正视和背视，从头到脚完整无遮挡；核心约束：特写与三视图为同一角色，五官 / 服装 / 配饰 / 体态 100% 一致；右区尺寸：三视图角色高度画面高度的 80%，三视图高度统一；无多余元素的浅灰色背景，角色无阴影；超高清分辨率，统一85mm焦距，无畸变，角色无动作，平视；中性表情（无喜怒哀乐），眼神平静，自然站立，双手自然下垂。\n\n风格：角色：伊芙琳·卡特（Evelyn Carter）。26岁白人女性，纽约记者。中长深棕色微卷发，略过肩，发尾带隐约银色光泽。淡褐绿色眼瞳，瞳孔深处泛极淡银光。面部线条清晰，轻微雀斑分布在鼻梁两侧，皮肤自然偏白。身高约165cm，身材纤瘦但结实。上身穿深棕色合身皮夹克，内搭深灰色圆领亨利衫；下身深蓝色修身牛仔裤，脚穿棕色低跟短靴。脖颈佩戴一条银色弯月吊坠项链（母亲遗物）。无其他首饰，妆容极淡自然。整体气质理性、倔强、干练。\n\n参考风格：\n欧美暗黑奇幻风格，参考《暮光之城》《吸血鬼日记》《真爱如血》视觉氛围。电影级写实质感，色调以冷灰蓝和暗棕大地色为主。哥特美式小镇背景人物设定。", "line_no": 1, "ext_params": {}, "source_mode": "template", "prompt_blocks": {"part1": "基于人物定妆照生成人物三视图\n（16：9）面部占满左区，五官 / 发型 / 配饰清晰，无身体入镜、无遮挡变形；右区：标准角色设定三视图，横向排列（侧视图、正视图、背视图），三个视图严格呈现侧视、正视和背视，从头到脚完整无遮挡；核心约束：特写与三视图为同一角色，五官 / 服装 / 配饰 / 体态 100% 一致；右区尺寸：三视图角色高度画面高度的 80%，三视图高度统一；无多余元素的浅灰色背景，角色无阴影；超高清分辨率，统一85mm焦距，无畸变，角色无动作，平视；中性表情（无喜怒哀乐），眼神平静，自然站立，双手自然下垂。", "part2": "角色：伊芙琳·卡特（Evelyn Carter）。26岁白人女性，纽约记者。中长深棕色微卷发，略过肩，发尾带隐约银色光泽。淡褐绿色眼瞳，瞳孔深处泛极淡银光。面部线条清晰，轻微雀斑分布在鼻梁两侧，皮肤自然偏白。身高约165cm，身材纤瘦但结实。上身穿深棕色合身皮夹克，内搭深灰色圆领亨利衫；下身深蓝色修身牛仔裤，脚穿棕色低跟短靴。脖颈佩戴一条银色弯月吊坠项链（母亲遗物）。无其他首饰，妆容极淡自然。整体气质理性、倔强、干练。", "part4": "欧美暗黑奇幻风格，参考《暮光之城》《吸血鬼日记》《真爱如血》视觉氛围。电影级写实质感，色调以冷灰蓝和暗棕大地色为主。哥特美式小镇背景人物设定。"}, "character_name": null, "negative_prompt": null}, {"prompt": "基于人物定妆照生成人物三视图\n（16：9）面部占满左区，五官 / 发型 / 配饰清晰，无身体入镜、无遮挡变形；右区：标准角色设定三视图，横向排列（侧视图、正视图、背视图），三个视图严格呈现侧视、正视和背视，从头到脚完整无遮挡；核心约束：特写与三视图为同一角色，五官 / 服装 / 配饰 / 体态 100% 一致；右区尺寸：三视图角色高度画面高度的 80%，三视图高度统一；无多余元素的浅灰色背景，角色无阴影；超高清分辨率，统一85mm焦距，无畸变，角色无动作，平视；中性表情（无喜怒哀乐），眼神平静，自然站立，双手自然下垂。\n\n风格：角色：卢卡斯·布莱克伍德（Lucas Blackwood）。30岁白人男性，布莱克伍德家族继承人，狼人族长之子。短黑色头发，微乱但有型，两鬓略短。深邃幽蓝色眼瞳，带一丝非人的冷光。面部棱角分明，高颧骨，强壮下颌线，浓眉，唇线锋利，面色冷白。身高约188cm，高大健壮体型，肩宽背厚。穿一件黑色长款修身羊毛大衣，内搭黑色立领衬衫，纽扣扣至最上方；深灰色修身西裤，脚穿黑色皮靴。双手指节粗壮，指甲略长略尖。无明显首饰。整体气质冷峻、压抑、危险，哥特贵