INSERT INTO "public"."import_files" VALUES (28, 23, 'inline-text.txt', 'text', 1621, 'BATCH_CREATED', NULL, '2026-04-24 05:17:46.311', 'CREATE_BATCH', '{"errors": [], "prompts": [{"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：角色名：陆观。31岁中国男性，地理系学生。身高178cm，身形消瘦清瘦，体态略显单薄但挺拔。面容清俊端正，五官线条清秀利落，颧骨微显，下颌线分明。黑色眼睛，目光沉静内敛，透出坚定感。黑色短发，发丝间夹杂明显的几缕银白色发丝，形成黑银相间的独特发色效果，发型整洁自然，微有层次。穿着一件略显破旧但干净整洁的深灰色立领外套，面料略有磨损痕迹但保持体面，立领设计贴合颈部，外套合身略收腰，内搭深色简约衬衣。下身深色长裤，黑色简洁靴鞋。整体气质为沉稳内敛的青年学者形象，带有经历沧桑后的坚韧感。\n\n参考风格：\n画风：写实偏电影概念设定风格，半写实CG质感。色调以深灰、黑色、银白为主调，冷静沉稳。强调黑发中银白发丝的细节刻画，立领外套的面料质感与微旧磨损细节需清晰可辨。全身像，角色定妆照构图。", "line_no": 1, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色名：陆观。31岁中国男性，地理系学生。身高178cm，身形消瘦清瘦，体态略显单薄但挺拔。面容清俊端正，五官线条清秀利落，颧骨微显，下颌线分明。黑色眼睛，目光沉静内敛，透出坚定感。黑色短发，发丝间夹杂明显的几缕银白色发丝，形成黑银相间的独特发色效果，发型整洁自然，微有层次。穿着一件略显破旧但干净整洁的深灰色立领外套，面料略有磨损痕迹但保持体面，立领设计贴合颈部，外套合身略收腰，内搭深色简约衬衣。下身深色长裤，黑色简洁靴鞋。整体气质为沉稳内敛的青年学者形象，带有经历沧桑后的坚韧感。", "part4": "画风：写实偏电影概念设定风格，半写实CG质感。色调以深灰、黑色、银白为主调，冷静沉稳。强调黑发中银白发丝的细节刻画，立领外套的面料质感与微旧磨损细节需清晰可辨。全身像，角色定妆照构图。"}, "character_name": "陆观", "negative_prompt": null}, {"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：角色名：安德烈。35岁北欧/斯拉夫血统白人男性，北境同盟军事代表。身高190cm，身形极为魁梧壮硕如熊，肩宽体厚，肌肉结实，体格雄伟具有强烈压迫感。面容刚毅粗犷如石刻般棱角分明，颧骨高耸，下颌方阔有力，眉骨突出。蓝色眼睛深邃冰冷，目光如冰原般凛冽锐利。金色短发整齐利落，向后梳理，发质硬朗。穿着一件深蓝色军装式外套，剪裁笔挺，肩章结构清晰，纽扣为金属质感，胸前佩戴着多枚象征战功的金属勋章，勋章造型精致，带有北境寒原军事风格的纹饰。内搭深色高领衬衣，腰间束有军用皮带。下身深蓝色军裤，黑色军靴厚重有力。双手宽大有力，指关节粗壮。整体气质为铁血冷峻的军事强人形象，充满威压与力量感。\n\n参考风格：\n画风：写实偏电影概念设定风格，半写实CG质感。色调以深蓝、金属色、冰蓝为主调，冷硬肃穆。强调魁梧身形的体量感、军装的笔挺剪裁与勋章的金属反光细节，蓝色眼睛需有冰冷通透的质感。全身像，角色定妆照构图。", "line_no": 2, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色名：安德烈。35岁北欧/斯拉夫血统白人男性，北境同盟军事代表。身高190cm，身形极为魁梧壮硕如熊，肩宽体厚，肌肉结实，体格雄伟具有强烈压迫感。面容刚毅粗犷如石刻般棱角分明，颧骨高耸，下颌方阔有力，眉骨突出。蓝色眼睛深邃冰冷，目光如冰原般凛冽锐利。金色短发整齐利落，向后梳理，发质硬朗。穿着一件深蓝色军装式外套，剪裁笔挺，肩章结构清晰，纽扣为金属质感，胸前佩戴着多枚象征战功的金属勋章，勋章造型精致，带有北境寒原军事风格的纹饰。内搭深色高领衬衣，腰间束有军用皮带。下身深蓝色军裤，黑色军靴厚重有力。双手宽大有力，指关节粗壮。整体气质为铁血冷峻的军事强人形象，充满威压与力量感。", "part4": "画风：写实偏电影概念设定风格，半写实CG质感。色调以深蓝、金属色、冰蓝为主调，冷硬肃穆。强调魁梧身形的体量感、军装的笔挺剪裁与勋章的金属反光细节，蓝色眼睛需有冰冷通透的质感。全身像，角色定妆照构图。"}, "character_name": "安德烈", "negative_prompt": null}, {"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：角色名：千岛凛。28岁日本女性，精英学者兼武士。身高165cm，身形纤细如柳，体态修长轻盈但暗含力量感，腰身纤细，四肢匀称。面容清冷似霜，五官精致锐利，眉目如画但不带丝毫温度，唇线紧致，表情冷淡克制。黑色眼睛极为锐利如刀锋般具有穿透力，目光冷静。黑色长发浓密顺直，束成一丝不苟的高马尾，发丝光泽如墨，无一缕碎发散落，马尾利落垂于脑后。穿着一套黑色改良制服，融合日式制服与武士装束元素，上衣立领合身，衣摆利落，袖口收紧便于行动，面料平整具有高级质感，细节处可见暗纹或极简徽章装饰。腰间配戴一柄古朴武士刀，刀鞘为深色木质或漆面，刀柄缠绕传统菱形绳结，造型古雅。下身黑色修身长裤或裙裤，黑色简洁短靴。整体气质为冰冷锐利的女武士学者形象，精准、克制、带有致命美感。\n\n参考风格：\n画风：写实偏电影概念设定风格，半写实CG质感。色调以黑色、深灰为绝对主调，极简冷调，可带微弱冷光勾勒轮廓。强调高马尾的利落线条与发丝光泽、黑色改良制服的面料质感与剪裁细节、武士刀的古朴造型与刀柄缠绳纹理。全身像，角色定妆照构图。", "line_no": 3, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色名：千岛凛。28岁日本女性，精英学者兼武士。身高165cm，身形纤细如柳，体态修长轻盈但暗含力量感，腰身纤细，四肢匀称。面容清冷似霜，五官精致锐利，眉目如画但不带丝毫温度，唇线紧致，表情冷淡克制。黑色眼睛极为锐利如刀锋般具有穿透力，目光冷静。黑色长发浓密顺直，束成一丝不苟的高马尾，发丝光泽如墨，无一缕碎发散落，马尾利落垂于脑后。穿着一套黑色改良制服，融合日式制服与武士装束元素，上衣立领合身，衣摆利落，袖口收紧便于行动，面料平整具有高级质感，细节处可见暗纹或极简徽章装饰。腰间配戴一柄古朴武士刀，刀鞘为深色木质或漆面，刀柄缠绕传统菱形绳结，造型古雅。下身黑色修身长裤或裙裤，黑色简洁短靴。整体气质为冰冷锐利的女武士学者形象，精准、克制、带有致命美感。", "part4": "画风：写实偏电影概念设定风格，半写实CG质感。色调以黑色、深灰为绝对主调，极简冷调，可带微弱冷光勾勒轮廓。强调高马尾的利落线条与发丝光泽、黑色改良制服的面料质感与剪裁细节、武士刀的古朴造型与刀柄缠绳纹理。全身像，角色定妆照构图。"}, "character_name": "千岛凛", "negative_prompt": null}, {"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：角色名：阿米尔。40岁南亚/印度血统男性，天竺联邦外交官兼智者。身高175cm，身形匀称稳健，体态从容端庄，既不过于壮硕也不瘦弱，身姿挺直带有贵族气度。面容温和慈善，五官深邃立体，眉目舒展，鼻梁挺拔，嘴角微带暖意的笑容，面部线条柔中有刚。棕色眼睛温润深沉，充满睿智与洞察力，目光如深潭般平静。黑色卷发自然蓬松，发卷柔和，发丝间已染有几缕明显的银丝，显出成熟智者的阅历。头戴一顶精美的绣金头巾，头巾为白色或米色基底，边缘与局部饰有金色刺绣花纹，绣工精致，符合南亚贵族风格，包裹方式庄重典雅。穿着白色亚麻长袍，面料质朴透气，垂坠自然，长袍剪裁宽松大方，领口与袖口可见细密的装饰纹样或暗纹，腰间可束有浅色织带或腰带。脚穿浅色皮质凉鞋或传统鞋履。整体气质为温文睿智的贵族学者外交官形象，从容、儒雅、深不可测。\n\n参考风格：\n画风：写实偏电影概念设定风格，半写实CG质感。色调以白色、米色、金色为主调，温暖明亮而不失庄重。强调绣金头巾的刺绣细节与金线光泽、白色亚麻长袍的面料质感与垂坠感、卷发中银丝的自然过渡、棕色眼睛的温润深度。全身像，角色定妆照构图。", "line_no": 4, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色名：阿米尔。40岁南亚/印度血统男性，天竺联邦外交官兼智者。身高175cm，身形匀称稳健，体态从容端庄，既不过于壮硕也不瘦弱，身姿挺直带有贵族气度。面容温和慈善，五官深邃立体，眉目舒展，鼻梁挺拔，嘴角微带暖意的笑容，面部线条柔中有刚。棕色眼睛温润深沉，充满睿智与洞察力，目光如深潭般平静。黑色卷发自然蓬松，发卷柔和，发丝间已染有几缕明显的银丝，显出成熟智者的阅历。头戴一顶精美的绣金头巾，头巾为白色或米色基底，边缘与局部饰有金色刺绣花纹，绣工精致，符合南亚贵族风格，包裹方式庄重典雅。穿着白色亚麻长袍，面料质朴透气，垂坠自然，长袍剪裁宽松大方，领口与袖口可见细密的装饰纹样或暗纹，腰间可束有浅色织带或腰带。脚穿浅色皮质凉鞋或传统鞋履。整体气质为温文睿智的贵族学者外交官形象，从容、儒雅、深不可测。", "part4": "画风：写实偏电影概念设定风格，半写实CG质感。色调以白色、米色、金色为主调，温暖明亮而不失庄重。强调绣金头巾的刺绣细节与金线光泽、白色亚麻长袍的面料质感与垂坠感、卷发中银丝的自然过渡、棕色眼睛的温润深度。全身像，角色定妆照构图。"}, "character_name": "阿米尔", "negative_prompt": null}], "raw_count": 1, "source_type": "text", "valid_count": 4, "invalid_count": 0}', '{"dedupe": true, "params": {"count": 1}, "task_name": "", "capability": "PORTRAIT", "parse_mode": "claude", "folder_name": "batch-output", "submit_mode": "CREATE_BATCH", "idempotency_key": null, "template_config": {"mode": "template", "preset": "PORTRAIT", "defaults": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "", "part4": ""}, "language_mode": "zh_with_en_reference"}}', '主角——陆观31岁，地理系学生，身高178cm，身形消瘦，面容清俊，黑色眼睛，黑色短发中夹杂着几缕银白色发丝。常穿着一件略显破旧但干净的深灰色立领外套，穿越后决心帮助大夏重振国威。北境同盟代表——安德烈35岁，北境同盟军事代表，身高190cm，身形魁梧如熊，面容刚毅如石刻，蓝色眼睛深邃冰冷，金色短发整齐利落。常穿着一件深蓝色军装式外套，佩戴着象征战功的金属勋章。他出身北境寒原的军事世家，自幼接受严酷训练，目的是在帝王擂台上以绝对武力碾压对手，为同盟夺取能源配额与土地权限，巩固北境在全球的霸权地位。樱花代表——千岛凛28岁，樱花精英学者兼武士，身高165cm，身形纤细如柳，面容清冷似霜，黑色眼睛锐利如刀，黑色长发束成一丝不苟的高马尾。常穿着一套黑色改良制服，配戴一柄古朴武士刀。她来自学阀高层家族，精通历史与战术，目的是通过帝王擂台召唤樱花历史中的强者，赢得科技密钥以提升学阀实力，并暗中抹除其他文明的历史痕迹。天竺代表——阿米尔40岁，天竺联邦外交官兼智者，身高175cm，身形匀称稳健，面容温和带笑，棕色眼睛充满睿智，黑色卷发间已染几缕银丝。常穿着白色亚麻长袍，头戴绣金头巾。他出身天竺古老贵族，深谙历史哲学，目的是在擂台上召唤联邦帝王，竞争能源配额，同时借此机会修复天竺被篡改的历史记忆，重塑联邦文明尊严。', NULL, 0, 3, NULL, NULL, NULL, '2026-04-24 13:17:46.308807+08', '2026-04-24 13:18:50.402+08', NULL);
