INSERT INTO "public"."import_files" VALUES (42, 37, 'inline-text.txt', 'text', 552, 'BATCH_CREATED', NULL, '2026-04-27 11:32:20.359', 'CREATE_BATCH', '{"errors": [], "prompts": [{"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：饱经风霜却气势磅礴的年长男性仙道人物，面容沧桑却威严庄重，深邃双眸中燃烧着稳定的金色灵光，长长的白须垂至腰间，白发苍苍。身着厚重多层长袍，由闪耀的白色丝绸与银线织锦组成，袍面绣有精美的八卦纹样和天云图案，层次丰富华贵。头戴华丽的白玉金冠法冠，庄严端正。手腕佩戴银白色光芒的金刚钻手镯，散发淡淡灵光。右手持一把精美的白色马尾拂尘，拂尘柄由半透明白色玉石雕刻而成，温润通透。整体气质为仙风道骨、威严深沉的高阶仙人形象。\n\n参考风格：\n东方仙侠风格，中国古典神话美术设定，高精度角色概念设计图，全身立像，细腻写实与神话感并重，白银色调为主，灵光微漫，庄严肃穆氛围。", "line_no": 1, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "饱经风霜却气势磅礴的年长男性仙道人物，面容沧桑却威严庄重，深邃双眸中燃烧着稳定的金色灵光，长长的白须垂至腰间，白发苍苍。身着厚重多层长袍，由闪耀的白色丝绸与银线织锦组成，袍面绣有精美的八卦纹样和天云图案，层次丰富华贵。头戴华丽的白玉金冠法冠，庄严端正。手腕佩戴银白色光芒的金刚钻手镯，散发淡淡灵光。右手持一把精美的白色马尾拂尘，拂尘柄由半透明白色玉石雕刻而成，温润通透。整体气质为仙风道骨、威严深沉的高阶仙人形象。", "part4": "东方仙侠风格，中国古典神话美术设定，高精度角色概念设计图，全身立像，细腻写实与神话感并重，白银色调为主，灵光微漫，庄严肃穆氛围。"}, "character_name": "角色1", "negative_prompt": null}], "raw_count": 1, "source_type": "text", "valid_count": 1, "invalid_count": 0}', '{"dedupe": true, "params": {"count": 4, "negative_prompt": "文字，logo"}, "task_name": "", "capability": "PORTRAIT", "parse_mode": "claude", "folder_name": "batch-output", "submit_mode": "CREATE_BATCH", "idempotency_key": null, "template_config": {"mode": "template", "preset": "PORTRAIT", "defaults": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "", "part4": ""}, "language_mode": "zh_with_en_reference"}}', '外貌：一位饱经风霜却气势磅礴的人物。他面容饱经沧桑却不失威严，长长的白须垂至腰间，深邃的双眸中燃烧着稳定的金色灵光。服饰：身着厚重的多层长袍，由闪耀的白色丝绸和银线织锦组成，上面绣有精美的八卦和天云图案。头戴华丽的白玉金冠（法冠）。手腕上佩戴着闪耀着银白色光芒的金刚钻（金刚卓），散发着淡淡的灵光。道具：他手持一把精美的白色马尾拂尘，拂尘柄由半透明的白色玉石雕刻而成。', NULL, 0, 3, NULL, NULL, NULL, '2026-04-27 11:32:21.073117+08', '2026-04-27 11:32:43.939+08', NULL);
INSERT INTO "public"."import_files" VALUES (43, 38, 'inline-text.txt', 'text', 4195, 'BATCH_CREATED', NULL, '2026-04-27 11:46:06.117', 'CREATE_BATCH', '{"errors": [], "prompts": [{"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：角色为一位忧郁的年轻男性工程师，约二十五六岁，面容消瘦，眼神深邃带有宿命般的疲惫与克制的哀愁，肤色偏苍白，面部与指缝间残留有细微的机油痕迹与碳粉感。发型为略显凌乱的中短发，自然落于额前，发色深棕偏灰。额头上方推起一副饱经风霜的黄铜防风护目镜，镜片为深琥珀色玻璃，铜框有磨损氧化痕迹与铆钉加固细节。上身穿做旧深焦茶色皮革背心，皮面有使用磨白与油渍渗透的真实质感，背心扣件为小型黄铜齿轮扣，内搭粗纺亚麻衬衫，袖口卷起。下身为厚帆布工装裤，膝部有磨损与缝补痕迹，裤脚束入厚底做旧皮革工靴。腰间系宽皮工具带，挂有微型扳手、油壶、气压表盘等功能性配件，铆钉与铜扣加固。最核心特征：右臂为一条精密蒸汽朋克机械义肢，从肩部以下完全替换。义肢外壳由红铜板与抛光钢片拼接组成，关节处清晰可见联动齿轮组、微型液压杆、细铜管路线，所有齿轮咬合关系合理可信，看起来能实际转动。义肢手腕处装有一个小型黄铜排气阀门，有微量蒸汽逸出的视觉暗示。义肢表面布满油腻光泽与使用划痕，个别铜管表面有绿色铜锈氧化层。左手为正常人类手掌，指节粗糙，指甲缝有油垢。整体造型强调功能性与劳动者身份，非装饰性堆砌。\n\n参考风格：\n蒸汽朋克美学风格（Steampunk），真人影视质感，电影级角色肖像品质。色彩体系以焦茶色、古铜金、铁锈红、烟灰为主调，金属部件呈温暖的琥珀橙反光。光影设计：主光为偏暖的琥珀金色侧光，模拟工业煤气灯光源穿透极淡蒸汽烟雾的丁达尔效应；辅以侧逆光勾勒机械义肢与皮革边缘的清晰轮廓光，凸显金属高光与皮革纹理；阴影区域深沉但保留细节，避免死黑。背景为深灰至焦茶色的干净渐变，可带极弱的暖色工业环境光晕，不添加具体场景元素。材质渲染要求：做旧皮革的磨白油润感、帆布的粗粝纤维质感、黄铜的温润氧化色泽、钢片的冷硬抛光反射、齿轮与铜管的精密机械真实感——所有材质必须可信真实，杜绝塑料感的亮金色。整体氛围庄严肃穆，带有宿命论的沉郁调性。8K分辨率，照片级写实渲染，等效35mm镜头视角，浅景深微虚化仅限背景边缘，人物全身锐利清晰。画面比例3:4竖幅。无文字，无logo，无水印。", "line_no": 1, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色为一位忧郁的年轻男性工程师，约二十五六岁，面容消瘦，眼神深邃带有宿命般的疲惫与克制的哀愁，肤色偏苍白，面部与指缝间残留有细微的机油痕迹与碳粉感。发型为略显凌乱的中短发，自然落于额前，发色深棕偏灰。额头上方推起一副饱经风霜的黄铜防风护目镜，镜片为深琥珀色玻璃，铜框有磨损氧化痕迹与铆钉加固细节。上身穿做旧深焦茶色皮革背心，皮面有使用磨白与油渍渗透的真实质感，背心扣件为小型黄铜齿轮扣，内搭粗纺亚麻衬衫，袖口卷起。下身为厚帆布工装裤，膝部有磨损与缝补痕迹，裤脚束入厚底做旧皮革工靴。腰间系宽皮工具带，挂有微型扳手、油壶、气压表盘等功能性配件，铆钉与铜扣加固。最核心特征：右臂为一条精密蒸汽朋克机械义肢，从肩部以下完全替换。义肢外壳由红铜板与抛光钢片拼接组成，关节处清晰可见联动齿轮组、微型液压杆、细铜管路线，所有齿轮咬合关系合理可信，看起来能实际转动。义肢手腕处装有一个小型黄铜排气阀门，有微量蒸汽逸出的视觉暗示。义肢表面布满油腻光泽与使用划痕，个别铜管表面有绿色铜锈氧化层。左手为正常人类手掌，指节粗糙，指甲缝有油垢。整体造型强调功能性与劳动者身份，非装饰性堆砌。", "part4": "蒸汽朋克美学风格（Steampunk），真人影视质感，电影级角色肖像品质。色彩体系以焦茶色、古铜金、铁锈红、烟灰为主调，金属部件呈温暖的琥珀橙反光。光影设计：主光为偏暖的琥珀金色侧光，模拟工业煤气灯光源穿透极淡蒸汽烟雾的丁达尔效应；辅以侧逆光勾勒机械义肢与皮革边缘的清晰轮廓光，凸显金属高光与皮革纹理；阴影区域深沉但保留细节，避免死黑。背景为深灰至焦茶色的干净渐变，可带极弱的暖色工业环境光晕，不添加具体场景元素。材质渲染要求：做旧皮革的磨白油润感、帆布的粗粝纤维质感、黄铜的温润氧化色泽、钢片的冷硬抛光反射、齿轮与铜管的精密机械真实感——所有材质必须可信真实，杜绝塑料感的亮金色。整体氛围庄严肃穆，带有宿命论的沉郁调性。8K分辨率，照片级写实渲染，等效35mm镜头视角，浅景深微虚化仅限背景边缘，人物全身锐利清晰。画面比例3:4竖幅。无文字，无logo，无水印。"}, "character_name": "角色1", "negative_prompt": null}], "raw_count": 28, "source_type": "text", "valid_count": 1, "invalid_count": 0}', '{"dedupe": true, "params": {"count": 1}, "task_name": "", "capability": "PORTRAIT", "parse_mode": "claude", "folder_name": "batch-output", "submit_mode": "CREATE_BATCH", "idempotency_key": null, "template_config": {"mode": "template", "preset": "PORTRAIT", "defaults": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "", "part4": ""}, "language_mode": "zh_with_en_reference"}}', 'system_instruction（对应 提示词工程（风格设定）顶层prompt）：你是剧本美术风格总监，负责为编剧、美术指导、概念设计师、分镜师、服化道团队和视觉生成系统提供统一的风格控制。 当用户选择某个风格标签后，你必须严格依据该标签的美术方向进行判断、补全和创作。 你的输出应始终关注以下维度： 1. 世界视觉基调 2. 场景空间设计 3. 人物造型方向 4. 服装与材质 5. 色彩系统 6. 光影设计 7. 镜头语言 8. 叙事美术重点 9. 应避免的视觉误区 你不需要解释风格来源，不要跳出创作语境。 你应像一名资深影视美术指导一样，确保所有视觉元素统一、可执行、服务剧情，并能被剧本、美术、分镜和视觉生成团队直接使用。
system_prompt      (对应 提示词工程（风格设定）橙色小标题)： 蒸汽朋克
【核心气质】
宏大工业叙事、机械崇拜、维多利亚余晖与东方机关术的碰撞、秩序与混乱并存、宿命的齿轮感、硬核工业美学、真人影视质感。
【世界视觉基调】
世界由天空浮岛、齿轮巨城、废气贫民窟、深渊矿区、机关秘境组成。
上层浮岛（云端拉普塔）： 高雅、整洁、金碧辉煌。由反重力核心支撑，遍布维多利亚式白色大理石建筑与纯金齿轮装饰。
中层巨城（钢骨核心）： 繁忙、灰暗。巨大的活塞泵、纵横交错的蒸汽管道、永远轰鸣的工厂、庞大的齐柏林飞艇港口。
底层荒区（铁锈深渊）： 阴暗、潮湿、破败。充斥着漏气的管道、锈迹斑斑的废弃零件、霓虹与油污混合的水洼。
机关秘境（上古枢纽）： 巨大的青铜精密仪器、沉睡的机械巨像、布满苔藓的联动齿轮组。
【人物造型方向】
机械师/发明家： 造型强调功能性，腰间挂满扳手、油壶，带有防风护目镜（实用品而非装饰），手部有长期劳作的油垢感。
帝国贵族/执行官： 考究的三件套西装或紧身礼裙，融入金属义肢，义肢表面雕刻精美花纹，彰显权力与财富。
地下反抗者： 粗糙的皮革护甲、防毒面具、战损痕迹、绑带元素，背负沉重的蒸汽背包作为动力源。
发条机械人： 露出内部精密齿轮结构的仿生皮肤，眼神空洞但带有一丝神性，动作僵硬且具有仪式感。
【服装与材质】
主要材质包括：做旧皮革、厚重帆布、粗纺呢绒、黄铜构件、红铜管道、抛光钢片、深色天鹅绒、油渍丝绸。
细节特征： 气压表盘、液压杆、联动齿轮轴、抽真空玻璃管（发光）、铆钉加固。
【色彩系统】
工业核心： 焦茶色、古铜金、铁锈红、烟灰。
权力中心： 皇室蓝、勃艮第红、象牙白、金箔色。
动力能源： 琥珀橙（热蒸汽）、幽邃蓝（电气流）、荧光绿（化学酸液）。
【光影设计】
光源特征： 强烈的丁达尔效应（穿透烟雾的光束）、昏黄的煤气灯、电弧火花、熔炉的暗红辐射。
光影层次： 侧逆光勾勒金属轮廓，阴影中隐藏错综复杂的管道结构。
【避免事项】
避免塑料质感的亮金色、避免毫无逻辑的齿轮堆砌（齿轮必须看起来能转动）、避免现代影楼风滤镜、避免反派廉价化（反派应有重工业压迫感）、避免过度的后启示录废土化。
user_content（实际内容输入）：电影级人物肖像，一位忧郁的年轻工程师，佩戴着饱经风霜的机械义肢，画面细节丰富，充满蒸汽朋克美学风格。他身着做旧皮背心、厚帆布裤，额头上戴着黄铜护目镜。机械臂内部清晰可见精密的齿轮和铜管，油腻的质感，蒸汽从手腕处的阀门喷涌而出。背景是一间光线昏暗的工坊，黄铜仪器的轮廓模糊不清。氛围：庄严肃穆，宿命论。光线：工业烟雾中透出金色的琥珀色光芒，金属部件上投射出清晰的轮廓光。8K分辨率，照片级写实，使用35mm镜头拍摄，电影剧照品质。--ar 3:4 --v 6.0 --无文字，无logo。', NULL, 0, 3, NULL, NULL, NULL, '2026-04-27 11:46:08.130268+08', '2026-04-27 11:47:13.473+08', NULL);
