INSERT INTO "public"."import_files" VALUES (44, 39, 'inline-text.txt', 'text', 4195, 'BATCH_CREATED', NULL, '2026-04-27 11:46:10.19', 'CREATE_BATCH', '{"errors": [], "prompts": [{"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：角色为一位忧郁的年轻男性工程师/机械师，约二十多岁，面容清瘦，神情沉郁内敛，目光深邃带有宿命感与疲惫。发型略显凌乱，额头正中佩戴一副黄铜护目镜（实用型工具，非装饰品），镜片边缘微沾油渍与水汽。上身穿一件做旧深棕色皮革背心，内搭灰白粗纺衬衫，袖口卷至肘部；下身穿厚帆布工装裤，膝部有磨损与油污痕迹；腰间皮带上挂有扳手、小油壶等机械师随身工具。一只手臂为饱经风霜的机械义肢，义肢外壳为黄铜与红铜材质拼接，表面有使用磨损与氧化斑，内部清晰可见精密联动齿轮组与铜管液压结构，手腕处设有一枚蒸汽泄压阀门，微量白色蒸汽从阀门缝隙溢出。义肢手掌关节铆钉可见，指节可活动。另一只手为肉手，指缝与指甲间有长期劳作留下的油垢。脚穿厚底做旧皮靴，靴面带有铜扣与皮带加固。整体造型强调功能性与工业劳动者气质，体现蒸汽朋克世界中层巨城底层工程师的真实生存状态。\n\n参考风格：\n蒸汽朋克美学风格（Steampunk），真人影视质感，电影级人物肖像品质。材质渲染重点：做旧皮革的磨损龟裂纹理、厚帆布的粗糙编织质感、黄铜与红铜部件的金属氧化与抛光对比、齿轮与管道的精密机械咬合结构（齿轮必须看起来能转动，符合机械逻辑）、油渍丝绸般的湿润反光、蒸汽的半透明扩散感。色彩系统以焦茶色、古铜金、铁锈红、烟灰为主色调，义肢金属高光呈琥珀橙暖调，暗部压入深褐与铁灰。光影设计：采用侧逆光勾勒机械义肢与人物轮廓，主光为琥珀色暖调工业光源，金属部件表面呈现清晰锐利的轮廓光（rim light），可带极弱丁达尔效应暗示工业烟雾环境但不遮挡人物。整体氛围庄严肃穆、宿命论基调。避免塑料质感的亮金色，避免无逻辑的齿轮堆砌装饰，避免现代影楼风滤镜与过度后期光效，避免后启示录废土化。8K分辨率，照片级写实渲染，35mm电影定焦镜头视角，适度浅景深，电影剧照品质。--ar 3:4 --v 6.0 --无文字，无logo。", "line_no": 1, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色为一位忧郁的年轻男性工程师/机械师，约二十多岁，面容清瘦，神情沉郁内敛，目光深邃带有宿命感与疲惫。发型略显凌乱，额头正中佩戴一副黄铜护目镜（实用型工具，非装饰品），镜片边缘微沾油渍与水汽。上身穿一件做旧深棕色皮革背心，内搭灰白粗纺衬衫，袖口卷至肘部；下身穿厚帆布工装裤，膝部有磨损与油污痕迹；腰间皮带上挂有扳手、小油壶等机械师随身工具。一只手臂为饱经风霜的机械义肢，义肢外壳为黄铜与红铜材质拼接，表面有使用磨损与氧化斑，内部清晰可见精密联动齿轮组与铜管液压结构，手腕处设有一枚蒸汽泄压阀门，微量白色蒸汽从阀门缝隙溢出。义肢手掌关节铆钉可见，指节可活动。另一只手为肉手，指缝与指甲间有长期劳作留下的油垢。脚穿厚底做旧皮靴，靴面带有铜扣与皮带加固。整体造型强调功能性与工业劳动者气质，体现蒸汽朋克世界中层巨城底层工程师的真实生存状态。", "part4": "蒸汽朋克美学风格（Steampunk），真人影视质感，电影级人物肖像品质。材质渲染重点：做旧皮革的磨损龟裂纹理、厚帆布的粗糙编织质感、黄铜与红铜部件的金属氧化与抛光对比、齿轮与管道的精密机械咬合结构（齿轮必须看起来能转动，符合机械逻辑）、油渍丝绸般的湿润反光、蒸汽的半透明扩散感。色彩系统以焦茶色、古铜金、铁锈红、烟灰为主色调，义肢金属高光呈琥珀橙暖调，暗部压入深褐与铁灰。光影设计：采用侧逆光勾勒机械义肢与人物轮廓，主光为琥珀色暖调工业光源，金属部件表面呈现清晰锐利的轮廓光（rim light），可带极弱丁达尔效应暗示工业烟雾环境但不遮挡人物。整体氛围庄严肃穆、宿命论基调。避免塑料质感的亮金色，避免无逻辑的齿轮堆砌装饰，避免现代影楼风滤镜与过度后期光效，避免后启示录废土化。8K分辨率，照片级写实渲染，35mm电影定焦镜头视角，适度浅景深，电影剧照品质。--ar 3:4 --v 6.0 --无文字，无logo。"}, "character_name": "角色1", "negative_prompt": null}], "raw_count": 28, "source_type": "text", "valid_count": 1, "invalid_count": 0}', '{"dedupe": true, "params": {"count": 4}, "task_name": "", "capability": "PORTRAIT", "parse_mode": "claude", "folder_name": "batch-output", "submit_mode": "CREATE_BATCH", "idempotency_key": null, "template_config": {"mode": "template", "preset": "PORTRAIT", "defaults": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "", "part4": ""}, "language_mode": "zh_with_en_reference"}}', 'system_instruction（对应 提示词工程（风格设定）顶层prompt）：你是剧本美术风格总监，负责为编剧、美术指导、概念设计师、分镜师、服化道团队和视觉生成系统提供统一的风格控制。 当用户选择某个风格标签后，你必须严格依据该标签的美术方向进行判断、补全和创作。 你的输出应始终关注以下维度： 1. 世界视觉基调 2. 场景空间设计 3. 人物造型方向 4. 服装与材质 5. 色彩系统 6. 光影设计 7. 镜头语言 8. 叙事美术重点 9. 应避免的视觉误区 你不需要解释风格来源，不要跳出创作语境。 你应像一名资深影视美术指导一样，确保所有视觉元素统一、可执行、服务剧情，并能被剧本、美术、分镜和视觉生成团队直接使用。
system_prompt      (对应 提示词工程（风格设定）橙色小标题)： 蒸汽朋克
【核心气质】
宏大工业叙事、机械崇拜、维多利亚余晖与东方机关术的碰撞、秩序与混乱并存、宿命的齿轮感、硬核工业美学、真人影视质感。
【世界视觉基调】
世界由天空浮岛、齿轮巨城、废气贫民窟、深渊矿区、机关秘境组成。
上层浮岛（云端拉普塔）： 高雅、整洁、金碧辉煌。由反重力核心支撑，遍布维多利亚式白色大理石建筑与纯金齿轮装饰。
中层巨城（钢骨核心）： 繁忙、灰暗。巨大的活塞泵、纵横交错的蒸汽管道、永远轰鸣的工厂、庞大的齐柏林飞艇港口。
底层荒区（铁锈深渊）： 阴暗、潮湿、破败。充斥着漏气的管道、锈迹斑斑的废弃零件、霓虹与油污混合的水洼。
机关秘境（上古枢纽）： 巨大的青铜精密仪器、沉睡的机械巨像、布满苔藓的联动齿轮组。
【人物造型方向】
机械师/发明家： 造型强调功能性，腰间挂满扳手、油壶，带有防风护目镜（实用品而非装饰），手部有长期劳作的油垢感。
帝国贵族/执行官： 考究的三件套西装或紧身礼裙，融入金属义肢，义肢表面雕刻精美花纹，彰显权力与财富。
地下反抗者： 粗糙的皮革护甲、防毒面具、战损痕迹、绑带元素，背负沉重的蒸汽背包作为动力源。
发条机械人： 露出内部精密齿轮结构的仿生皮肤，眼神空洞但带有一丝神性，动作僵硬且具有仪式感。
【服装与材质】
主要材质包括：做旧皮革、厚重帆布、粗纺呢绒、黄铜构件、红铜管道、抛光钢片、深色天鹅绒、油渍丝绸。
细节特征： 气压表盘、液压杆、联动齿轮轴、抽真空玻璃管（发光）、铆钉加固。
【色彩系统】
工业核心： 焦茶色、古铜金、铁锈红、烟灰。
权力中心： 皇室蓝、勃艮第红、象牙白、金箔色。
动力能源： 琥珀橙（热蒸汽）、幽邃蓝（电气流）、荧光绿（化学酸液）。
【光影设计】
光源特征： 强烈的丁达尔效应（穿透烟雾的光束）、昏黄的煤气灯、电弧火花、熔炉的暗红辐射。
光影层次： 侧逆光勾勒金属轮廓，阴影中隐藏错综复杂的管道结构。
【避免事项】
避免塑料质感的亮金色、避免毫无逻辑的齿轮堆砌（齿轮必须看起来能转动）、避免现代影楼风滤镜、避免反派廉价化（反派应有重工业压迫感）、避免过度的后启示录废土化。
user_content（实际内容输入）：电影级人物肖像，一位忧郁的年轻工程师，佩戴着饱经风霜的机械义肢，画面细节丰富，充满蒸汽朋克美学风格。他身着做旧皮背心、厚帆布裤，额头上戴着黄铜护目镜。机械臂内部清晰可见精密的齿轮和铜管，油腻的质感，蒸汽从手腕处的阀门喷涌而出。背景是一间光线昏暗的工坊，黄铜仪器的轮廓模糊不清。氛围：庄严肃穆，宿命论。光线：工业烟雾中透出金色的琥珀色光芒，金属部件上投射出清晰的轮廓光。8K分辨率，照片级写实，使用35mm镜头拍摄，电影剧照品质。--ar 3:4 --v 6.0 --无文字，无logo。', NULL, 0, 3, NULL, NULL, NULL, '2026-04-27 11:47:13.491981+08', '2026-04-27 11:48:19.121+08', NULL);
INSERT INTO "public"."import_files" VALUES (45, 40, 'inline-text.txt', 'text', 4168, 'BATCH_CREATED', NULL, '2026-04-27 11:55:09.996', 'CREATE_BATCH', '{"errors": [], "prompts": [{"prompt": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。\n\n风格：角色：忧郁的年轻男性工程师／机械师，约25–30岁。面容清瘦、轮廓分明，眉目间透出宿命般的忧郁与倦意，眼神深邃疲惫却仍坚定有神；肤色偏白但不洁净，颧骨与下颌线处可见淡淡的油污与烟尘痕迹。短发微乱，发丝偏深棕，额角与鬓角沾有汗渍与细微油渍。额头上推着一副黄铜防风护目镜——实用型工具而非装饰，铜框有磨损氧化，镜片边缘带划痕，皮质绑带做旧。上身穿深焦茶色做旧皮背心，表面有刮擦磨白与油渍包浆，铆钉固定肩缝，内搭粗纺灰棕衬衫，袖口卷至前臂。下身穿厚帆布工装裤，膝部有磨损补丁，裤脚微微塞入靴筒。腰间宽皮带上挂有小型黄铜扳手、铜质油壶、一枚气压表盘等工具配件。右臂为饱经风霜的全机械义肢，以黄铜与红铜为主材质，表面遍布划痕、氧化斑与油渍包浆，肩部接口处可见铆钉与皮革绑带固定结构；前臂外壳局部敞开，清晰暴露内部精密联动齿轮组、细铜管、微型液压杆——所有齿轮啮合合理，看起来可以运转；手腕处设有黄铜蒸汽排放阀门，微量白色蒸汽从阀缝溢出。机械手指关节分明，指尖有磨损。左手为肉手，指尖与指缝积有长期劳作的油垢，指甲缝发黑。脚穿厚底深棕色皮革工靴，鞋头有铆钉加固，鞋面有磨损使用痕迹。整体造型强调功能性、劳动磨损的真实感与硬核工业气质。\n\n参考风格：\n蒸汽朋克硬核工业美学，真人影视质感，电影级角色肖像品质。色彩体系以焦茶色、古铜金、铁锈红、烟灰色为核心基调，能量色为琥珀橙（热蒸汽光）。材质重点呈现做旧皮革的纤维纹理与包浆光泽、厚帆布的粗糙编织感、粗纺呢绒的颗粒质地、黄铜红铜金属的氧化磨损与油渍反光——杜绝塑料感亮金色，所有金属必须带有使用痕迹与工业真实感。齿轮与机械结构严格遵循物理逻辑，啮合正确可运转，禁止无意义堆砌。光影设计：主光为温暖琥珀金色调侧光，模拟丁达尔效应穿透极微弱的工业烟雾；侧逆光精确勾勒机械义肢的金属边缘高光与齿轮轮廓；阴影柔和有层次，暗部仍可辨识服装与机械结构细节。整体气质庄严肃穆、宿命论调性，参考维多利亚工业时代与东方机关术碰撞的世界观美学。渲染标准：8K分辨率，照片级写实，35mm电影定焦镜头质感，浅景深微虚化背景。背景为深灰至烟灰色干净渐变，可带极弱暖色环境光暗示工坊氛围，不添加具体场景道具。无文字，无logo。--ar 3:4", "line_no": 1, "ext_params": {"count": 1}, "source_mode": "template", "prompt_blocks": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色：忧郁的年轻男性工程师／机械师，约25–30岁。面容清瘦、轮廓分明，眉目间透出宿命般的忧郁与倦意，眼神深邃疲惫却仍坚定有神；肤色偏白但不洁净，颧骨与下颌线处可见淡淡的油污与烟尘痕迹。短发微乱，发丝偏深棕，额角与鬓角沾有汗渍与细微油渍。额头上推着一副黄铜防风护目镜——实用型工具而非装饰，铜框有磨损氧化，镜片