valid_count": 0}', '{"dedupe": true, "params": {"count": 1}, "task_name": "", "capability": "PORTRAIT", "parse_mode": "claude", "folder_name": "batch-output", "submit_mode": "CREATE_BATCH", "idempotency_key": null, "template_config": {"mode": "template", "preset": "PORTRAIT", "defaults": {"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。画面严禁出现任何文字、字母、数字、书法、印章、水印、logo、签名、标签、标注、UI 元素、边框、说明框或注释；角色服装、配饰、道具上也不得出现可辨识的文字图案或符号。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "", "part4": ""}, "language_mode": "zh_with_en_reference"}}', '主角——陆观31岁，地理系学生，身高178cm，身形消瘦，面容清俊，黑色眼睛，黑色短发中夹杂着几缕银白色发丝。常穿着一件略显破旧但干净的深灰色立领外套，穿越后决心帮助大夏重振国威。北境同盟代表——安德烈35岁，北境同盟军事代表，身高190cm，身形魁梧如熊，面容刚毅如石刻，蓝色眼睛深邃冰冷，金色短发整齐利落。常穿着一件深蓝色军装式外套，佩戴着象征战功的金属勋章。他出身北境寒原的军事世家，自幼接受严酷训练，目的是在帝王擂台上以绝对武力碾压对手，为同盟夺取能源配额与土地权限，巩固北境在全球的霸权地位。樱花代表——千岛凛28岁，樱花精英学者兼武士，身高165cm，身形纤细如柳，面容清冷似霜，黑色眼睛锐利如刀，黑色长发束成一丝不苟的高马尾。常穿着一套黑色改良制服，配戴一柄古朴武士刀。她来自学阀高层家族，精通历史与战术，目的是通过帝王擂台召唤樱花历史中的强者，赢得科技密钥以提升学阀实力，并暗中抹除其他文明的历史痕迹。天竺代表——阿米尔40岁，天竺联邦外交官兼智者，身高175cm，身形匀称稳健，面容温和带笑，棕色眼睛充满睿智，黑色卷发间已染几缕银丝。常穿着白色亚麻长袍，头戴绣金头巾。他出身天竺古老贵族，深谙历史哲学，目的是在擂台上召唤联邦帝王，竞争能源配额，同时借此机会修复天竺被篡改的历史记忆，重塑联邦文明尊严。', NULL, 0, 3, NULL, NULL, NULL, '2026-04-27 16:15:36.159456+08', '2026-04-27 16:16:12.875+08', NULL);
INSERT INTO "public"."import_files" VALUES (48, 45, 'inline-text.txt', 'text', 1621, 'BATCH_CREATED', NULL, '2026-04-27 17:42:48.349', 'CREATE_BATCH', '{"errors": [], "prompts": [{"prompt": "1boy, 31 years old, 178cm tall, thin build, handsome clean face, black eyes, black short hair with several silver-white streaks, wearing a slightly worn but clean dark gray stand-collar jacket\n\n风格：geography student, determined expression, scholarly aura, resolute gaze\n\n参考风格：\nLu Guan, protagonist, a geography student who crossed into another world, determined to help restore national glory, youthful yet weathered appearance with premature silver streaks", "line_no": 1, "ext_params": {}, "source_mode": "template", "prompt_blocks": {"part1": "1boy, 31 years old, 178cm tall, thin build, handsome clean face, black eyes, black short hair with several silver-white streaks, wearing a slightly worn but clean dark gray stand-collar jacket", "part2": "geography student, determined expression, scholarly aura, resolute gaze", "part4": "Lu Guan, protagonist, a geography student who crossed into another world, determined to help restore national glory, youthful yet weathered appearance with premature silver streaks"}, "character_name": "角色1", "negative_prompt": null}, {"prompt": "1boy, 35 years old, 190cm tall, burly bear-like build, chiseled stone-like rugged face, deep cold blue eyes, neat short golden hair, wearing a dark blue military-style coat with metal merit badges\n\n风格：military representative, imposing authoritative presence, cold intimidating aura, warrior stance\n\n参考风格：\nAndre, Northern Alliance military representative, born into a military family from the frozen northern plains, trained rigorously since childhood, seeks to dominate the Emperor Arena with absolute force to secure energy quotas and territorial rights", "line_no": 2, "ext_params": {}, "source_mode": "template", "prompt_blocks": {"part1": "1boy, 35 years old, 190cm tall, burly bear-like build, chiseled stone-like rugged face, deep cold blue eyes, neat short golden hair, wearing a dark blue military-style coat with metal merit badges", "part2": "military representative, imposing authoritative presence, cold intimidating aura, warrior stance", "part4": "Andre, Northern Alliance military representative, born into a military family from the frozen northern plains, trained rigorously since childhood, seeks to dominate the Emperor Arena with absolute force to secure energy quotas and territorial rights"}, "character_name": "角色2", "negative_prompt": null}, {"prompt": "1girl, 28 years old, 165cm tall, slender willow-like figure, cold frost-like face, sharp blade-like black eyes, long black hair tied in a meticulous high ponytail, wearing a black modified uniform, carrying an antique katana\n\n风格：elite scholar and warrior, cold and precise demeanor, lethal elegance, disciplined posture\n\n参考风格：\nChishima Rin, Sakura representative, elite scholar and samurai from an academic elite family, master of history and tactics, aims to summon historical warriors through the Emperor Arena to obtain technology keys and secretly erase other civilizations'' historical traces", "line_no": 3, "ext_params": {}, "source_mode": "template", "prompt_blocks": {"part1": "1girl, 28 years old, 165cm tall, slender willow-like figure, cold frost-like face, sharp blade-like black eyes, long black hair tied in a meticulous high ponytail, wearing a black modified uniform, carrying an antique katana", "part2": "elite scholar and warrior, cold and precise demeanor, lethal elegance, disciplined posture", "part4": "Chishima Rin, Sakura representative, elite scholar and samurai from an academic elite family, master of history and tactics, aims to summon historical warriors through the Emperor Arena to obtain technology keys and secretly erase other civilizations'' historical traces"}, "character_name": "角色3", "negative_prompt": null}, {"prompt": "1boy, 40 years old, 175cm tall, balanced sturdy build, warm smiling face, wise brown eyes, black curly hair with a few silver strands, wearing a white linen long robe, gold-embroidered turban on head\n\n风格：diplomat and sage, gentle wise presence, serene composed aura, scholarly warmth\n\n参考风格：\nAmir, Tianzhu Federation diplomat and sage, born into an ancient noble family, deeply versed in historical philosophy, aims to summon federation emperors in the arena to compete for energy quotas while restoring Tianzhu''s altered historical memory and rebuilding civilizational dignity", "line_no": 4, "ext_params": {}, "source_mode": "template", "prompt_blocks": {"part1": "1boy, 40 years old, 175cm tall, balanced sturdy build, warm smiling face, wise brown eyes, black curly hair with a few silver strands, wearing a white linen long robe, gold-embroidered turban on head", "part2": "diplomat and sage, gentle wise presence, serene composed aura, scholarly warmth", "part4": "Amir, Tianzhu Federation diplomat and sage, born into an ancient noble family, deeply versed in historical philosophy, aims to summon federation emperors in the arena to compete for energy quotas while restoring Tianzhu''s altered historical memory and rebuilding civilizational dignity"}, "character_name": "角色4", "negative_prompt": null}], "raw_count": 1, "source_type": "text", "valid_count": 4, "invalid_count": 0}', '{"dedupe": true, "params": {"count": 3}, "style_key": "xuanhuan_live_action", "task_name": "", "capability": "PORTRAIT", "parse_mode": "claude", "folder_name": "batch-output", "submit_mode": "CREATE_BATCH", "idempotency_key": null}', '主角——陆观31岁，地理系学生，身高178cm，身形消瘦，面容清俊，黑色眼睛，黑色短发中夹杂着几缕银白色发丝。常穿着一件略显破旧但干净的深灰色立领外套，穿越后决心帮助大夏重振国威。北境同盟代表——安德烈35岁，北境同盟军事代表，身高190cm，身形魁梧如熊，面容刚毅如石刻，蓝色眼睛深邃冰冷，金色短发整齐利落。常穿着一件深蓝色军装式外套，佩戴着象征战功的金属勋章。他出身北境寒原的军事世家，自幼接受严酷训练，目的是在帝王擂台上以绝对武力碾压对手，为同盟夺取能源配额与土地权限，巩固北境在全球的霸权地位。樱花代表——千岛凛28岁，樱花精英学者兼武士，身高165cm，身形纤细如柳，面容清冷似霜，黑色眼睛锐利如刀，黑色长发束成一丝不苟的高马尾。常穿着一套黑色改良制服，配戴一柄古朴武士刀。她来自学阀高层家族，精通历史与战术，目的是通过帝王擂台召唤樱花历史中的强者，赢得科技密钥以提升学阀实力，并暗中抹除其他文明的历史痕迹。天竺代表——阿米尔40岁，天竺联邦外交官兼智者，身高175cm，身形匀称稳健，面容温和带笑，棕色眼睛充满睿智，黑色卷发间已染几缕银丝。常穿着白色亚麻长袍，头戴绣金头巾。他出身天竺古老贵族，深谙历史哲学，目的是在擂台上召唤联邦帝王，竞争能源配额，同时借此机会修复天竺被篡改的历史记忆，重塑联邦文明尊严。', NULL, 0, 3, NULL, NULL, NULL, '2026-04-27 17:42:48.573734+08', '2026-04-27 17:43:13.907+08', NULL);
