-- ----------------------------
-- Table structure for job_items
-- ----------------------------
DROP TABLE IF EXISTS "public"."job_items";
CREATE TABLE "public"."job_items" (
  "id" int8 NOT NULL DEFAULT nextval('job_items_id_seq'::regclass),
  "batch_job_id" int8 NOT NULL,
  "item_no" text COLLATE "pg_catalog"."default" NOT NULL,
  "line_no" int4 NOT NULL,
  "prompt" text COLLATE "pg_catalog"."default" NOT NULL,
  "negative_prompt" text COLLATE "pg_catalog"."default",
  "model_key" text COLLATE "pg_catalog"."default" NOT NULL,
  "status" "public"."JobItemStatus" NOT NULL DEFAULT 'PENDING'::"JobItemStatus",
  "retry_count" int4 NOT NULL DEFAULT 0,
  "max_retry" int4 NOT NULL DEFAULT 3,
  "next_retry_at" timestamp(3),
  "error_code" text COLLATE "pg_catalog"."default",
  "error_message" text COLLATE "pg_catalog"."default",
  "run_params" jsonb NOT NULL,
  "worker_id" text COLLATE "pg_catalog"."default",
  "started_at" timestamp(3),
  "finished_at" timestamp(3),
  "locked_at" timestamp(3),
  "prompt_blocks" jsonb,
  "character_name" text COLLATE "pg_catalog"."default",
  "source_portrait_id" int8,
  "character_profile" jsonb,
  "style_key" text COLLATE "pg_catalog"."default"
)
;
COMMENT ON COLUMN "public"."job_items"."id" IS '主键ID。';
COMMENT ON COLUMN "public"."job_items"."batch_job_id" IS '所属批任务ID。';
COMMENT ON COLUMN "public"."job_items"."item_no" IS '子任务编号（业务唯一）。';
COMMENT ON COLUMN "public"."job_items"."line_no" IS '来源行号。';
COMMENT ON COLUMN "public"."job_items"."prompt" IS '最终发送给模型的正向提示词。';
COMMENT ON COLUMN "public"."job_items"."negative_prompt" IS '反向提示词。';
COMMENT ON COLUMN "public"."job_items"."model_key" IS '执行模型标识。';
COMMENT ON COLUMN "public"."job_items"."status" IS '子任务状态。';
COMMENT ON COLUMN "public"."job_items"."retry_count" IS '当前重试次数。';
COMMENT ON COLUMN "public"."job_items"."max_retry" IS '最大允许重试次数。';
COMMENT ON COLUMN "public"."job_items"."next_retry_at" IS '下次重试时间。';
COMMENT ON COLUMN "public"."job_items"."error_code" IS '失败错误码。';
COMMENT ON COLUMN "public"."job_items"."error_message" IS '失败错误信息。';
COMMENT ON COLUMN "public"."job_items"."run_params" IS '运行参数快照（JSON）。';
COMMENT ON COLUMN "public"."job_items"."worker_id" IS '处理该任务的 worker 标识。';
COMMENT ON COLUMN "public"."job_items"."started_at" IS '开始处理时间。';
COMMENT ON COLUMN "public"."job_items"."finished_at" IS '完成时间。';
COMMENT ON COLUMN "public"."job_items"."locked_at" IS '任务锁定时间。';
COMMENT ON COLUMN "public"."job_items"."prompt_blocks" IS '结构化提示词块快照（含 source_mode 与 PART1~PART4）。';
COMMENT ON COLUMN "public"."job_items"."character_name" IS '角色名称，用于图片文件按角色命名（可空）。';
COMMENT ON COLUMN "public"."job_items"."source_portrait_id" IS '三视图来源定妆照 image_results.id（仅在所属 batch_jobs.capability=THREE_VIEW 时填充）。';
COMMENT ON COLUMN "public"."job_items"."character_profile" IS '结构化角色档案 JSON：{name, gender, age_band, build, complexion, face, hair, outfit, accessories, extra_visual}。';
COMMENT ON COLUMN "public"."job_items"."style_key" IS '引用服务端 StyleRegistry 的风格预设键。';
COMMENT ON TABLE "public"."job_items" IS '子任务表：记录批任务中每条提示词对应的执行单元。';

-- ----------------------------
-- Records of job_items
-- ----------------------------
