INSERT INTO "public"."job_items" VALUES (131, 30, 'IT20260424180907XTHPW', 2, '请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调"角色资产展示"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。

风格：角色：安德烈，35岁男性，北境斯拉夫系军人气质。身高190cm，身形魁梧厚重如熊，肩宽体壮，肌肉感明显但被军装包裹。面容刚毅如石刻，下颌线硬朗方正，颧骨高耸，面部棱角分明。蓝色眼睛深邃冰冷，目光带有压迫感与审视感。金色短发整齐利落，近似军人板寸但略长，发色明亮。肤色偏白略带粗粝感，面部可有淡淡的伤疤或风霜痕迹。穿着一件深蓝色军装式外套，外套为高领双排扣设计，肩部有肩章结构，衣身剪裁合体，面料厚实带有军事制服质感。胸前左侧佩戴数枚金属勋章，勋章造型精致可辨，象征战功荣誉。腰间系深色军用皮带，下身深蓝色军裤，脚穿黑色高筒军靴。双手自然垂放或一手背于身后，整体姿态挺拔威严。

参考风格：
画风：写实偏影视概念设定风格，光影偏冷硬，色调以深蓝、钢灰、金属色为主，突出角色军人的威压感与北境寒原硬朗气质。注意勋章的金属反光质感与军装面料的厚实纹理。', NULL, 'midj_default', 'SUCCESS', 0, 3, NULL, NULL, NULL, '{"cfg": 7, "size": "1024x1536", "count": 1, "steps": 30}', NULL, '2026-04-24 18:09:07.405', '2026-04-24 18:09:49.703', NULL, '{"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色：安德烈，35岁男性，北境斯拉夫系军人气质。身高190cm，身形魁梧厚重如熊，肩宽体壮，肌肉感明显但被军装包裹。面容刚毅如石刻，下颌线硬朗方正，颧骨高耸，面部棱角分明。蓝色眼睛深邃冰冷，目光带有压迫感与审视感。金色短发整齐利落，近似军人板寸但略长，发色明亮。肤色偏白略带粗粝感，面部可有淡淡的伤疤或风霜痕迹。穿着一件深蓝色军装式外套，外套为高领双排扣设计，肩部有肩章结构，衣身剪裁合体，面料厚实带有军事制服质感。胸前左侧佩戴数枚金属勋章，勋章造型精致可辨，象征战功荣誉。腰间系深色军用皮带，下身深蓝色军裤，脚穿黑色高筒军靴。双手自然垂放或一手背于身后，整体姿态挺拔威严。", "part3": null, "part4": "画风：写实偏影视概念设定风格，光影偏冷硬，色调以深蓝、钢灰、金属色为主，突出角色军人的威压感与北境寒原硬朗气质。注意勋章的金属反光质感与军装面料的厚实纹理。", "source_mode": "template"}', '角色2', NULL, NULL, NULL);
INSERT INTO "public"."job_items" VALUES (130, 30, 'IT20260424180907VCE6M', 1, '请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调"角色资产展示"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。

风格：角色：陆观，31岁男性，中国青年学者气质。身高178cm，身形消瘦修长，面容清俊，五官线条分明但不凌厉，带有书卷气与内敛感。黑色眼睛，目光沉静坚定。黑色短发，发丝间夹杂几缕明显的银白色发丝，形成黑银交错的独特发色细节，发型自然略显凌乱但不邋遢。肤色偏白，面部轮廓清瘦，颧骨微显。穿着一件略显破旧但整洁干净的深灰色立领外套，立领设计挺括，外套面料有轻微磨损与使用痕迹，纽扣与缝线细节可见。内搭深色简洁衬衫或薄内衣。下身深色长裤，鞋履为朴素深色平底鞋。整体造型朴素克制，气质介于现代学生与穿越者之间，透出一种沉稳内敛但暗藏决心的精神面貌。

参考风格：
画风：写实偏影视概念设定风格，光影柔和干净，色调以灰调、冷色为主，突出角色清冷消瘦的气质。注意银白发丝与黑发的对比细节，立领外套的面料磨损质感需真实可辨。', NULL, 'midj_default', 'SUCCESS', 0, 3, NULL, NULL, NULL, '{"cfg": 7, "size": "1024x1536", "count": 1, "steps": 30}', NULL, '2026-04-24 18:09:07.405', '2026-04-24 18:09:51.571', NULL, '{"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色：陆观，31岁男性，中国青年学者气质。身高178cm，身形消瘦修长，面容清俊，五官线条分明但不凌厉，带有书卷气与内敛感。黑色眼睛，目光沉静坚定。黑色短发，发丝间夹杂几缕明显的银白色发丝，形成黑银交错的独特发色细节，发型自然略显凌乱但不邋遢。肤色偏白，面部轮廓清瘦，颧骨微显。穿着一件略显破旧但整洁干净的深灰色立领外套，立领设计挺括，外套面料有轻微磨损与使用痕迹，纽扣与缝线细节可见。内搭深色简洁衬衫或薄内衣。下身深色长裤，鞋履为朴素深色平底鞋。整体造型朴素克制，气质介于现代学生与穿越者之间，透出一种沉稳内敛但暗藏决心的精神面貌。", "part3": null, "part4": "画风：写实偏影视概念设定风格，光影柔和干净，色调以灰调、冷色为主，突出角色清冷消瘦的气质。注意银白发丝与黑发的对比细节，立领外套的面料磨损质感需真实可辨。", "source_mode": "template"}', '角色1', NULL, NULL, NULL);
