INSERT INTO "public"."job_items" VALUES (155, 36, 'IT20260424184349HIACU', 2, '请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调"角色资产展示"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。

风格：角色名：安德烈。35岁北欧/斯拉夫裔白人男性，北境同盟军事代表。身高190cm，身形魁梧厚实如熊，肩宽胸阔，肌肉结实，体量感强。面容刚毅粗犷，颧骨与下颌线条棱角分明如石刻般硬朗，面部皮肤略粗糙。蓝色眼睛深邃冰冷，目光锐利逼人。金色短发整齐利落，偏军人式寸头或板寸长度。穿着一件深蓝色军装式立领外套，肩部有肩章结构，胸前左侧佩戴数枚象征战功的金属勋章，勋章造型精致可辨，外套剪裁硬挺利落，有军事制服的束带与纽扣细节。下装深蓝色军装裤，搭配深色军靴。双手自然垂于两侧或背于身后，姿态威严庄重。表情冷峻肃穆，透出压迫感与统治力。整体气质为强权军事铁血将领型。

参考风格：
画风写实偏电影概念美术风格，色调偏深蓝冷钢色调，突出角色魁梧威压体量与军装制服金属质感。蓝色眼睛与金色短发需色彩鲜明准确，金属勋章需有光泽反射细节。', NULL, 'midj_default', 'FAILED', 3, 3, NULL, 'E_INTERNAL', 'duplicate key value violates unique constraint "image_results_nas_object_key_key"', '{"cfg": 7, "size": "1024x1536", "count": 1, "steps": 30}', NULL, '2026-04-24 18:43:48.599', '2026-04-24 18:56:37.158', NULL, '{"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色名：安德烈。35岁北欧/斯拉夫裔白人男性，北境同盟军事代表。身高190cm，身形魁梧厚实如熊，肩宽胸阔，肌肉结实，体量感强。面容刚毅粗犷，颧骨与下颌线条棱角分明如石刻般硬朗，面部皮肤略粗糙。蓝色眼睛深邃冰冷，目光锐利逼人。金色短发整齐利落，偏军人式寸头或板寸长度。穿着一件深蓝色军装式立领外套，肩部有肩章结构，胸前左侧佩戴数枚象征战功的金属勋章，勋章造型精致可辨，外套剪裁硬挺利落，有军事制服的束带与纽扣细节。下装深蓝色军装裤，搭配深色军靴。双手自然垂于两侧或背于身后，姿态威严庄重。表情冷峻肃穆，透出压迫感与统治力。整体气质为强权军事铁血将领型。", "part3": null, "part4": "画风写实偏电影概念美术风格，色调偏深蓝冷钢色调，突出角色魁梧威压体量与军装制服金属质感。蓝色眼睛与金色短发需色彩鲜明准确，金属勋章需有光泽反射细节。", "source_mode": "template"}', '角色2', NULL, NULL, NULL);
INSERT INTO "public"."job_items" VALUES (158, 37, 'IT20260427113243VYU2J', 1, '请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调"角色资产展示"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。

风格：饱经风霜却气势磅礴的年长男性仙道人物，面容沧桑却威严庄重，深邃双眸中燃烧着稳定的金色灵光，长长的白须垂至腰间，白发苍苍。身着厚重多层长袍，由闪耀的白色丝绸与银线织锦组成，袍面绣有精美的八卦纹样和天云图案，层次丰富华贵。头戴华丽的白玉金冠法冠，庄严端正。手腕佩戴银白色光芒的金刚钻手镯，散发淡淡灵光。右手持一把精美的白色马尾拂尘，拂尘柄由半透明白色玉石雕刻而成，温润通透。整体气质为仙风道骨、威严深沉的高阶仙人形象。

参考风格：
东方仙侠风格，中国古典神话美术设定，高精度角色概念设计图，全身立像，细腻写实与神话感并重，白银色调为主，灵光微漫，庄严肃穆氛围。', NULL, 'midj_default', 'SUCCESS', 0, 3, NULL, NULL, NULL, '{"cfg": 7, "size": "1024x1536", "count": 1, "steps": 30, "negative_prompt": "文字，logo"}', NULL, '2026-04-27 11:32:44.525', '2026-04-27 11:34:04.158', NULL, '{"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "饱经风霜却气势磅礴的年长男性仙道人物，面容沧桑却威严庄重，深邃双眸中燃烧着稳定的金色灵光，长长的白须垂至腰间，白发苍苍。身着厚重多层长袍，由闪耀的白色丝绸与银线织锦组成，袍面绣有精美的八卦纹样和天云图案，层次丰富华贵。头戴华丽的白玉金冠法冠，庄严端正。手腕佩戴银白色光芒的金刚钻手镯，散发淡淡灵光。右手持一把精美的白色马尾拂尘，拂尘柄由半透明白色玉石雕刻而成，温润通透。整体气质为仙风道骨、威严深沉的高阶仙人形象。", "part3": null, "part4": "东方仙侠风格，中国古典神话美术设定，高精度角色概念设计图，全身立像，细腻写实与神话感并重，白银色调为主，灵光微漫，庄严肃穆氛围。", "source_mode": "template"}', '角色1', NULL, NULL, NULL);
INSERT INTO "public"."job_items" VALUES (156, 36, 'IT20260424184349TBZEG', 3, '请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调"角色资产展示"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。

风格：角色名：千岛凛。28岁日本女性，精英学者兼武士。身高165cm，身形纤细如柳，体态轻盈但有力度感，腰身纤细，四肢修长。面容清冷如霜，五官精致锐利，眉形英气，唇色淡雅，面部线条柔中带刚。黑色眼睛锐利如刀，目光冷静而警觉。黑色长发束成一丝不苟的高马尾，发丝顺直光泽，马尾高束利落无碎发。穿着一套黑色改良制服，制服融合了学院风与和风武装元素，立领或小翻领设计，剪裁合身利落，袖口与衣襟有暗纹装饰细节，腰部束带收紧。腰侧配戴一柄古朴武士刀，刀鞘深色木质或漆面质感，刀柄缠绕传统编织带。下装黑色修身长裤或短裙搭配长靴。表情清冷内敛，嘴角微抿，透出隐忍与锋锐。整体气质为冷面女武士学者型，克制而危险。

参考风格：
画风写实偏电影概念美术风格，色调以黑色为主基调，点缀极少暗红或银色细节。突出角色纤细冷冽身姿与武士刀质感。高马尾发型需清晰利落，刀鞘与刀柄细节完整可辨。', NULL, 'midj_default', 'FAILED', 3, 3, NULL, 'E_INTERNAL', 'duplicate key value violates unique constraint "image_results_nas_object_key_key"', '{"cfg": 7, "size": "1024x1536", "count": 1, "steps": 30}', NULL, '2026-04-24 18:43:48.599', '2026-04-24 18:56:26.881', NULL, '{"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色名：千岛凛。28岁日本女性，精英学者兼武士。身高165cm，身形纤细如柳，体态轻盈但有力度感，腰身纤细，四肢修长。面容清冷如霜，五官精致锐利，眉形英气，唇色淡雅，面部线条柔中带刚。黑色眼睛锐利如刀，目光冷静而警觉。黑色长发束成一丝不苟的高马尾，发丝顺直光泽，马尾高束利落无碎发。穿着一套黑色改良制服，制服融合了学院风与和风武装元素，立领或小翻领设计，剪裁合身利落，袖口与衣襟有暗纹装饰细节，腰部束带收紧。腰侧配戴一柄古朴武士刀，刀鞘深色木质或漆面质感，刀柄缠绕传统编织带。下装黑色修身长裤或短裙搭配长靴。表情清冷内敛，嘴角微抿，透出隐忍与锋锐。整体气质为冷面女武士学者型，克制而危险。", "part3": null, "part4": "画风写实偏电影概念美术风格，色调以黑色为主基调，点缀极少暗红或银色细节。突出角色纤细冷冽身姿与武士刀质感。高马尾发型需清晰利落，刀鞘与刀柄细节完整可辨。", "source_mode": "template"}', '角色3', NULL, '{"name": "角色3", "gender": "unknown"}', NULL);
INSERT INTO "public"."job_items" VALUES (134, 31, 'IT20260424181411P-LJ8', 1, '基于人物定妆照生成人物角色设定三视图。

【画面整体】严格16:9横版构图，画面分为左区和右区两部分。

【左区——面部特写】面部占满左区整个区域，五官/发型/配饰清晰可辨，无身体入镜，无遮挡，无变形，面部居中填满。

【右区——标准角色设定三视图】标准角色设定三视图严格横向排列，从左到右依次为：侧视图（左侧面90度）、正视图（正面0度）、背视图（背面180度）。三个视图必须严格呈现侧视、正视和背视三个角度，从头顶到脚底完整呈现全身，无裁切无遮挡。

【核心一致性约束】左区面部特写与右区三视图必须为完全相同的同一角色，五官/服装/配饰/体态/发型/配色100%一致，不允许出现任何差异。

【右区尺寸规范】三视图中每个角色的高度为画面高度的80%，三个视图高度严格统一对齐，角色间距均匀。

【背景与光影】纯净浅灰色背景，无多余元素，无装饰，无文字，无标注；角色无阴影，无地面投影，无环境反光。

【镜头与分辨率】超高清分辨率，统一85mm焦距，无透视畸变，无广角变形，平视角度（镜头与角色视平线齐平）。

【角色姿态与表情】中性表情（无喜怒哀乐），眼神平静直视前方，自然站立姿势，双手自然下垂贴于身体两侧，无任何动作，无转头无倾斜。

风格：【角色描述】陆观，31岁男性，身高178cm，身形消瘦修长。面容清俊，五官线条分明而秀气。黑色眼睛，目光沉静。黑色短发，发间夹杂着几缕醒目的银白色发丝，形成黑白交错的独特发色。穿着一件略显破旧但干净整洁的深灰色立领外套，外套面料有轻微磨损痕迹，立领挺直贴合颈部，内搭素色衣物。下身深色长裤，脚穿简洁深色鞋履。整体气质清瘦内敛，书卷气中带有一丝历经沧桑的沉稳。

参考风格：
写实风格，东亚青年男性面孔，注意黑色短发中银白色发丝的细节刻画，立领外套的旧感质感需体现面料磨损但整洁。', NULL, 'midj_default', 'SUCCESS', 0, 3, NULL, NULL, NULL, '{"size": "1920x1080", "aspect_ratio": "16:9", "negative_prompt": "shadow, ground shadow, drop shadow, cast shadow, reflection, extra limbs, extra fingers, missing fingers, deformed hands, text, watermark, logo, signature, label, annotation, action pose, dynamic pose, tilted head, turned head, smile, frown, angry, sad, surprised, open mouth, teeth showing, lens distortion, wide angle, fisheye, barrel distortion, background objects, props, furniture, decorations, patterns, blurry, low resolution, pixelated, noise, artifacts, body cut off, cropped figure, partial body, missing feet, missing head"}', NULL, '2026-04-24 18:14:11.095', '2026-04-24 18:14:54.627', NULL, '{"part1": "基于人物定妆照生成人物角色设定三视图。\n\n【画面整体】严格16:9横版构图，画面分为左区和右区两部分。\n\n【左区——面部特写】面部占满左区整个区域，五官/发型/配饰清晰可辨，无身体入镜，无遮挡，无变形，面部居中填满。\n\n【右区——标准角色设定三视图】标准角色设定三视图严格横向排列，从左到右依次为：侧视图（左侧面90度）、正视图（正面0度）、背视图（背面180度）。三个视图必须严格呈现侧视、正视和背视三个角度，从头顶到脚底完整呈现全身，无裁切无遮挡。\n\n【核心一致性约束】左区面部特写与右区三视图必须为完全相同的同一角色，五官/服装/配饰/体态/发型/配色100%一致，不允许出现任何差异。\n\n【右区尺寸规范】三视图中每个角色的高度为画面高度的80%，三个视图高度严格统一对齐，角色间距均匀。\n\n【背景与光影】纯净浅灰色背景，无多余元素，无装饰，无文字，无标注；角色无阴影，无地面投影，无环境反光。\n\n【镜头与分辨率】超高清分辨率，统一85mm焦距，无透视畸变，无广角变形，平视角度（镜头与角色视平线齐平）。\n\n【角色姿态与表情】中性表情（无喜怒哀乐），眼神平静直视前方，自然站立姿势，双手自然下垂贴于身体两侧，无任何动作，无转头无倾斜。", "part2": "【角色描述】陆观，31岁男性，身高178cm，身形消瘦修长。面容清俊，五官线条分明而秀气。黑色眼睛，目光沉静。黑色短发，发间夹杂着几缕醒目的银白色发丝，形成黑白交错的独特发色。穿着一件略显破旧但干净整洁的深灰色立领外套，外套面料有轻微磨损痕迹，立领挺直贴合颈部，内搭素色衣物。下身深色长裤，脚穿简洁深色鞋履。整体气质清瘦内敛，书卷气中带有一丝历经沧桑的沉稳。", "part3": null, "part4": "写实风格，东亚青年男性面孔，注意黑色短发中银白色发丝的细节刻画，立领外套的旧感质感需体现面料磨损但整洁。", "source_mode": "template"}', '角色1', NULL, NULL, NULL);
INSERT INTO "public"."job_items" VALUES (54, 13, 'IT20260424033737SFC_V', 3, '请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调"角色资产展示"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。

风格：Damien Grey（达米安·格雷），28岁男性，卢卡斯同父异母的兄长，狼群叛徒，野心勃勃的魅力反派。欧美白人面孔，英俊但带有邪魅之气。深棕色中长发，向后梳理整齐，略带波浪，极为考究。五官英俊迷人，嘴角常带似笑非笑的弧度，眼神狡黠锐利，瞳孔呈琥珀金色（狼人特征），眉形挑高显傲慢。肤色比卢卡斯略暖但仍偏冷白，面部轮廓优雅，下巴尖锐。身材高挑修长，体型偏瘦但充满力量感。穿着更为考究精致的暗色贵族服装——深红色天鹅绒西装外套，黑色丝质衬衫微敞领口露出锁骨，深色修身西裤与尖头黑色皮鞋，手指戴有家族纹章暗银戒指。后期仪式场景会穿仪式长袍，但定妆照以日常造型为主。整体气质如毒蛇般优雅危险，魅力与威胁并存。

人设：欧美暗黑奇幻风格，参考《暮光之城》《吸血鬼日记》《真爱如血》氛围，暗红与黑金色调，写实仿真人质感，电影级灯光。

参考风格：
