INSERT INTO "public"."job_items" VALUES (44, 11, 'IT20260424033734_OBQT', 3, '请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调"角色资产展示"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。

风格：角色名：达米安·格雷（Damien Grey）。28岁男性，卢卡斯同父异母的兄长，狼群中的叛徒，欧美白人面孔，外表英俊迷人但带有危险的邪魅气质。五官深邃精致，眼窝略深，瞳孔为琥珀金色偏暗，眼神中透出算计与野心，嘴角常挂一抹玩味微笑。发色为深金棕色，中长发型，自然后梳露出额头，发梢微卷搭在颈侧，造型精致考究。面部线条比卢卡斯更柔和但更具欺骗性，下巴尖削，唇形饱满。体格修长挺拔，略瘦于卢卡斯但气场强势。身穿深酒红色天鹅绒西装外套，内搭黑色丝质衬衫微敞领口，下穿黑色修身西裤，脚踏酒红色尖头皮鞋。手指佩戴暗金色狼头戒指，胸口别针为银色蛇形胸针。整体造型偏华丽暗黑贵公子风格，魅力反派气质突出，精致中透出阴谋与危险。

人设：欧美暗黑奇幻风格，参考《暮光之城》《吸血鬼日记》《真爱如血》氛围，色调偏暗红与深金，质感写实偏电影级仿真人画风，光影带微弱暖金侧光衬托邪魅感。

参考风格：
仿真人风格，电影级质感，高清细节，暗红金色调为主，暗黑奇幻基调。', NULL, 'midj_default', 'SUCCESS', 0, 3, NULL, NULL, NULL, '{"cfg": 7, "size": "1024x1536", "count": 1, "steps": 30}', NULL, '2026-04-24 03:38:54.203', '2026-04-24 03:40:21.143', NULL, '{"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色名：达米安·格雷（Damien Grey）。28岁男性，卢卡斯同父异母的兄长，狼群中的叛徒，欧美白人面孔，外表英俊迷人但带有危险的邪魅气质。五官深邃精致，眼窝略深，瞳孔为琥珀金色偏暗，眼神中透出算计与野心，嘴角常挂一抹玩味微笑。发色为深金棕色，中长发型，自然后梳露出额头，发梢微卷搭在颈侧，造型精致考究。面部线条比卢卡斯更柔和但更具欺骗性，下巴尖削，唇形饱满。体格修长挺拔，略瘦于卢卡斯但气场强势。身穿深酒红色天鹅绒西装外套，内搭黑色丝质衬衫微敞领口，下穿黑色修身西裤，脚踏酒红色尖头皮鞋。手指佩戴暗金色狼头戒指，胸口别针为银色蛇形胸针。整体造型偏华丽暗黑贵公子风格，魅力反派气质突出，精致中透出阴谋与危险。", "part3": "欧美暗黑奇幻风格，参考《暮光之城》《吸血鬼日记》《真爱如血》氛围，色调偏暗红与深金，质感写实偏电影级仿真人画风，光影带微弱暖金侧光衬托邪魅感。", "part4": "仿真人风格，电影级质感，高清细节，暗红金色调为主，暗黑奇幻基调。", "source_mode": "template"}', NULL, NULL, NULL, NULL);
INSERT INTO "public"."job_items" VALUES (56, 13, 'IT20260424033737AVLEG', 5, '请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调"角色资产展示"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。

风格：Eldritch（艾尔德里奇），布莱克伍德家族老祭司与长老，年龄约70-80岁，欧美白人男性，知晓族群所有秘密的智者角色。满头银白色长发及肩，微卷而苍老，胡须修剪整齐呈灰白色，短须覆盖下巴。面部布满深刻皱纹，颧骨突出，眼窝深陷，但双眼依然锐利有神，瞳孔呈苍灰色带有微弱银蓝光芒。肤色苍白偏黄，面容严肃而慈悲，带有历经沧桑的古老气质。身材偏瘦但挺拔，身高中等，骨架宽大但因年老而消瘦。穿着深色祭司长袍——暗灰色粗麻质地长袍及踝，外层披有深棕色厚重斗篷，腰间系着编织绳带垂挂古旧银质护符与药草袋，手持一根黑木拐杖顶端镶嵌狼牙，脚穿深棕色旧皮靴。手指骨节粗大苍老，指甲略长泛黄。整体气质如古老森林中的守护祭司，神秘、威严、充满古老智慧。

人设：欧美暗黑奇幻风格，参考《暮光之城》《真爱如血》氛围，深灰与暗棕色调，写实仿真人质感，电影级灯光，古老神秘感。

参考风格：
