INSERT INTO "public"."job_items" VALUES (42, 11, 'IT20260424033734L3KJ-', 1, '请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调"角色资产展示"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。

风格：角色名：伊芙琳·卡特（Evelyn Carter）。26岁年轻女性，纽约记者，欧美白人面孔，五官精致立体，眉骨高挑，眼神锐利而倔强，透出理性与坚韧。中长发，深棕色偏栗色发色，自然微卷，发丝质感细腻。面容清秀但带有硬朗线条感，唇色自然偏暗粉，淡妆，不浓艳。体型纤细但不瘦弱，身姿挺拔有力。身穿深色修身皮夹克，内搭深灰色高领针织衫，下穿深蓝色修身牛仔裤，脚踏深棕色短筒靴。颈间佩戴一条精致的银色古旧项链（母亲遗物），手腕处戴简约银色手表。整体造型偏现代都市干练风格，带有记者/调查者的职业气质，兼具暗黑奇幻世界观下的女主气场。瞳孔为深棕色，后期可带淡淡银光变体。

人设：欧美暗黑奇幻风格，参考《暮光之城》《吸血鬼日记》《真爱如血》氛围，色调偏冷调暗蓝与深棕，质感写实偏电影级仿真人画风，光影带微弱月光冷蓝调辅助光。

参考风格：
仿真人风格，电影级质感，高清细节，冷色调为主，暗黑奇幻基调。', NULL, 'midj_default', 'SUCCESS', 0, 3, NULL, NULL, NULL, '{"cfg": 7, "size": "1024x1536", "count": 1, "steps": 30}', NULL, '2026-04-24 03:38:54.203', '2026-04-24 03:40:38.648', NULL, '{"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色名：伊芙琳·卡特（Evelyn Carter）。26岁年轻女性，纽约记者，欧美白人面孔，五官精致立体，眉骨高挑，眼神锐利而倔强，透出理性与坚韧。中长发，深棕色偏栗色发色，自然微卷，发丝质感细腻。面容清秀但带有硬朗线条感，唇色自然偏暗粉，淡妆，不浓艳。体型纤细但不瘦弱，身姿挺拔有力。身穿深色修身皮夹克，内搭深灰色高领针织衫，下穿深蓝色修身牛仔裤，脚踏深棕色短筒靴。颈间佩戴一条精致的银色古旧项链（母亲遗物），手腕处戴简约银色手表。整体造型偏现代都市干练风格，带有记者/调查者的职业气质，兼具暗黑奇幻世界观下的女主气场。瞳孔为深棕色，后期可带淡淡银光变体。", "part3": "欧美暗黑奇幻风格，参考《暮光之城》《吸血鬼日记》《真爱如血》氛围，色调偏冷调暗蓝与深棕，质感写实偏电影级仿真人画风，光影带微弱月光冷蓝调辅助光。", "part4": "仿真人风格，电影级质感，高清细节，冷色调为主，暗黑奇幻基调。", "source_mode": "template"}', NULL, NULL, NULL, NULL);
INSERT INTO "public"."job_items" VALUES (43, 11, 'IT20260424033734PTJXT', 2, '请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调"角色资产展示"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。

风格：角色名：卢卡斯·布莱克伍德（Lucas Blackwood）。30岁男性，布莱克伍德狼人家族继承人、族长之子，欧美白人面孔，面容英俊冷峻，轮廓深邃，颧骨分明，下颌线锐利，眉骨高，浓眉，眼神幽蓝透出非人的冷冽光芒，瞳孔为深幽蓝色。短发偏中长，黑色发色，微微后梳带自然碎发纹理，发质浓密。面部带有淡淡疤痕（左颧骨处一道细长旧伤疤），胡茬极淡，整体气质压抑、危险、隐忍。体格高大健壮，肩宽背厚，肌肉线条明显但不过度夸张。身穿深黑色长款羊毛大衣，内搭深灰色V领毛衣，下穿黑色修身长裤，脚踏黑色皮质长靴。手指修长有力，指甲微尖暗示狼人特质。腰间别有一枚古铜色家族纹章扣饰。整体造型偏哥特贵族与暗黑守护者风格，带有压抑悲情的孤狼气质。

人设：欧美暗黑奇幻风格，参考《暮光之城》《吸血鬼日记》《真爱如血》氛围，色调偏冷黑与深蓝，质感写实偏电影级仿真人画风，光影带微弱冷蓝月光辅助光。

