INSERT INTO "public"."job_items" VALUES (46, 11, 'IT20260424033734LECHO', 5, '请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调"角色资产展示"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。

风格：角色名：老祭司艾尔德里奇（Eldritch）。年约65-70岁老年男性，布莱克伍德狼人家族长老与祭司，欧美白人面孔，面容苍老但威严深沉，满脸岁月刻痕，深陷的眼窝中瞳孔为暗灰绿色，目光深邃睿智，透出洞察一切的古老智慧。银白色长发，及肩长度，向后自然梳理，发质干枯但整齐，鬓角处有编织的细辫。面部留有修剪整齐的银白色短须，颧骨突出，皮肤粗糙如树皮。体型偏瘦高但不佝偻，骨架宽大，站姿挺直带有长者威仪。身穿深墨绿色粗织长袍，外披暗褐色兽皮斗篷，斗篷边缘绣有古老狼族符文图腾。腰间系粗麻绳腰带，挂有兽骨坠饰与干草药束。脚穿深棕色旧皮靴。右手持一根深色木质手杖，杖头雕刻狼首。颈间佩戴多层兽牙与石珠项链。整体造型偏古老部落祭司与森林隐者风格，神秘、沧桑、可信赖的长者形象。

人设：欧美暗黑奇幻风格，参考《暮光之城》《吸血鬼日记》《真爱如血》氛围，色调偏暗绿与深褐，质感写实偏电影级仿真人画风，光影带微弱暖色烛火光辅助，营造古老神秘氛围。

参考风格：
仿真人风格，电影级质感，高清细节，暗绿深褐色调为主，暗黑奇幻基调，古老神秘气质。', NULL, 'midj_default', 'SUCCESS', 0, 3, NULL, NULL, NULL, '{"cfg": 7, "size": "1024x1536", "count": 1, "steps": 30}', NULL, '2026-04-24 03:38:54.203', '2026-04-24 03:41:22.332', NULL, '{"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色名：老祭司艾尔德里奇（Eldritch）。年约65-70岁老年男性，布莱克伍德狼人家族长老与祭司，欧美白人面孔，面容苍老但威严深沉，满脸岁月刻痕，深陷的眼窝中瞳孔为暗灰绿色，目光深邃睿智，透出洞察一切的古老智慧。银白色长发，及肩长度，向后自然梳理，发质干枯但整齐，鬓角处有编织的细辫。面部留有修剪整齐的银白色短须，颧骨突出，皮肤粗糙如树皮。体型偏瘦高但不佝偻，骨架宽大，站姿挺直带有长者威仪。身穿深墨绿色粗织长袍，外披暗褐色兽皮斗篷，斗篷边缘绣有古老狼族符文图腾。腰间系粗麻绳腰带，挂有兽骨坠饰与干草药束。脚穿深棕色旧皮靴。右手持一根深色木质手杖，杖头雕刻狼首。颈间佩戴多层兽牙与石珠项链。整体造型偏古老部落祭司与森林隐者风格，神秘、沧桑、可信赖的长者形象。", "part3": "欧美暗黑奇幻风格，参考《暮光之城》《吸血鬼日记》《真爱如血》氛围，色调偏暗绿与深褐，质感写实偏电影级仿真人画风，光影带微弱暖色烛火光辅助，营造古老神秘氛围。", "part4": "仿真人风格，电影级质感，高清细节，暗绿深褐色调为主，暗黑奇幻基调，古老神秘气质。", "source_mode": "template"}', NULL, NULL, NULL, NULL);
INSERT INTO "public"."job_items" VALUES (45, 11, 'IT20260424033734C_END', 4, '请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调"角色资产展示"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。

风格：角色名：塞琳娜·卡特（Selena Carter）。约26岁女性（1998年生），伊芙琳的姐姐，卢卡斯的已故未婚妻，银血家族后裔，欧美白人面孔。与伊芙琳长相极为相似但气质更柔和温婉，五官精致秀美，眼神温柔带有淡淡忧郁，瞳孔为浅棕偏蜜色。长发，深棕色偏栗色发色，长至肩下，自然大卷波浪，发丝柔顺飘逸。面容比伊芙琳更圆润柔和，唇色偏玫瑰粉，肤色白皙。体型纤细柔美，气质温和优雅。身穿米白色雪纺长裙，裙摆及脚踝，腰间束有细银腰带，外搭浅灰色针织披肩。脚穿浅棕色平底绑带凉鞋。颈间佩戴与伊芙琳同款的银色古旧项链（姐妹信物）。整体造型偏温柔古典风格，带有一丝悲剧命运感与银血家族的高洁气质，如同月光下的幽灵般清丽。

人设：欧美暗黑奇幻风格，参考《暮光之城》《吸血鬼日记》《真爱如血》氛围，色调偏冷白与淡银蓝，质感写实偏电影级仿真人画风，光影带柔和月光散射质感，营造悲美氛围。

参考风格：
仿真人风格，电影级质感，高清细节，冷白银蓝色调为主，暗黑奇幻基调，悲美气质。', NULL, 'midj_default', 'SUCCESS', 0, 3, NULL, NULL, NULL, '{"cfg": 7, "size": "1024x1536", "count": 1, "steps": 30}', NULL, '2026-04-24 03:38:54.203', '2026-04-24 03:41:38.877', NULL, '{"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色名：塞琳娜·卡特（Selena Carter）。约26岁女性（1998年生），伊芙琳的姐姐，卢卡斯的已故未婚妻，银血家族后裔，欧美白人面孔。与伊芙琳长相极为相似但气质更柔和温婉，五官精致秀美，眼神温柔带有淡淡忧郁，瞳孔为浅棕偏蜜色。长发，深棕色偏栗色发色，长至肩下，自然大卷波浪，发丝柔顺飘逸。面容比伊芙琳更圆润柔和，唇色偏玫瑰粉，肤色白皙。体型纤细柔美，气质温和优雅。身穿米白色雪纺长裙，裙摆及脚踝，腰间束有细银腰带，外搭浅灰色针织披肩。脚穿浅棕色平底绑带凉鞋。颈间佩戴与伊芙琳同款的银色古旧项链（姐妹信物）。整体造型偏温柔古典风格，带有一丝悲剧命运感与银血家族的高洁气质，如同月光下的幽灵般清丽。", "part3": "欧美暗黑奇幻风格，参考《暮光之城》《吸血鬼日记》《真爱如血》氛围，色调偏冷白与淡银蓝，质感写实偏电影级仿真人画风，光影带柔和月光散射质感，营造悲美氛围。", "part4": "仿真人风格，电影级质感，高清细节，冷白银蓝色调为主，暗黑奇幻基调，悲美气质。", "source_mode": "template"}', NULL, NULL, NULL, NULL);
INSERT INTO "public"."job_items" VALUES (128, 29, 'IT20260424081347FOFNI', 3, '基于人物定妆照生成人物角色设定三视图。

【画面整体】严格16:9横版构图，画面分为左区和右区两部分。

【左区——面部特写】面部占满左区整个区域，五官/发型/配饰清晰可辨，无身体入镜，无遮挡，无变形，面部居中填满。

【右区——标准角色设定三视图】标准角色设定三视图严格横向排列，从左到右依次为：侧视图（左侧面90度）、正视图（正面0度）、背视图（背面180度）。三个视图必须严格呈现侧视、正视和背视三个角度，从头顶到脚底完整呈现全身，无裁切无遮挡。

【核心一致性约束】左区面部特写与右区三视图必须为完全相同的同一角色，五官/服装/配饰/体态/发型/配色100%一致，不允许出现任何差异。

【右区尺寸规范】三视图中每个角色的高度为画面高度的80%，三个视图高度严格统一对齐，角色间距均匀。

【背景与光影】纯净浅灰色背景，无多余元素，无装饰，无文字，无标注；角色无阴影，无地面投影，无环境反光。

【镜头与分辨率】超高清分辨率，统一85mm焦距，无透视畸变，无广角变形，平视角度（镜头与角色视平线齐平）。

【角色姿态与表情】中性表情（无喜怒哀乐），眼神平静直视前方，自然站立姿势，双手自然下垂贴于身体两侧，无任何动作，无转头无倾斜。

风格：一位28岁日本女性，樱花精英学者兼武士，身高165cm，身形纤细如柳，面容清冷似霜，黑色眼睛锐利如刀，黑色长发束成一丝不苟的高马尾。穿着一套黑色改良制服，立领收腰剪裁利落，腰间配戴一柄古朴武士刀，深色长裤，黑色短靴。整体气质冷厉肃杀，兼具学者的沉静与武士的杀意。

参考风格：
千岛凛，28岁，樱花代表，纤细清冷，黑色高马尾，黑色改良制服，腰佩古朴武士刀', NULL, 'Nano Banana Pro', 'SUCCESS', 1, 3, '2026-04-24 16:16:28.827', NULL, NULL, '{"size": "1920x1080", "aspect_ratio": "16:9", "negative_prompt": "shadow, ground shadow, drop shadow, cast shadow, reflection, extra limbs, extra fingers, missing fingers, deformed hands, text, watermark, logo, signature, label, annotation, action pose, dynamic pose, tilted head, turned head, smile, frown, angry, sad, surprised, open mouth, teeth showing, lens distortion, wide angle, fisheye, barrel distortion, background objects, props, furniture, decorations, patterns, blurry, low resolution, pixelated, noise, artifacts, body cut off, cropped figure, partial body, missing feet, missing head"}', NULL, '2026-04-24 08:13:50.068', '2026-04-24 16:23:04.467', NULL, '{"part1": "基于人物定妆照生成人物角色设定三视图。\n\n【画面整体】严格16:9横版构图，画面分为左区和右区两部分。\n\n【左区——面部特写】面部占满左区整个区域，五官/发型/配饰清晰可辨，无身体入镜，无遮挡，无变形，面部居中填满。\n\n【右区——标准角色设定三视图】标准角色设定三视图严格横向排列，从左到右依次为：侧视图（左侧面90度）、正视图（正面0度）、背视图（背面180度）。三个视图必须严格呈现侧视、正视和背视三个角度，从头顶到脚底完整呈现全身，无裁切无遮挡。\n\n【核心一致性约束】左区面部特写与右区三视图必须为完全相同的同一角色，五官/服装/配饰/体态/发型/配色100%一致，不允许出现任何差异。\n\n【右区尺寸规范】三视图中每个角色的高度为画面高度的80%，三个视图高度严格统一对齐，角色间距均匀。\n\n【背景与光影】纯净浅灰色背景，无多余元素，无装饰，无文字，无标注；角色无阴影，无地面投影，无环境反光。\n\n【镜头与分辨率】超高清分辨率，统一85mm焦距，无透视畸变，无广角变形，平视角度（镜头与角色视平线齐平）。\n\n【角色姿态与表情】中性表情（无喜怒哀乐），眼神平静直视前方，自然站立姿势，双手自然下垂贴于身体两侧，无任何动作，无转头无倾斜。", "part2": "一位28岁日本女性，樱花精英学者兼武士，身高165cm，身形纤细如柳，面容清冷似霜，黑色眼睛锐利如刀，黑色长发束成一丝不苟的高马尾。穿着一套黑色改良制服，立领收腰剪裁利落，腰间配戴一柄古朴武士刀，深色长裤，黑色短靴。整体气质冷厉肃杀，兼具学者的沉静与武士的杀意。", "part3": null, "part4": "千岛凛，28岁，樱花代表，纤细清冷，黑色高马尾，黑色改良制服，腰佩古朴武士刀", "source_mode": "template"}', NULL, NULL, NULL, NULL);
INSERT INTO "public"."job_items" VALUES (159, 38, 'IT20260427114712-VUOO', 1, '请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调"角色资产展示"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。

风格：角色为一位忧郁的年轻男性工程师，约二十五六岁，面容消瘦，眼神深邃带有宿命般的疲惫与克制的哀愁，肤色偏苍白，面部与指缝间残留有细微的机油痕迹与碳粉感。发型为略显凌乱的中短发，自然落于额前，发色深棕偏灰。额头上方推起一副饱经风霜的黄铜防风护目镜，镜片为深琥珀色玻璃，铜框有磨损氧化痕迹与铆钉加固细节。上身穿做旧深焦茶色皮革背心，皮面有使用磨白与油渍渗透的真实质感，背心扣件为小型黄铜齿轮扣，内搭粗纺亚麻衬衫，袖口卷起。下身为厚帆布工装裤，膝部有磨损与缝补痕迹，裤脚束入厚底做旧皮革工靴。腰间系宽皮工具带，挂有微型扳手、油壶、气压表盘等功能性配件，铆钉与铜扣加固。最核心特征：右臂为一条精密蒸汽朋克机械义肢，从肩部以下完全替换。义肢外壳由红铜板与抛光钢片拼接组成，关节处清晰可见联动齿轮组、微型液压杆、细铜管路线，所有齿轮咬合关系合理可信，看起来能实际转动。义肢手腕处装有一个小型黄铜排气阀门，有微量蒸汽逸出的视觉暗示。义肢表面布满油腻光泽与使用划痕，个别铜管表面有绿色铜锈氧化层。左手为正常人类手掌，指节粗糙，指甲缝有油垢。整体造型强调功能性与劳动者身份，非装饰性堆砌。

参考风格：
蒸汽朋克美学风格（Steampunk），真人影视质感，电影级角色肖像品质。色彩体系以焦茶色、古铜金、铁锈红、烟灰为主调，金属部件呈温暖的琥珀橙反光。光影设计：主光为偏暖的琥珀金色侧光，模拟工业煤气灯光源穿透极淡蒸汽烟雾的丁达尔效应；辅以侧逆光勾勒机械义肢与皮革边缘的清晰轮廓光，凸显金属高光与皮革纹理；阴影区域深沉但保留细节，避免死黑。背景为深灰至焦茶色的干净渐变，可带极弱的暖色工业环境光晕，不添加具体场景元素。材质渲染要求：做旧皮革的磨白油润感、帆布的粗粝纤维质感、黄铜的温润氧化色泽、钢片的冷硬抛光反射、齿轮与铜管的精密机械真实感——所有材质必须可信真实，杜绝塑料感的亮金色。整体氛围庄严肃穆，带有宿命论的沉郁调性。8K分辨率，照片级写实渲染，等效35mm镜头视角，浅景深微虚化仅限背景边缘，人物全身锐利清晰。画面比例3:4竖幅。无文字，无logo，无水印。', NULL, 'midj_default', 'SUCCESS', 0, 3, NULL, NULL, NULL, '{"cfg": 7, "size": "1024x1536", "count": 1, "steps": 30}', NULL, '2026-04-27 11:47:12.913', '2026-04-27 11:48:26.631', NULL, '{"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色为一位忧郁的年轻男性工程师，约二十五六岁，面容消瘦，眼神深邃带有宿命般的疲惫与克制的哀愁，肤色偏苍白，面部与指缝间残留有细微的机油痕迹与碳粉感。发型为略显凌乱的中短发，自然落于额前，发色深棕偏灰。额头上方推起一副饱经风霜的黄铜防风护目镜，镜片为深琥珀色玻璃，铜框有磨损氧化痕迹与铆钉加固细节。上身穿做旧深焦茶色皮革背心，皮面有使用磨白与油渍渗透的真实质感，背心扣件为小型黄铜齿轮扣，内搭粗纺亚麻衬衫，袖口卷起。下身为厚帆布工装裤，膝部有磨损与缝补痕迹，裤脚束入厚底做旧皮革工靴。腰间系宽皮工具带，挂有微型扳手、油壶、气压表盘等功能性配件，铆钉与铜扣加固。最核心特征：右臂为一条精密蒸汽朋克机械义肢，从肩部以下完全替换。义肢外壳由红铜板与抛光钢片拼接组成，关节处清晰可见联动齿轮组、微型液压杆、细铜管路线，所有齿轮咬合关系合理可信，看起来能实际转动。义肢手腕处装有一个小型黄铜排气阀门，有微量蒸汽逸出的视觉暗示。义肢表面布满油腻光泽与使用划痕，个别铜管表面有绿色铜锈氧化层。左手为正常人类手掌，指节粗糙，指甲缝有油垢。整体造型强调功能性与劳动者身份，非装饰性堆砌。", "part3": null, "part4": "蒸汽朋克美学风格（Steampunk），真人影视质感，电影级角色肖像品质。色彩体系以焦茶色、古铜金、铁锈红、烟灰为主调，金属部件呈温暖的琥珀橙反光。光影设计：主光为偏暖的琥珀金色侧光，模拟工业煤气灯光源穿透极淡蒸汽烟雾的丁达尔效应；辅以侧逆光勾勒机械义肢与皮革边缘的清晰轮廓光，凸显金属高光与皮革纹理；阴影区域深沉但保留细节，避免死黑。背景为深灰至焦茶色的干净渐变，可带极弱的暖色工业环境光晕，不添加具体场景元素。材质渲染要求：做旧皮革的磨白油润感、帆布的粗粝纤维质感、黄铜的温润氧化色泽、钢片的冷硬抛光反射、齿轮与铜管的精密机械真实感——所有材质必须可信真实，杜绝塑料感的亮金色。整体氛围庄严肃穆，带有宿命论的沉郁调性。8K分辨率，照片级写实渲染，等效35mm镜头视角，浅景深微虚化仅限背景边缘，人物全身锐利清晰。画面比例3:4竖幅。无文字，无logo，无水印。", "source_mode": "template"}', '角色1', NULL, NULL, NULL);
