INSERT INTO "public"."job_items" VALUES (140, 32, 'IT202604241814190XLGK', 3, '基于人物定妆照生成人物角色设定三视图。

【画面整体】严格16:9横版构图，画面分为左区和右区两部分。

【左区——面部特写】面部占满左区整个区域，五官/发型/配饰清晰可辨，无身体入镜，无遮挡，无变形，面部居中填满。

【右区——标准角色设定三视图】标准角色设定三视图严格横向排列，从左到右依次为：侧视图（左侧面90度）、正视图（正面0度）、背视图（背面180度）。三个视图必须严格呈现侧视、正视和背视三个角度，从头顶到脚底完整呈现全身，无裁切无遮挡。

【核心一致性约束】左区面部特写与右区三视图必须为完全相同的同一角色，五官/服装/配饰/体态/发型/配色100%一致，不允许出现任何差异。

【右区尺寸规范】三视图中每个角色的高度为画面高度的80%，三个视图高度严格统一对齐，角色间距均匀。

【背景与光影】纯净浅灰色背景，无多余元素，无装饰，无文字，无标注；角色无阴影，无地面投影，无环境反光。

【镜头与分辨率】超高清分辨率，统一85mm焦距，无透视畸变，无广角变形，平视角度（镜头与角色视平线齐平）。

【角色姿态与表情】中性表情（无喜怒哀乐），眼神平静直视前方，自然站立姿势，双手自然下垂贴于身体两侧，无任何动作，无转头无倾斜。

风格：【角色描述】千岛凛，28岁女性，身高165cm，身形纤细修长如柳枝，体态轻盈。面容清冷如霜，五官精致冷峻，薄唇紧抿，表情疏离。黑色眼睛锐利如刀锋，目光冰冷犀利。黑色长发束成一丝不苟的高马尾，发丝顺滑笔直，无碎发。穿着一套黑色改良制服，制服剪裁合身利落，融合东方传统与现代军事风格，衣领整齐，袖口收紧。腰间左侧佩戴一柄古朴武士刀，刀鞘为深色木质，刀柄缠绕传统织布。下身黑色修身长裤，脚穿黑色短靴。整体气质冷厉肃杀，如出鞘利刃。

参考风格：
写实风格，东亚年轻女性面孔，注意高马尾发型的整洁束感与黑色长发的垂顺质感，黑色改良制服需体现面料挺括与东方元素融合，腰间武士刀的古朴木鞘与缠绕刀柄需清晰可辨。', NULL, 'midj_default', 'FAILED', 3, 3, NULL, 'E_INTERNAL', 'duplicate key value violates unique constraint "image_results_nas_object_key_key"', '{"size": "1920x1080", "aspect_ratio": "16:9", "negative_prompt": "shadow, ground shadow, drop shadow, cast shadow, reflection, extra limbs, extra fingers, missing fingers, deformed hands, text, watermark, logo, signature, label, annotation, action pose, dynamic pose, tilted head, turned head, smile, frown, angry, sad, surprised, open mouth, teeth showing, lens distortion, wide angle, fisheye, barrel distortion, background objects, props, furniture, decorations, patterns, blurry, low resolution, pixelated, noise, artifacts, body cut off, cropped figure, partial body, missing feet, missing head"}', NULL, '2026-04-24 18:14:57.752', '2026-04-24 18:56:24.212', NULL, '{"part1": "基于人物定妆照生成人物角色设定三视图。\n\n【画面整体】严格16:9横版构图，画面分为左区和右区两部分。\n\n【左区——面部特写】面部占满左区整个区域，五官/发型/配饰清晰可辨，无身体入镜，无遮挡，无变形，面部居中填满。\n\n【右区——标准角色设定三视图】标准角色设定三视图严格横向排列，从左到右依次为：侧视图（左侧面90度）、正视图（正面0度）、背视图（背面180度）。三个视图必须严格呈现侧视、正视和背视三个角度，从头顶到脚底完整呈现全身，无裁切无遮挡。\n\n【核心一致性约束】左区面部特写与右区三视图必须为完全相同的同一角色，五官/服装/配饰/体态/发型/配色100%一致，不允许出现任何差异。\n\n【右区尺寸规范】三视图中每个角色的高度为画面高度的80%，三个视图高度严格统一对齐，角色间距均匀。\n\n【背景与光影】纯净浅灰色背景，无多余元素，无装饰，无文字，无标注；角色无阴影，无地面投影，无环境反光。\n\n【镜头与分辨率】超高清分辨率，统一85mm焦距，无透视畸变，无广角变形，平视角度（镜头与角色视平线齐平）。\n\n【角色姿态与表情】中性表情（无喜怒哀乐），眼神平静直视前方，自然站立姿势，双手自然下垂贴于身体两侧，无任何动作，无转头无倾斜。", "part2": "【角色描述】千岛凛，28岁女性，身高165cm，身形纤细修长如柳枝，体态轻盈。面容清冷如霜，五官精致冷峻，薄唇紧抿，表情疏离。黑色眼睛锐利如刀锋，目光冰冷犀利。黑色长发束成一丝不苟的高马尾，发丝顺滑笔直，无碎发。穿着一套黑色改良制服，制服剪裁合身利落，融合东方传统与现代军事风格，衣领整齐，袖口收紧。腰间左侧佩戴一柄古朴武士刀，刀鞘为深色木质，刀柄缠绕传统织布。下身黑色修身长裤，脚穿黑色短靴。整体气质冷厉肃杀，如出鞘利刃。", "part3": null, "part4": "写实风格，东亚年轻女性面孔，注意高马尾发型的整洁束感与黑色长发的垂顺质感，黑色改良制服需体现面料挺括与东方元素融合，腰间武士刀的古朴木鞘与缠绕刀柄需清晰可辨。", "source_mode": "template"}', '角色3', NULL, '{"name": "角色3", "gender": "unknown"}', NULL);
INSERT INTO "public"."job_items" VALUES (92, 21, 'IT20260424043931YZJTX', 1, '基于人物定妆照生成人物三视图
（16：9）面部占满左区，五官 / 发型 / 配饰清晰，无身体入镜、无遮挡变形；右区：标准角色设定三视图，横向排列（侧视图、正视图、背视图），三个视图严格呈现侧视、正视和背视，从头到脚完整无遮挡；核心约束：特写与三视图为同一角色，五官 / 服装 / 配饰 / 体态 100% 一致；右区尺寸：三视图角色高度画面高度的 80%，三视图高度统一；无多余元素的浅灰色背景，角色无阴影；超高清分辨率，统一85mm焦距，无畸变，角色无动作，平视；中性表情（无喜怒哀乐），眼神平静，自然站立，双手自然下垂。

风格：角色：伊芙琳·卡特（Evelyn Carter），26岁白人女性，纽约记者。中等身高，身材匀称，面容精致且坚毅，深棕色长发微卷垂至肩下，浅灰绿色眼眸透出理性与倔强。穿着深灰色修身风衣，内搭黑色高领毛衣，深色牛仔裤，棕色短靴，斜挎旧棕色皮质记者包，颈间佩戴银色古董项链（母亲遗物）。整体气质干练、现代都市感，目光坚定。

人设：基于人物定妆照生成人物三视图
（16：9）面部占满左区，五官 / 发型 / 配饰清晰，无身体入镜、无遮挡变形；右区：标准角色设定三视图，横向排列（侧视图、正视图、背视图），三个视图严格呈现侧视、正视和背视，从头到脚完整无遮挡；核心约束：特写与三视图为同一角色，五官 / 服装 / 配饰 / 体态 100% 一致；右区尺寸：三视图角色高度画面高度的 80%，三视图高度统一；无多余元素的浅灰色背景，角色无阴影；超高清分辨率，统一85mm焦距，无畸变，角色无动作，平视；中性表情（无喜怒哀乐），眼神平静，自然站立，双手自然下垂。

风格：角色：伊芙琳·卡特（Evelyn Carter），26岁白人女性，纽约记者。中等身高，身材匀称，面容精致且坚毅，深棕色长发微卷垂至肩下，浅灰绿色眼眸透出理性与倔强。穿着深灰色修身风衣，内搭黑色高领毛衣，深色牛仔裤，棕色短靴，斜挎旧棕色皮质记者包，颈间佩戴银色古董项链（母亲遗物）。整体气质干练、现代都市感，目光坚定。

参考风格：
