INSERT INTO "public"."job_items" VALUES (161, 40, 'IT20260427115621KPTRY', 1, '请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调"角色资产展示"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。

风格：角色：忧郁的年轻男性工程师／机械师，约25–30岁。面容清瘦、轮廓分明，眉目间透出宿命般的忧郁与倦意，眼神深邃疲惫却仍坚定有神；肤色偏白但不洁净，颧骨与下颌线处可见淡淡的油污与烟尘痕迹。短发微乱，发丝偏深棕，额角与鬓角沾有汗渍与细微油渍。额头上推着一副黄铜防风护目镜——实用型工具而非装饰，铜框有磨损氧化，镜片边缘带划痕，皮质绑带做旧。上身穿深焦茶色做旧皮背心，表面有刮擦磨白与油渍包浆，铆钉固定肩缝，内搭粗纺灰棕衬衫，袖口卷至前臂。下身穿厚帆布工装裤，膝部有磨损补丁，裤脚微微塞入靴筒。腰间宽皮带上挂有小型黄铜扳手、铜质油壶、一枚气压表盘等工具配件。右臂为饱经风霜的全机械义肢，以黄铜与红铜为主材质，表面遍布划痕、氧化斑与油渍包浆，肩部接口处可见铆钉与皮革绑带固定结构；前臂外壳局部敞开，清晰暴露内部精密联动齿轮组、细铜管、微型液压杆——所有齿轮啮合合理，看起来可以运转；手腕处设有黄铜蒸汽排放阀门，微量白色蒸汽从阀缝溢出。机械手指关节分明，指尖有磨损。左手为肉手，指尖与指缝积有长期劳作的油垢，指甲缝发黑。脚穿厚底深棕色皮革工靴，鞋头有铆钉加固，鞋面有磨损使用痕迹。整体造型强调功能性、劳动磨损的真实感与硬核工业气质。

参考风格：
蒸汽朋克硬核工业美学，真人影视质感，电影级角色肖像品质。色彩体系以焦茶色、古铜金、铁锈红、烟灰色为核心基调，能量色为琥珀橙（热蒸汽光）。材质重点呈现做旧皮革的纤维纹理与包浆光泽、厚帆布的粗糙编织感、粗纺呢绒的颗粒质地、黄铜红铜金属的氧化磨损与油渍反光——杜绝塑料感亮金色，所有金属必须带有使用痕迹与工业真实感。齿轮与机械结构严格遵循物理逻辑，啮合正确可运转，禁止无意义堆砌。光影设计：主光为温暖琥珀金色调侧光，模拟丁达尔效应穿透极微弱的工业烟雾；侧逆光精确勾勒机械义肢的金属边缘高光与齿轮轮廓；阴影柔和有层次，暗部仍可辨识服装与机械结构细节。整体气质庄严肃穆、宿命论调性，参考维多利亚工业时代与东方机关术碰撞的世界观美学。渲染标准：8K分辨率，照片级写实，35mm电影定焦镜头质感，浅景深微虚化背景。背景为深灰至烟灰色干净渐变，可带极弱暖色环境光暗示工坊氛围，不添加具体场景道具。无文字，无logo。--ar 3:4', NULL, 'midj_default', 'SUCCESS', 0, 3, NULL, NULL, NULL, '{"cfg": 7, "size": "1024x1536", "count": 1, "steps": 30}', NULL, '2026-04-27 11:56:21.497', '2026-04-27 11:58:57.316', NULL, '{"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色：忧郁的年轻男性工程师／机械师，约25–30岁。面容清瘦、轮廓分明，眉目间透出宿命般的忧郁与倦意，眼神深邃疲惫却仍坚定有神；肤色偏白但不洁净，颧骨与下颌线处可见淡淡的油污与烟尘痕迹。短发微乱，发丝偏深棕，额角与鬓角沾有汗渍与细微油渍。额头上推着一副黄铜防风护目镜——实用型工具而非装饰，铜框有磨损氧化，镜片边缘带划痕，皮质绑带做旧。上身穿深焦茶色做旧皮背心，表面有刮擦磨白与油渍包浆，铆钉固定肩缝，内搭粗纺灰棕衬衫，袖口卷至前臂。下身穿厚帆布工装裤，膝部有磨损补丁，裤脚微微塞入靴筒。腰间宽皮带上挂有小型黄铜扳手、铜质油壶、一枚气压表盘等工具配件。右臂为饱经风霜的全机械义肢，以黄铜与红铜为主材质，表面遍布划痕、氧化斑与油渍包浆，肩部接口处可见铆钉与皮革绑带固定结构；前臂外壳局部敞开，清晰暴露内部精密联动齿轮组、细铜管、微型液压杆——所有齿轮啮合合理，看起来可以运转；手腕处设有黄铜蒸汽排放阀门，微量白色蒸汽从阀缝溢出。机械手指关节分明，指尖有磨损。左手为肉手，指尖与指缝积有长期劳作的油垢，指甲缝发黑。脚穿厚底深棕色皮革工靴，鞋头有铆钉加固，鞋面有磨损使用痕迹。整体造型强调功能性、劳动磨损的真实感与硬核工业气质。", "part3": null, "part4": "蒸汽朋克硬核工业美学，真人影视质感，电影级角色肖像品质。色彩体系以焦茶色、古铜金、铁锈红、烟灰色为核心基调，能量色为琥珀橙（热蒸汽光）。材质重点呈现做旧皮革的纤维纹理与包浆光泽、厚帆布的粗糙编织感、粗纺呢绒的颗粒质地、黄铜红铜金属的氧化磨损与油渍反光——杜绝塑料感亮金色，所有金属必须带有使用痕迹与工业真实感。齿轮与机械结构严格遵循物理逻辑，啮合正确可运转，禁止无意义堆砌。光影设计：主光为温暖琥珀金色调侧光，模拟丁达尔效应穿透极微弱的工业烟雾；侧逆光精确勾勒机械义肢的金属边缘高光与齿轮轮廓；阴影柔和有层次，暗部仍可辨识服装与机械结构细节。整体气质庄严肃穆、宿命论调性，参考维多利亚工业时代与东方机关术碰撞的世界观美学。渲染标准：8K分辨率，照片级写实，35mm电影定焦镜头质感，浅景深微虚化背景。背景为深灰至烟灰色干净渐变，可带极弱暖色环境光暗示工坊氛围，不添加具体场景道具。无文字，无logo。--ar 3:4", "source_mode": "template"}', '角色1', NULL, NULL, NULL);
