INSERT INTO "public"."job_items" VALUES (49, 12, 'IT20260424033737YU-VK', 3, '请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调"角色资产展示"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。

风格：达米安·格雷（Damien Grey），28岁男性，卢卡斯同父异母的兄长，白人，野心勃勃的魅力反派。深棕偏红色头发，向后梳理的利落发型，鬓角修饰整齐，发丝带有微微光泽。面容英俊但带有危险的锐利感，高挺鼻梁，薄唇常带似笑非笑的弧度，琥珀色瞳孔带有狡黠与野心的光芒，眼神自信且带有攻击性。肤色比卢卡斯略暖，下颌轮廓锋利。身材修长挺拔，约183cm，体型精瘦有力。穿着暗黑时尚贵族风——深红色丝绒西装外套，内搭黑色衬衫微敞领口，黑色修身西裤，尖头黑色皮鞋。手上戴一枚古老的家族银戒。整体造型介于优雅与邪恶之间，危险的魅力型反派形象。

人设：欧美暗黑奇幻风格，仿真人AI短剧角色，参考《暮光之城》《吸血鬼日记》《真爱如血》氛围，电影级质感，高清细腻', NULL, 'midj_default', 'SUCCESS', 1, 3, '2026-04-24 11:41:32.466', NULL, NULL, '{"cfg": 7, "size": "1024x1536", "count": 1, "steps": 30}', NULL, '2026-04-24 03:38:54.203', '2026-04-24 16:22:09.332', NULL, '{"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "达米安·格雷（Damien Grey），28岁男性，卢卡斯同父异母的兄长，白人，野心勃勃的魅力反派。深棕偏红色头发，向后梳理的利落发型，鬓角修饰整齐，发丝带有微微光泽。面容英俊但带有危险的锐利感，高挺鼻梁，薄唇常带似笑非笑的弧度，琥珀色瞳孔带有狡黠与野心的光芒，眼神自信且带有攻击性。肤色比卢卡斯略暖，下颌轮廓锋利。身材修长挺拔，约183cm，体型精瘦有力。穿着暗黑时尚贵族风——深红色丝绒西装外套，内搭黑色衬衫微敞领口，黑色修身西裤，尖头黑色皮鞋。手上戴一枚古老的家族银戒。整体造型介于优雅与邪恶之间，危险的魅力型反派形象。", "part3": "欧美暗黑奇幻风格，仿真人AI短剧角色，参考《暮光之城》《吸血鬼日记》《真爱如血》氛围，电影级质感，高清细腻", "part4": null, "source_mode": "template"}', NULL, NULL, NULL, NULL);
INSERT INTO "public"."job_items" VALUES (109, 24, 'IT20260424051950I7P6I', 4, '请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调"角色资产展示"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。

风格：角色名：阿米尔。40岁南亚/印度裔男性，身高175cm，身形匀称稳健，体态端正从容，既不魁梧也不纤细，带有成熟儒雅的稳重感。面容温和，眉目舒展，常带淡淡笑意，面部轮廓柔和但不失骨感，鼻梁挺直。棕色眼睛温润深沉，充满睿智洞察之感。黑色卷发中长，自然卷曲蓬松，发间已染有几缕银丝，银黑交织显出智者气质。肤色为温暖的小麦棕色。头戴一顶绣金头巾，头巾为浅金色或米白色织物，边缘与正面饰有精致金线刺绣纹样，包裹方式为传统南亚贵族式缠法，露出额头上方部分卷发。身穿白色亚麻长袍，面料为天然亚麻质感，略有纹理但整洁，长袍至脚踝，领口与袖口有细密金线暗纹装饰，腰间以一条绣金织带束腰。足蹬浅棕色皮质凉鞋或软底鞋。手部可佩戴一枚古朴金属指环。整体造型温和尊贵，兼具外交官的儒雅与古老贵族的沉稳底蕴。

