INSERT INTO "public"."job_items" VALUES (60, 14, 'IT20260424033738U3LQD', 4, '请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调"角色资产展示"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。

风格：Selena Carter（塞琳娜·卡特），伊芙琳的姐姐，真相的关键人物，已故角色但需要在回忆与幻象中出现。白人女性，约28岁容貌，五官与伊芙琳高度相似但更柔和温婉，面容精致秀美、气质更为内敛柔和。眼瞳深棕偏暖色调，眼神温柔而带有淡淡忧伤。长发深棕色、长度过肩至胸口、自然柔顺的波浪卷发，发质柔亮。肤色白皙偏暖调，妆容柔美自然、唇色偏粉。表情温柔平静、嘴角带有淡淡微笑。身材纤细优雅。着装为柔美浪漫风格——象牙白色丝质长裙、微V领、裙摆及脚踝，外搭一件浅灰色薄开衫，脚穿裸色平底绑带凉鞋。脖子上同样佩戴与伊芙琳相同款式的银色古朴项链（姐妹对应道具）。整体气质是温婉美好却注定悲剧的角色，纯净而带有幽灵般的空灵感。

人设：欧美暗黑奇幻风格，参考《暮光之城》《吸血鬼日记》的视觉氛围，但塞琳娜本身色调偏柔和暖白、带有回忆滤镜般的朦胧梦幻感，与整体暗黑基调形成对比。写实仿真人风格，高精度角色资产图。', NULL, 'midj_default', 'SUCCESS', 0, 3, NULL, NULL, NULL, '{"cfg": 7, "size": "1024x1536", "count": 1, "steps": 30}', NULL, '2026-04-24 03:38:54.203', '2026-04-24 03:42:37.059', NULL, '{"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "Selena Carter（塞琳娜·卡特），伊芙琳的姐姐，真相的关键人物，已故角色但需要在回忆与幻象中出现。白人女性，约28岁容貌，五官与伊芙琳高度相似但更柔和温婉，面容精致秀美、气质更为内敛柔和。眼瞳深棕偏暖色调，眼神温柔而带有淡淡忧伤。长发深棕色、长度过肩至胸口、自然柔顺的波浪卷发，发质柔亮。肤色白皙偏暖调，妆容柔美自然、唇色偏粉。表情温柔平静、嘴角带有淡淡微笑。身材纤细优雅。着装为柔美浪漫风格——象牙白色丝质长裙、微V领、裙摆及脚踝，外搭一件浅灰色薄开衫，脚穿裸色平底绑带凉鞋。脖子上同样佩戴与伊芙琳相同款式的银色古朴项链（姐妹对应道具）。整体气质是温婉美好却注定悲剧的角色，纯净而带有幽灵般的空灵感。", "part3": "欧美暗黑奇幻风格，参考《暮光之城》《吸血鬼日记》的视觉氛围，但塞琳娜本身色调偏柔和暖白、带有回忆滤镜般的朦胧梦幻感，与整体暗黑基调形成对比。写实仿真人风格，高精度角色资产图。", "part4": null, "source_mode": "template"}', NULL, NULL, NULL, NULL);
INSERT INTO "public"."job_items" VALUES (139, 32, 'IT20260424181419IIM9U', 2, '基于人物定妆照生成人物角色设定三视图。

【画面整体】严格16:9横版构图，画面分为左区和右区两部分。

【左区——面部特写】面部占满左区整个区域，五官/发型/配饰清晰可辨，无身体入镜，无遮挡，无变形，面部居中填满。

【右区——标准角色设定三视图】标准角色设定三视图严格横向排列，从左到右依次为：侧视图（左侧面90度）、正视图（正面0度）、背视图（背面180度）。三个视图必须严格呈现侧视、正视和背视三个角度，从头顶到脚底完整呈现全身，无裁切无遮挡。

【核心一致性约束】左区面部特写与右区三视图必须为完全相同的同一角色，五官/服装/配饰/体态/发型/配色100%一致，不允许出现任何差异。

【右区尺寸规范】三视图中每个角色的高度为画面高度的80%，三个视图高度严格统一对齐，角色间距均匀。

【背景与光影】纯净浅灰色背景，无多余元素，无装饰，无文字，无标注；角色无阴影，无地面投影，无环境反光。

【镜头与分辨率】超高清分辨率，统一85mm焦距，无透视畸变，无广角变形，平视角度（镜头与角色视平线齐平）。

【角色姿态与表情】中性表情（无喜怒哀乐），眼神平静直视前方，自然站立姿势，双手自然下垂贴于身体两侧，无任何动作，无转头无倾斜。

风格：【角色描述】安德烈，35岁男性，身高190cm，身形极为魁梧壮硕，体格如熊般雄壮，肩宽胸厚。面容刚毅棱角分明，如同石头雕刻一般，颧骨突出，下颌线硬朗。蓝色眼睛深邃冰冷，目光锐利。金色短发整齐利落，发型一丝不苟。穿着一件深蓝色军装式外套，外套剪裁笔挺，带有军服风格的立领与肩章设计，胸口佩戴着多枚象征战功的金属勋章，勋章表面有精细雕刻纹饰。下身深色军装长裤，脚穿深色军靴。整体气质威严刚猛，充满军人的强势压迫感。

参考风格：
写实风格，高加索白人男性面孔，注意金色短发与蓝色虹膜的准确呈现，深蓝色军装外套的材质需体现厚实挺括感，胸前金属勋章要有金属反光质感。', NULL, 'midj_default', 'FAILED', 3, 3, NULL, 'E_INTERNAL', 'duplicate key value violates unique constraint "image_results_nas_object_key_key"', '{"size": "1920x1080", "aspect_ratio": "16:9", "negative_prompt": "shadow, ground shadow, drop shadow, cast shadow, reflection, extra limbs, extra fingers, missing fingers, deformed hands, text, watermark, logo, signature, label, annotation, action pose, dynamic pose, tilted head, turned head, smile, frown, angry, sad, surprised, open mouth, teeth showing, lens distortion, wide angle, fisheye, barrel distortion, background objects, props, furniture, decorations, patterns, blurry, low resolution, pixelated, noise, artifacts, body cut off, cropped figure, partial body, missing feet, missing head"}', NULL, '2026-04-24 18:14:57.752', '2026-04-24 18:56:35.073', NULL, '{"part1": "基于人物定妆照生成人物角色设定三视图。\n\n【画面整体】严格16:9横版构图，画面分为左区和右区两部分。\n\n【左区——面部特写】面部占满左区整个区域，五官/发型/配饰清晰可辨，无身体入镜，无遮挡，无变形，面部居中填满。\n\n【右区——标准角色设定三视图】标准角色设定三视图严格横向排列，从左到右依次为：侧视图（左侧面90度）、正视图（正面0度）、背视图（背面180度）。三个视图必须严格呈现侧视、正视和背视三个角度，从头顶到脚底完整呈现全身，无裁切无遮挡。\n\n【核心一致性约束】左区面部特写与右区三视图必须为完全相同的同一角色，五官/服装/配饰/体态/发型/配色100%一致，不允许出现任何差异。\n\n【右区尺寸规范】三视图中每个角色的高度为画面高度的80%，三个视图高度严格统一对齐，角色间距均匀。\n\n【背景与光影】纯净浅灰色背景，无多余元素，无装饰，无文字，无标注；角色无阴影，无地面投影，无环境反光。\n\n【镜头与分辨率】超高清分辨率，统一85mm焦距，无透视畸变，无广角变形，平视角度（镜头与角色视平线齐平）。\n\n【角色姿态与表情】中性表情（无喜怒哀乐），眼神平静直视前方，自然站立姿势，双手自然下垂贴于身体两侧，无任何动作，无转头无倾斜。", "part2": "【角色描述】安德烈，35岁男性，身高190cm，身形极为魁梧壮硕，体格如熊般雄壮，肩宽胸厚。面容刚毅棱角分明，如同石头雕刻一般，颧骨突出，下颌线硬朗。蓝色眼睛深邃冰冷，目光锐利。金色短发整齐利落，发型一丝不苟。穿着一件深蓝色军装式外套，外套剪裁笔挺，带有军服风格的立领与肩章设计，胸口佩戴着多枚象征战功的金属勋章，勋章表面有精细雕刻纹饰。下身深色军装长裤，脚穿深色军靴。整体气质威严刚猛，充满军人的强势压迫感。", "part3": null, "part4": "写实风格，高加索白人男性面孔，注意金色短发与蓝色虹膜的准确呈现，深蓝色军装外套的材质需体现厚实挺括感，胸前金属勋章要有金属反光质感。", "source_mode": "template"}', '角色2', NULL, NULL, NULL);
INSERT INTO "public"."job_items" VALUES (93, 21, 'IT20260424043931W7GKT', 2, '基于人物定妆照生成人物三视图
（16：9）面部占满左区，五官 / 发型 / 配饰清晰，无身体入镜、无遮挡变形；右区：标准角色设定三视图，横向排列（侧视图、正视图、背视图），三个视图严格呈现侧视、正视和背视，从头到脚完整无遮挡；核心约束：特写与三视图为同一角色，五官 / 服装 / 配饰 / 体态 100% 一致；右区尺寸：三视图角色高度画面高度的 80%，三视图高度统一；无多余元素的浅灰色背景，角色无阴影；超高清分辨率，统一85mm焦距，无畸变，角色无动作，平视；中性表情（无喜怒哀乐），眼神平静，自然站立，双手自然下垂。

风格：角色：卢卡斯·布莱克伍德（Lucas Blackwood），30岁白人男性，狼人家族继承人。高大健壮，约188cm，棱角分明的面庞，浓黑短发微乱，深邃幽蓝色瞳孔带有非人的冷光，下颌线锋利，面色苍白。穿着黑色长款羊毛大衣，内搭深灰色亨利领衫，黑色修身长裤，黑色皮靴，左手无名指戴一枚家族纹章银戒。整体气质冷峻、压抑、危险，贵族暗黑王子感。

人设：基于人物定妆照生成人物三视图
