INSERT INTO "public"."job_items" VALUES (152, 35, 'IT202604241832388IUUY', 3, '请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调"角色资产展示"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。

风格：角色名：千岛凛。28岁日本女性，精英学者兼武士。身高165cm，身形纤细如柳，体态轻盈但有力度感，腰身纤细，四肢修长。面容清冷如霜，五官精致锐利，眉形英气，唇色淡雅，面部线条柔中带刚。黑色眼睛锐利如刀，目光冷静而警觉。黑色长发束成一丝不苟的高马尾，发丝顺直光泽，马尾高束利落无碎发。穿着一套黑色改良制服，制服融合了学院风与和风武装元素，立领或小翻领设计，剪裁合身利落，袖口与衣襟有暗纹装饰细节，腰部束带收紧。腰侧配戴一柄古朴武士刀，刀鞘深色木质或漆面质感，刀柄缠绕传统编织带。下装黑色修身长裤或短裙搭配长靴。表情清冷内敛，嘴角微抿，透出隐忍与锋锐。整体气质为冷面女武士学者型，克制而危险。

参考风格：
画风写实偏电影概念美术风格，色调以黑色为主基调，点缀极少暗红或银色细节。突出角色纤细冷冽身姿与武士刀质感。高马尾发型需清晰利落，刀鞘与刀柄细节完整可辨。', NULL, 'midj_default', 'FAILED', 3, 3, NULL, 'E_INTERNAL', 'duplicate key value violates unique constraint "image_results_nas_object_key_key"', '{"cfg": 7, "size": "1024x1536", "count": 1, "steps": 30}', NULL, '2026-04-24 18:32:38.423', '2026-04-24 18:56:35.675', NULL, '{"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色名：千岛凛。28岁日本女性，精英学者兼武士。身高165cm，身形纤细如柳，体态轻盈但有力度感，腰身纤细，四肢修长。面容清冷如霜，五官精致锐利，眉形英气，唇色淡雅，面部线条柔中带刚。黑色眼睛锐利如刀，目光冷静而警觉。黑色长发束成一丝不苟的高马尾，发丝顺直光泽，马尾高束利落无碎发。穿着一套黑色改良制服，制服融合了学院风与和风武装元素，立领或小翻领设计，剪裁合身利落，袖口与衣襟有暗纹装饰细节，腰部束带收紧。腰侧配戴一柄古朴武士刀，刀鞘深色木质或漆面质感，刀柄缠绕传统编织带。下装黑色修身长裤或短裙搭配长靴。表情清冷内敛，嘴角微抿，透出隐忍与锋锐。整体气质为冷面女武士学者型，克制而危险。", "part3": null, "part4": "画风写实偏电影概念美术风格，色调以黑色为主基调，点缀极少暗红或银色细节。突出角色纤细冷冽身姿与武士刀质感。高马尾发型需清晰利落，刀鞘与刀柄细节完整可辨。", "source_mode": "template"}', '角色3', NULL, '{"name": "角色3", "gender": "unknown"}', NULL);
INSERT INTO "public"."job_items" VALUES (151, 35, 'IT202604241832380TGFC', 2, '请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调"角色资产展示"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。

风格：角色名：安德烈。35岁北欧/斯拉夫裔白人男性，北境同盟军事代表。身高190cm，身形魁梧厚实如熊，肩宽胸阔，肌肉结实，体量感强。面容刚毅粗犷，颧骨与下颌线条棱角分明如石刻般硬朗，面部皮肤略粗糙。蓝色眼睛深邃冰冷，目光锐利逼人。金色短发整齐利落，偏军人式寸头或板寸长度。穿着一件深蓝色军装式立领外套，肩部有肩章结构，胸前左侧佩戴数枚象征战功的金属勋章，勋章造型精致可辨，外套剪裁硬挺利落，有军事制服的束带与纽扣细节。下装深蓝色军装裤，搭配深色军靴。双手自然垂于两侧或背于身后，姿态威严庄重。表情冷峻肃穆，透出压迫感与统治力。整体气质为强权军事铁血将领型。

参考风格：
画风写实偏电影概念美术风格，色调偏深蓝冷钢色调，突出角色魁梧威压体量与军装制服金属质感。蓝色眼睛与金色短发需色彩鲜明准确，金属勋章需有光泽反射细节。', NULL, 'midj_default', 'FAILED', 3, 3, NULL, 'E_INTERNAL', 'duplicate key value violates unique constraint "image_results_nas_object_key_key"', '{"cfg": 7, "size": "1024x1536", "count": 1, "steps": 30}', NULL, '2026-04-24 18:32:38.423', '2026-04-24 18:56:31.959', NULL, '{"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色名：安德烈。35岁北欧/斯拉夫裔白人男性，北境同盟军事代表。身高190cm，身形魁梧厚实如熊，肩宽胸阔，肌肉结实，体量感强。面容刚毅粗犷，颧骨与下颌线条棱角分明如石刻般硬朗，面部皮肤略粗糙。蓝色眼睛深邃冰冷，目光锐利逼人。金色短发整齐利落，偏军人式寸头或板寸长度。穿着一件深蓝色军装式立领外套，肩部有肩章结构，胸前左侧佩戴数枚象征战功的金属勋章，勋章造型精致可辨，外套剪裁硬挺利落，有军事制服的束带与纽扣细节。下装深蓝色军装裤，搭配深色军靴。双手自然垂于两侧或背于身后，姿态威严庄重。表情冷峻肃穆，透出压迫感与统治力。整体气质为强权军事铁血将领型。", "part3": null, "part4": "画风写实偏电影概念美术风格，色调偏深蓝冷钢色调，突出角色魁梧威压体量与军装制服金属质感。蓝色眼睛与金色短发需色彩鲜明准确，金属勋章需有光泽反射细节。", "source_mode": "template"}', '角色2', NULL, NULL, NULL);
INSERT INTO "public"."job_items" VALUES (97, 22, 'IT202604240444233-BS6', 1, '基于人物定妆照生成人物三视图
（16：9）面部占满左区，五官 / 发型 / 配饰清晰，无身体入镜、无遮挡变形；右区：标准角色设定三视图，横向排列（侧视图、正视图、背视图），三个视图严格呈现侧视、正视和背视，从头到脚完整无遮挡；核心约束：特写与三视图为同一角色，五官 / 服装 / 配饰 / 体态 100% 一致；右区尺寸：三视图角色高度画面高度的 80%，三视图高度统一；无多余元素的浅灰色背景，角色无阴影；超高清分辨率，统一85mm焦距，无畸变，角色无动作，平视；中性表情（无喜怒哀乐），眼神平静，自然站立，双手自然下垂。

风格：角色：伊芙琳·卡特（Evelyn Carter）。26岁白人女性，纽约记者。中长深棕色微卷发，略过肩，发尾带隐约银色光泽。淡褐绿色眼瞳，瞳孔深处泛极淡银光。面部线条清晰，轻微雀斑分布在鼻梁两侧，皮肤自然偏白。身高约165cm，身材纤瘦但结实。上身穿深棕色合身皮夹克，内搭深灰色圆领亨利衫；下身深蓝色修身牛仔裤，脚穿棕色低跟短靴。脖颈佩戴一条银色弯月吊坠项链（母亲遗物）。无其他首饰，妆容极淡自然。整体气质理性、倔强、干练。

