INSERT INTO "public"."job_items" VALUES (123, 28, 'IT20260424075726SNVFI', 2, '请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调"角色资产展示"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。

风格：北欧/斯拉夫白人男性，35岁，身高190cm，身形极其魁梧壮硕如熊，肩宽体厚，肌肉轮廓明显。面容刚毅深刻如石刻般棱角分明，颧骨与下颌线条硬朗，蓝色眼睛深邃冰冷，目光锐利如鹰，金色短发整齐利落，偏军人式的干净短发。表情严肃冷峻，带有压迫感。穿着一件深蓝色军装式外套，军装剪裁考究，双排扣或立领设计，肩章结构清晰，胸前佩戴数枚象征战功的金属勋章，勋章造型精致有金属光泽。内搭深色高领衬衣，下装为深蓝色军装长裤，脚穿黑色军靴，腰间或有军用腰带。整体气质为强势威压的军事精英。

参考风格：
北境同盟代表角色。勋章需有明确金属质感和精致造型，数量2-4枚，分布在左胸位置。军装整体风格偏近未来科幻感的军事制服，非现实任何国家军装。蓝色眼睛需突出冰冷深邃感。体型需明显大于普通人比例以体现190cm魁梧设定。', NULL, 'midj_default', 'SUCCESS', 0, 3, NULL, NULL, NULL, '{"cfg": 7, "size": "1024x1536", "count": 1, "steps": 30}', NULL, '2026-04-24 07:57:26.686', '2026-04-24 08:01:18.128', NULL, '{"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "北欧/斯拉夫白人男性，35岁，身高190cm，身形极其魁梧壮硕如熊，肩宽体厚，肌肉轮廓明显。面容刚毅深刻如石刻般棱角分明，颧骨与下颌线条硬朗，蓝色眼睛深邃冰冷，目光锐利如鹰，金色短发整齐利落，偏军人式的干净短发。表情严肃冷峻，带有压迫感。穿着一件深蓝色军装式外套，军装剪裁考究，双排扣或立领设计，肩章结构清晰，胸前佩戴数枚象征战功的金属勋章，勋章造型精致有金属光泽。内搭深色高领衬衣，下装为深蓝色军装长裤，脚穿黑色军靴，腰间或有军用腰带。整体气质为强势威压的军事精英。", "part3": null, "part4": "北境同盟代表角色。勋章需有明确金属质感和精致造型，数量2-4枚，分布在左胸位置。军装整体风格偏近未来科幻感的军事制服，非现实任何国家军装。蓝色眼睛需突出冰冷深邃感。体型需明显大于普通人比例以体现190cm魁梧设定。", "source_mode": "template"}', '安德烈', NULL, '{"name": "安德烈", "gender": "unknown"}', NULL);
INSERT INTO "public"."job_items" VALUES (125, 28, 'IT20260424075726_SOCQ', 4, '请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调"角色资产展示"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。

风格：南亚/印度男性，40岁，身高175cm，身形匀称稳健，体态端正从容，既不瘦弱也不壮硕。面容温和慈祥带有微笑，五官深邃立体，棕色眼睛温暖而充满睿智洞察力，黑色卷发自然蓬松，发间已染有几缕银丝，显露阅历。皮肤为温暖的小麦棕色。表情温和可亲但目光深远。穿着白色亚麻长袍，长袍垂至脚踝，面料质感柔软透气有自然褶皱纹理，剪裁宽松优雅。头戴一顶绣金头巾，头巾面料考究，缝有精致金线刺绣纹样，包裹方式庄重。脚穿浅色皮质便鞋或凉鞋。可配有简朴的手环或指环等小饰品。整体气质为儒雅通达的外交智者与贵族学人。

参考风格：
天竺联邦代表角色。白色亚麻长袍需突出面料的自然亚麻质感与垂坠感。绣金头巾为关键辨识元素，金色刺绣纹样需精致可辨，可融合传统印度纹样风格。卷发中的银丝需自然分布。整体色调以白色与金色为主，温暖高雅。微笑需温和而不失威严感。', NULL, 'midj_default', 'SUCCESS', 0, 3, NULL, NULL, NULL, '{"cfg": 7, "size": "1024x1536", "count": 1, "steps": 30}', NULL, '2026-04-24 07:57:26.686', '2026-04-24 08:01:33.739', NULL, '{"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "南亚/印度男性，40岁，身高175cm，身形匀称稳健，体态端正从容，既不瘦弱也不壮硕。面容温和慈祥带有微笑，五官深邃立体，棕色眼睛温暖而充满睿智洞察力，黑色卷发自然蓬松，发间已染有几缕银丝，显露阅历。皮肤为温暖的小麦棕色。表情温和可亲但目光深远。穿着白色亚麻长袍，长袍垂至脚踝，面料质感柔软透气有自然褶皱纹理，剪裁宽松优雅。头戴一顶绣金头巾，头巾面料考究，缝有精致金线刺绣纹样，包裹方式庄重。脚穿浅色皮质便鞋或凉鞋。可配有简朴的手环或指环等小饰品。整体气质为儒雅通达的外交智者与贵族学人。", "part3": null, "part4": "天竺联邦代表角色。白色亚麻长袍需突出面料的自然亚麻质感与垂坠感。绣金头巾为关键辨识元素，金色刺绣纹样需精致可辨，可融合传统印度纹样风格。卷发中的银丝需自然分布。整体色调以白色与金色为主，温暖高雅。微笑需温和而不失威严感。", "source_mode": "template"}', '阿米尔', NULL, '{"name": "阿米尔", "gender": "unknown"}', NULL);
INSERT INTO "public"."job_items" VALUES (183, 48, 'IT20260427181639WLEZ_', 3, '樱花代表，千岛凛，28岁女性，樱花精英学者兼武士

风格：身高165cm，身形纤细如柳，面容清冷似霜，黑色眼睛锐利如刀，黑色长发束成一丝不苟的高马尾，穿着一套黑色改良制服，腰间配戴一柄古朴武士刀

