INSERT INTO "public"."job_items" VALUES (124, 28, 'IT20260424075726YFM4T', 3, '请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调"角色资产展示"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。

风格：日本女性，28岁，身高165cm，身形纤细修长如柳，体态优雅但暗含力量感。面容清冷精致似霜，五官线条利落，黑色眼睛锐利如刀，眼神冷峻，黑色长发束成一丝不苟的高马尾，发丝顺滑服帖，马尾高高束起干净利落。表情冷淡疏离，嘴唇微抿。穿着一套黑色改良制服，融合现代制服剪裁与和风元素，立领或小翻领设计，修身收腰，袖口与衣摆可有暗纹或细节线条，面料质感挺括。腰间配戴一柄古朴武士刀，刀鞘色泽沉稳，刀柄缠绕传统编织。下装为黑色修身长裤或及膝裙配长靴，脚穿黑色短靴或及膝靴。整体气质为冷厉精密的武士学者。

参考风格：
樱花代表角色。改良制服强调黑色主色调，可有极少量暗红或银色细节点缀。武士刀需完整呈现，刀鞘古朴有木纹或漆面质感，佩戴位置在腰侧。高马尾发型需扎紧无碎发，突出干练气质。整体风格为写实偏美型，不走二次元风。', NULL, 'midj_default', 'SUCCESS', 0, 3, NULL, NULL, NULL, '{"cfg": 7, "size": "1024x1536", "count": 1, "steps": 30}', NULL, '2026-04-24 07:57:26.686', '2026-04-24 08:03:05.808', NULL, '{"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "日本女性，28岁，身高165cm，身形纤细修长如柳，体态优雅但暗含力量感。面容清冷精致似霜，五官线条利落，黑色眼睛锐利如刀，眼神冷峻，黑色长发束成一丝不苟的高马尾，发丝顺滑服帖，马尾高高束起干净利落。表情冷淡疏离，嘴唇微抿。穿着一套黑色改良制服，融合现代制服剪裁与和风元素，立领或小翻领设计，修身收腰，袖口与衣摆可有暗纹或细节线条，面料质感挺括。腰间配戴一柄古朴武士刀，刀鞘色泽沉稳，刀柄缠绕传统编织。下装为黑色修身长裤或及膝裙配长靴，脚穿黑色短靴或及膝靴。整体气质为冷厉精密的武士学者。", "part3": null, "part4": "樱花代表角色。改良制服强调黑色主色调，可有极少量暗红或银色细节点缀。武士刀需完整呈现，刀鞘古朴有木纹或漆面质感，佩戴位置在腰侧。高马尾发型需扎紧无碎发，突出干练气质。整体风格为写实偏美型，不走二次元风。", "source_mode": "template"}', '千岛凛', NULL, '{"name": "千岛凛", "gender": "unknown"}', NULL);
INSERT INTO "public"."job_items" VALUES (184, 48, 'IT202604271816397E5FC', 4, '天竺代表，阿米尔，40岁男性，天竺联邦外交官兼智者

风格：身高175cm，身形匀称稳健，面容温和带笑，棕色眼睛充满睿智，黑色卷发间已染几缕银丝，穿着白色亚麻长袍，头戴绣金头巾

参考风格：
出身天竺古老贵族，深谙历史哲学，目的是在擂台上召唤联邦帝王竞争能源配额，同时借机修复天竺被篡改的历史记忆、重塑联邦文明尊严，气质从容睿智', NULL, 'midj_default', 'SUCCESS', 0, 3, NULL, NULL, NULL, '{"cfg": 7, "size": "1024x1536", "count": 1, "steps": 30}', NULL, '2026-04-27 18:16:39.544', '2026-04-27 18:18:39.878', NULL, '{"part1": "天竺代表，阿米尔，40岁男性，天竺联邦外交官兼智者", "part2": "身高175cm，身形匀称稳健，面容温和带笑，棕色眼睛充满睿智，黑色卷发间已染几缕银丝，穿着白色亚麻长袍，头戴绣金头巾", "part3": null, "part4": "出身天竺古老贵族，深谙历史哲学，目的是在擂台上召唤联邦帝王竞争能源配额，同时借机修复天竺被篡改的历史记忆、重塑联邦文明尊严，气质从容睿智", "source_mode": "template"}', '角色4', NULL, '{"name": "角色4", "gender": "unknown"}', NULL);
INSERT INTO "public"."job_items" VALUES (153, 35, 'IT20260424183238JOBB9', 4, '请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调"角色资产展示"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。

风格：角色名：阿米尔。40岁南亚裔男性，天竺联邦外交官兼智者。身高175cm，身形匀称稳健，不胖不瘦，体态从容端庄，站姿沉稳。面容温和宽厚，五官柔和深邃，面带淡淡微笑，轮廓饱满有亲和力。棕色眼睛温润通透，充满睿智与洞察。黑色卷发中长，自然卷曲蓬松，发间已染几缕银丝，显出阅历与沉稳。头戴一顶白色绣金头巾，头巾中央或边缘有精致的金线刺绣花纹，包裹工整讲究。穿着一件白色亚麻长袍，长袍剪裁宽松飘逸，面料质感为天然亚麻的柔软纹理，袍身有细微褶皱与垂坠感，领口与袖口可能有淡金色刺绣装饰。脚穿浅色皮质凉鞋或低帮鞋。双手自然交叠于身前或微微张开，姿态温文尔雅。表情平和睿智，目光柔和但深沉。整体气质为古典贵族智者外交家型，从容不迫、文雅深沉。

参考风格：
画风写实偏电影概念美术风格，色调偏暖白与淡金，突出角色温和睿智气质与白色亚麻长袍的柔和质感。绣金头巾的金线刺绣细节需精致可见，棕色眼睛需温润有光泽。', NULL, 'midj_default', 'FAILED', 3, 3, NULL, 'E_INTERNAL', 'duplicate key value violates unique constraint "image_results_nas_object_key_key"', '{"cfg": 7, "size": "1024x1536", "count": 1, "steps": 30}', NULL, '2026-04-24 18:32:38.423', '2026-04-24 18:56:29.752', NULL, '{"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色名：阿米尔。40岁南亚裔男性，天竺联邦外交官兼智者。身高175cm，身形匀称稳健，不胖不瘦，体态从容端庄，站姿沉稳。面容温和宽厚，五官柔和深邃，面带淡淡微笑，轮廓饱满有亲和力。棕色眼睛温润通透，充满睿智与洞察。黑色卷发中长，自然卷曲蓬松，发间已染几缕银丝，显出阅历与沉稳。头戴一顶白色绣金头巾，头巾中央或边缘有精致的金线刺绣花纹，包裹工整讲究。穿着一件白色亚麻长袍，长袍剪裁宽松飘逸，面料质感为天然亚麻的柔软纹理，袍身有细微褶皱与垂坠感，领口与袖口可能有淡金色刺绣装饰。脚穿浅色皮质凉鞋或低帮鞋。双手自然交叠于身前或微微张开，姿态温文尔雅。表情平和睿智，目光柔和但深沉。整体气质为古典贵族智者外交家型，从容不迫、文雅深沉。", "part3": null, "part4": "画风写实偏电影概念美术风格，色调偏暖白与淡金，突出角色温和睿智气质与白色亚麻长袍的柔和质感。绣金头巾的金线刺绣细节需精致可见，棕色眼睛需温润有光泽。", "source_mode": "template"}', '角色4', NULL, '{"name": "角色4", "gender": "unknown"}', NULL);
INSERT INTO "public"."job_items" VALUES (133, 30, 'IT20260424180907XAEPA', 4, '请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调"角色资产展示"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。

风格：角色：阿米尔，40岁男性，南亚贵族智者外交官气质。身高175cm，身形匀称稳健，体态从容端正，不胖不瘦，带有成熟男性的沉稳体格。面容温和带有淡淡笑意，五官深邃立体，鼻梁高挺，眉骨微隆，面部线条柔和而有智慧感。棕色眼睛温润深沉，充满睿智与洞察力。黑色卷发中长，卷曲自然蓬松，发间夹杂几缕银丝，显示成熟阅历。肤色为温暖的小麦棕色。穿着一件白色亚麻长袍，长袍质地轻柔飘逸，面料纹理自然，剪裁宽松但不邋遢，衣身有细密的暗纹或边缘刺绣装饰。头戴绣金头巾，头巾以白色或米色为底，边缘与正面有精致的金线刺绣纹样，包裹方式端正传统。脚穿浅色皮质凉鞋或平底鞋。可配戴手腕处的串珠或指环等细节饰品。整体造型素雅庄重，散发古老文明的智慧与尊严感。

参考风格：
画风：写实偏影视概念设定风格，光影温暖柔和，色调以暖白、米金、棕色为主，突出角色温厚睿智的贵族学者气质。注意白色亚麻长袍的面料垂坠纹理、绣金头巾的金线刺绣细节，以及卷发中银丝的自然过渡。', NULL, 'midj_default', 'SUCCESS', 0, 3, NULL, NULL, NULL, '{"cfg": 7, "size": "1024x1536", "count": 1, "steps": 30}', NULL, '2026-04-24 18:09:07.405', '2026-04-24 18:09:49.143', NULL, '{"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色：阿米尔，40岁男性，南亚贵族智者外交官气质。身高175cm，身形匀称稳健，体态从容端正，不胖不瘦，带有成熟男性的沉稳体格。面容温和带有淡淡笑意，五官深邃立体，鼻梁高挺，眉骨微隆，面部线条柔和而有智慧感。棕色眼睛温润深沉，充满睿智与洞察力。黑色卷发中长，卷曲自然蓬松，发间夹杂几缕银丝，显示成熟阅历。肤色为温暖的小麦棕色。穿着一件白色亚麻长袍，长袍质地轻柔飘逸，面料纹理自然，剪裁宽松但不邋遢，衣身有细密的暗纹或边缘刺绣装饰。头戴绣金头巾，头巾以白色或米色为底，边缘与正面有精致的金线刺绣纹样，包裹方式端正传统。脚穿浅色皮质凉鞋或平底鞋。可配戴手腕处的串珠或指环等细节饰品。整体造型素雅庄重，散发古老文明的智慧与尊严感。", "part3": null, "part4": "画风：写实偏影视概念设定风格，光影温暖柔和，色调以暖白、米金、棕色为主，突出角色温厚睿智的贵族学者气质。注意白色亚麻长袍的面料垂坠纹理、绣金头巾的金线刺绣细节，以及卷发中银丝的自然过渡。", "source_mode": "template"}', '角色4', NULL, '{"name": "角色4", "gender": "unknown"}', NULL);
INSERT INTO "public"."job_items" VALUES (132, 30, 'IT20260424180907D9MB2', 3, '请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调"角色资产展示"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。

风格：角色：千岛凛，28岁女性，日系精英武士学者气质。身高165cm，身形纤细如柳，体态修长轻盈但不显柔弱，隐含武者的紧绷与力量感。面容清冷似霜，五官精致锐利，下巴尖削，唇线薄而紧抿，表情冷淡克制。黑色眼睛锐利如刀，目光冷厉有穿透力。黑色长发浓密顺滑，束成一丝不苟的高马尾，马尾高扎利落，发丝整齐无散乱，额前无碎发遮挡。肤色白皙细腻。穿着一套黑色改良制服，上衣为立领收腰设计，融合日式学院制服与武士装束元素，衣身剪裁利落贴身，面料哑光黑色，袖口与领口有细密纹样暗纹。腰间系有窄带，左侧腰间配戴一柄古朴武士刀，刀鞘深色漆面，刀柄缠绳细节可见。下身黑色修身长裤或裙裤，脚穿黑色短靴。整体造型黑色系为主，干练、锐利、冷傲。

参考风格：
画风：写实偏影视概念设定风格，光影冷锐干净，色调以纯黑、冷白、暗灰为主，突出角色清冷凌厉的武士学者气质。注意高马尾的发丝光泽、武士刀的古朴金属与缠绳质感，以及改良制服的暗纹细节。', NULL, 'midj_default', 'SUCCESS', 0, 3, NULL, NULL, NULL, '{"cfg": 7, "size": "1024x1536", "count": 1, "steps": 30}', NULL, '2026-04-24 18:09:07.405', '2026-04-24 18:09:53.104', NULL, '{"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色：千岛凛，28岁女性，日系精英武士学者气质。身高165cm，身形纤细如柳，体态修长轻盈但不显柔弱，隐含武者的紧绷与力量感。面容清冷似霜，五官精致锐利，下巴尖削，唇线薄而紧抿，表情冷淡克制。黑色眼睛锐利如刀，目光冷厉有穿透力。黑色长发浓密顺滑，束成一丝不苟的高马尾，马尾高扎利落，发丝整齐无散乱，额前无碎发遮挡。肤色白皙细腻。穿着一套黑色改良制服，上衣为立领收腰设计，融合日式学院制服与武士装束元素，衣身剪裁利落贴身，面料哑光黑色，袖口与领口有细密纹样暗纹。腰间系有窄带，左侧腰间配戴一柄古朴武士刀，刀鞘深色漆面，刀柄缠绳细节可见。下身黑色修身长裤或裙裤，脚穿黑色短靴。整体造型黑色系为主，干练、锐利、冷傲。", "part3": null, "part4": "画风：写实偏影视概念设定风格，光影冷锐干净，色调以纯黑、冷白、暗灰为主，突出角色清冷凌厉的武士学者气质。注意高马尾的发丝光泽、武士刀的古朴金属与缠绳质感，以及改良制服的暗纹细节。", "source_mode": "template"}', '角色3', NULL, '{"name": "角色3", "gender": "unknown"}', NULL);
INSERT INTO "public"."job_items" VALUES (137, 31, 'IT20260424181411AXLT0', 4, '基于人物定妆照生成人物角色设定三视图。

【画面整体】严格16:9横版构图，画面分为左区和右区两部分。

【左区——面部特写】面部占满左区整个区域，五官/发型/配饰清晰可辨，无身体入镜，无遮挡，无变形，面部居中填满。

【右区——标准角色设定三视图】标准角色设定三视图严格横向排列，从左到右依次为：侧视图（左侧面90度）、正视图（正面0度）、背视图（背面180度）。三个视图必须严格呈现侧视、正视和背视三个角度，从头顶到脚底完整呈现全身，无裁切无遮挡。

【核心一致性约束】左区面部特写与右区三视图必须为完全相同的同一角色，五官/服装/配饰/体态/发型/配色100%一致，不允许出现任何差异。

【右区尺寸规范】三视图中每个角色的高度为画面高度的80%，三个视图高度严格统一对齐，角色间距均匀。

【背景与光影】纯净浅灰色背景，无多余元素，无装饰，无文字，无标注；角色无阴影，无地面投影，无环境反光。

【镜头与分辨率】超高清分辨率，统一85mm焦距，无透视畸变，无广角变形，平视角度（镜头与角色视平线齐平）。

【角色姿态与表情】中性表情（无喜怒哀乐），眼神平静直视前方，自然站立姿势，双手自然下垂贴于身体两侧，无任何动作，无转头无倾斜。

风格：【角色描述】阿米尔，40岁男性，身高175cm，身形匀称稳健，体态端正从容。面容温和宽厚，带有内敛的笑意，五官柔和饱满，眉眼间透出智慧。棕色眼睛温润深沉，充满睿智光芒。黑色自然卷发及耳，发间已染有几缕银丝，卷发蓬松柔软。头戴一顶绣有精致金色花纹的头巾，头巾包裹整齐。穿着一件白色亚麻长袍，长袍宽松垂坠，面料质朴天然，袍身剪裁简洁大方，袍边有细致的浅色纹饰。脚穿浅色皮质凉鞋。整体气质儒雅从容，散发着古老文明的贵族学者风范。

参考风格：
写实风格，南亚男性面孔，肤色偏深小麦色，注意黑色卷发中银丝的自然过渡，绣金头巾的金色花纹需精细可辨，白色亚麻长袍需体现天然麻布的肌理质感与垂坠感。', NULL, 'midj_default', 'SUCCESS', 0, 3, NULL, NULL, NULL, '{"size": "1920x1080", "aspect_ratio": "16:9", "negative_prompt": "shadow, ground shadow, drop shadow, cast shadow, reflection, extra limbs, extra fingers, missing fingers, deformed hands, text, watermark, logo, signature, label, annotation, action pose, dynamic pose, tilted head, turned head, smile, frown, angry, sad, surprised, open mouth, teeth showing, lens distortion, wide angle, fisheye, barrel distortion, background objects, props, furniture, decorations, patterns, blurry, low resolution, pixelated, noise, artifacts, body cut off, cropped figure, partial body, missing feet, missing head"}', NULL, '2026-04-24 18:14:11.095', '2026-04-24 18:14:52.446', NULL, '{"part1": "基于人物定妆照生成人物角色设定三视图。\n\n【画面整体】严格16:9横版构图，画面分为左区和右区两部分。\n\n【左区——面部特写】面部占满左区整个区域，五官/发型/配饰清晰可辨，无身体入镜，无遮挡，无变形，面部居中填满。\n\n【右区——标准角色设定三视图】标准角色设定三视图严格横向排列，从左到右依次为：侧视图（左侧面90度）、正视图（正面0度）、背视图（背面180度）。三个视图必须严格呈现侧视、正视和背视三个角度，从头顶到脚底完整呈现全身，无裁切无遮挡。\n\n【核心一致性约束】左区面部特写与右区三视图必须为完全相同的同一角色，五官/服装/配饰/体态/发型/配色100%一致，不允许出现任何差异。\n\n【右区尺寸规范】三视图中每个角色的高度为画面高度的80%，三个视图高度严格统一对齐，角色间距均匀。\n\n【背景与光影】纯净浅灰色背景，无多余元素，无装饰，无文字，无标注；角色无阴影，无地面投影，无环境反光。\n\n【镜头与分辨率】超高清分辨率，统一85mm焦距，无透视畸变，无广角变形，平视角度（镜头与角色视平线齐平）。\n\n【角色姿态与表情】中性表情（无喜怒哀乐），眼神平静直视前方，自然站立姿势，双手自然下垂贴于身体两侧，无任何动作，无转头无倾斜。", "part2": "【角色描述】阿米尔，40岁男性，身高175cm，身形匀称稳健，体态端正从容。面容温和宽厚，带有内敛的笑意，五官柔和饱满，眉眼间透出智慧。棕色眼睛温润深沉，充满睿智光芒。黑色自然卷发及耳，发间已染有几缕银丝，卷发蓬松柔软。头戴一顶绣有精致金色花纹的头巾，头巾包裹整齐。穿着一件白色亚麻长袍，长袍宽松垂坠，面料质朴天然，袍身剪裁简洁大方，袍边有细致的浅色纹饰。脚穿浅色皮质凉鞋。整体气质儒雅从容，散发着古老文明的贵族学者风范。", "part3": null, "part4": "写实风格，南亚男性面孔，肤色偏深小麦色，注意黑色卷发中银丝的自然过渡，绣金头巾的金色花纹需精细可辨，白色亚麻长袍需体现天然麻布的肌理质感与垂坠感。", "source_mode": "template"}', '角色4', NULL, '{"name": "角色4", "gender": "unknown"}', NULL);
INSERT INTO "public"."job_items" VALUES (136, 31, 'IT202604241814114TIYD', 3, '基于人物定妆照生成人物角色设定三视图。

【画面整体】严格16:9横版构图，画面分为左区和右区两部分。

【左区——面部特写】面部占满左区整个区域，五官/发型/配饰清晰可辨，无身体入镜，无遮挡，无变形，面部居中填满。

【右区——标准角色设定三视图】标准角色设定三视图严格横向排列，从左到右依次为：侧视图（左侧面90度）、正视图（正面0度）、背视图（背面180度）。三个视图必须严格呈现侧视、正视和背视三个角度，从头顶到脚底完整呈现全身，无裁切无遮挡。

【核心一致性约束】左区面部特写与右区三视图必须为完全相同的同一角色，五官/服装/配饰/体态/发型/配色100%一致，不允许出现任何差异。

【右区尺寸规范】三视图中每个角色的高度为画面高度的80%，三个视图高度严格统一对齐，角色间距均匀。

【背景与光影】纯净浅灰色背景，无多余元素，无装饰，无文字，无标注；角色无阴影，无地面投影，无环境反光。

【镜头与分辨率】超高清分辨率，统一85mm焦距，无透视畸变，无广角变形，平视角度（镜头与角色视平线齐平）。

【角色姿态与表情】中性表情（无喜怒哀乐），眼神平静直视前方，自然站立姿势，双手自然下垂贴于身体两侧，无任何动作，无转头无倾斜。

风格：【角色描述】千岛凛，28岁女性，身高165cm，身形纤细修长如柳枝，体态轻盈。面容清冷如霜，五官精致冷峻，薄唇紧抿，表情疏离。黑色眼睛锐利如刀锋，目光冰冷犀利。黑色长发束成一丝不苟的高马尾，发丝顺滑笔直，无碎发。穿着一套黑色改良制服，制服剪裁合身利落，融合东方传统与现代军事风格，衣领整齐，袖口收紧。腰间左侧佩戴一柄古朴武士刀，刀鞘为深色木质，刀柄缠绕传统织布。下身黑色修身长裤，脚穿黑色短靴。整体气质冷厉肃杀，如出鞘利刃。

参考风格：
写实风格，东亚年轻女性面孔，注意高马尾发型的整洁束感与黑色长发的垂顺质感，黑色改良制服需体现面料挺括与东方元素融合，腰间武士刀的古朴木鞘与缠绕刀柄需清晰可辨。', NULL, 'midj_default', 'SUCCESS', 0, 3, NULL, NULL, NULL, '{"size": "1920x1080", "aspect_ratio": "16:9", "negative_prompt": "shadow, ground shadow, drop shadow, cast shadow, reflection, extra limbs, extra fingers, missing fingers, deformed hands, text, watermark, logo, signature, label, annotation, action pose, dynamic pose, tilted head, turned head, smile, frown, angry, sad, surprised, open mouth, teeth showing, lens distortion, wide angle, fisheye, barrel distortion, background objects, props, furniture, decorations, patterns, blurry, low resolution, pixelated, noise, artifacts, body cut off, cropped figure, partial body, missing feet, missing head"}', NULL, '2026-04-24 18:14:11.095', '2026-04-24 18:14:57.667', NULL, '{"part1": "基于人物定妆照生成人物角色设定三视图。\n\n【画面整体】严格16:9横版构图，画面分为左区和右区两部分。\n\n【左区——面部特写】面部占满左区整个区域，五官/发型/配饰清晰可辨，无身体入镜，无遮挡，无变形，面部居中填满。\n\n【右区——标准角色设定三视图】标准角色设定三视图严格横向排列，从左到右依次为：侧视图（左侧面90度）、正视图（正面0度）、背视图（背面180度）。三个视图必须严格呈现侧视、正视和背视三个角度，从头顶到脚底完整呈现全身，无裁切无遮挡。\n\n【核心一致性约束】左区面部特写与右区三视图必须为完全相同的同一角色，五官/服装/配饰/体态/发型/配色100%一致，不允许出现任何差异。\n\n【右区尺寸规范】三视图中每个角色的高度为画面高度的80%，三个视图高度严格统一对齐，角色间距均匀。\n\n【背景与光影】纯净浅灰色背景，无多余元素，无装饰，无文字，无标注；角色无阴影，无地面投影，无环境反光。\n\n【镜头与分辨率】超高清分辨率，统一85mm焦距，无透视畸变，无广角变形，平视角度（镜头与角色视平线齐平）。\n\n【角色姿态与表情】中性表情（无喜怒哀乐），眼神平静直视前方，自然站立姿势，双手自然下垂贴于身体两侧，无任何动作，无转头无倾斜。", "part2": "【角色描述】千岛凛，28岁女性，身高165cm，身形纤细修长如柳枝，体态轻盈。面容清冷如霜，五官精致冷峻，薄唇紧抿，表情疏离。黑色眼睛锐利如刀锋，目光冰冷犀利。黑色长发束成一丝不苟的高马尾，发丝顺滑笔直，无碎发。穿着一套黑色改良制服，制服剪裁合身利落，融合东方传统与现代军事风格，衣领整齐，袖口收紧。腰间左侧佩戴一柄古朴武士刀，刀鞘为深色木质，刀柄缠绕传统织布。下身黑色修身长裤，脚穿黑色短靴。整体气质冷厉肃杀，如出鞘利刃。", "part3": null, "part4": "写实风格，东亚年轻女性面孔，注意高马尾发型的整洁束感与黑色长发的垂顺质感，黑色改良制服需体现面料挺括与东方元素融合，腰间武士刀的古朴木鞘与缠绕刀柄需清晰可辨。", "source_mode": "template"}', '角色3', NULL, '{"name": "角色3", "gender": "unknown"}', NULL);
