INSERT INTO "public"."job_items" VALUES (149, 34, 'IT202604241822278V0B2', 4, '请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调"角色资产展示"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。

风格：角色名：阿米尔。40岁男性，天竺联邦外交官兼智者。身高175cm，身形匀称稳健，体态端正从容，既不消瘦也不壮硕，中等偏沉稳。面容温和慈蔼，带淡淡微笑，五官轮廓深邃，南亚面孔。棕色眼睛充满睿智与洞察力，目光柔和而深远。黑色卷发自然蓬松，发间已染几缕银丝，增添成熟智者气质。肤色为温暖的小麦棕色。穿着白色亚麻长袍，面料质感自然柔软，长袍剪裁宽松飘逸，领口与袖口可带细致暗纹或刺绣装饰。头戴绣金头巾，头巾上有精致的金色刺绣纹样，包裹方式整洁讲究。脚穿浅色或棕色传统皮质便鞋。可配简约手环或指环等小饰品。整体造型白色与金色为主调，温润大气，外交官的从容优雅与智者的哲思沉稳并存。

参考风格：
天竺代表，气质关键词：温和睿智、匀称稳健、从容大气、哲思沉静。绣金头巾与白色亚麻长袍是重要辨识特征，卷发间的银丝需清晰体现。', NULL, 'midj_default', 'FAILED', 3, 3, NULL, 'E_INTERNAL', 'duplicate key value violates unique constraint "image_results_nas_object_key_key"', '{"cfg": 7, "size": "1024x1536", "count": 1, "steps": 30}', NULL, '2026-04-24 18:22:53.125', '2026-04-24 18:56:32.178', NULL, '{"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色名：阿米尔。40岁男性，天竺联邦外交官兼智者。身高175cm，身形匀称稳健，体态端正从容，既不消瘦也不壮硕，中等偏沉稳。面容温和慈蔼，带淡淡微笑，五官轮廓深邃，南亚面孔。棕色眼睛充满睿智与洞察力，目光柔和而深远。黑色卷发自然蓬松，发间已染几缕银丝，增添成熟智者气质。肤色为温暖的小麦棕色。穿着白色亚麻长袍，面料质感自然柔软，长袍剪裁宽松飘逸，领口与袖口可带细致暗纹或刺绣装饰。头戴绣金头巾，头巾上有精致的金色刺绣纹样，包裹方式整洁讲究。脚穿浅色或棕色传统皮质便鞋。可配简约手环或指环等小饰品。整体造型白色与金色为主调，温润大气，外交官的从容优雅与智者的哲思沉稳并存。", "part3": null, "part4": "天竺代表，气质关键词：温和睿智、匀称稳健、从容大气、哲思沉静。绣金头巾与白色亚麻长袍是重要辨识特征，卷发间的银丝需清晰体现。", "source_mode": "template"}', '角色4', NULL, '{"name": "角色4", "gender": "unknown"}', NULL);
INSERT INTO "public"."job_items" VALUES (71, 16, 'IT20260424033741IYYFZ', 5, '请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调"角色资产展示"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。

风格：一位约70岁的欧美老年男性，布莱克伍德狼人家族的长老与祭司，知晓族群所有秘密的智者。面容苍老而威严，深刻的皱纹布满额头与眼角，颧骨高耸，面颊凹陷，下颌瘦削但轮廓硬朗。银白色长发稀疏后梳至肩部，发质干枯略带野性。蓄有修剪整齐的银白短胡须。瞳色为浑浊的灰蓝色，眼神深邃幽远，透出古老的智慧与隐忍。肤色苍白偏灰，皮肤纹理粗糙真实，双手布满老茧与青筋。身材瘦高微驼，体态带有长者的沉稳。身穿深墨绿色长袍式大衣，面料厚重粗糙如粗花呢与亚麻混织，领口和袖口绣有古老的狼族符文图案。内搭深褐色粗织高领毛衫。下身深灰色宽松长裤，脚踩深棕色旧皮靴，靴面有磨损痕迹。腰间系一条编织皮绳腰带，悬挂一个小皮囊和几个古老护符。左手持一根深色木纹手杖，杖头雕有狼首。右手无名指戴一枚古旧的青铜戒指。整体风格为暗黑奇幻中的古老智者，色调以墨绿、深褐、银灰为主，气质沧桑、神秘、深沉而可信赖。

