INSERT INTO "public"."job_items" VALUES (148, 34, 'IT20260424182227T2OM2', 3, '请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调"角色资产展示"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。

风格：角色名：千岛凛。28岁女性，樱花精英学者兼武士。身高165cm，身形纤细如柳，体态修长轻盈但暗含力量感。面容清冷似霜，五官精致偏冷感，表情淡漠克制。黑色眼睛锐利如刀，目光冷峻专注。黑色长发束成一丝不苟的高马尾，发丝顺直光泽，马尾整洁利落无碎发。肤色白皙细腻。穿着一套黑色改良制服，剪裁利落贴身，融合现代感与传统武士服饰元素，领口与袖口可带简约暗纹细节，面料质感挺括。腰间配戴一柄古朴武士刀，刀鞘造型古典，握柄缠绕传统绑带。下身黑色修身长裤或裙裤，脚穿黑色短靴。整体造型黑色为主调，冷冽干练，学者的知性与武士的杀伐气并存。

参考风格：
樱花代表，气质关键词：清冷似霜、纤细如柳、锐利如刀、一丝不苟。高马尾与古朴武士刀是重要辨识特征，黑色改良制服需体现传统与现代融合感。', NULL, 'midj_default', 'FAILED', 3, 3, NULL, 'E_INTERNAL', 'duplicate key value violates unique constraint "image_results_nas_object_key_key"', '{"cfg": 7, "size": "1024x1536", "count": 1, "steps": 30}', NULL, '2026-04-24 18:22:53.125', '2026-04-24 18:56:39.037', NULL, '{"part1": "请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调\"角色资产展示\"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。", "part2": "角色名：千岛凛。28岁女性，樱花精英学者兼武士。身高165cm，身形纤细如柳，体态修长轻盈但暗含力量感。面容清冷似霜，五官精致偏冷感，表情淡漠克制。黑色眼睛锐利如刀，目光冷峻专注。黑色长发束成一丝不苟的高马尾，发丝顺直光泽，马尾整洁利落无碎发。肤色白皙细腻。穿着一套黑色改良制服，剪裁利落贴身，融合现代感与传统武士服饰元素，领口与袖口可带简约暗纹细节，面料质感挺括。腰间配戴一柄古朴武士刀，刀鞘造型古典，握柄缠绕传统绑带。下身黑色修身长裤或裙裤，脚穿黑色短靴。整体造型黑色为主调，冷冽干练，学者的知性与武士的杀伐气并存。", "part3": null, "part4": "樱花代表，气质关键词：清冷似霜、纤细如柳、锐利如刀、一丝不苟。高马尾与古朴武士刀是重要辨识特征，黑色改良制服需体现传统与现代融合感。", "source_mode": "template"}', '角色3', NULL, '{"name": "角色3", "gender": "unknown"}', NULL);
INSERT INTO "public"."job_items" VALUES (69, 16, 'IT20260424033741ROX07', 3, '请生成一张高完成度角色定妆照资产图，角色居中正面站立或微侧身展示，完整清晰呈现人物外形设定与服装造型，强调"角色资产展示"用途而非剧情场景。画面重点突出人物本体，五官精致稳定，脸型清晰，发型完整，发丝细腻，妆容准确，表情自然克制，眼神有神但不过度夸张。服装结构完整可辨，层次清楚，材质真实，纹样与配饰位置准确，鞋履、腰饰、头饰、手部细节齐全，整体设计统一且便于后续持续复用。光影干净通透，色彩统一高级，边缘清晰，无过强动态，无大幅透视变形。背景使用纯色、浅灰或干净渐变背景，可带极弱环境光，不添加复杂场景，确保人物轮廓完整突出。构图为标准角色定妆照/角色设定图形式，适合角色库归档与后续批量镜头统一。

风格：一位28岁的欧美男性，卢卡斯同父异母的兄长，狼群中的叛徒与野心家。面容英俊但带有邪魅之气，五官精致略带阴柔，薄唇微勾似笑非笑，笑容迷人却令人不寒而栗。深棕色头发向后梳理得一丝不苟，两侧剃短，顶部较长，发型精致考究。瞳色为琥珀偏金色，眼神狡黠锐利，带有掠食者般的审视感。肤色白皙偏冷，面部轮廓略比卢卡斯柔和但更具攻击性。身材修长精干，体态优雅从容，举止带有贵族式的傲慢。身穿深酒红色丝绒西装外套，剪裁贴身精致，内搭黑色高领打底衫，下身黑色修身西裤，脚踩光面黑色尖头皮鞋。右手佩戴一枚暗红宝石戒指，左手腕戴一条细银链，胸前西装口袋露出一角黑色丝质口袋巾。整体风格为暗黑魅力反派，色调以深酒红、黑色、暗金为主，气质野心勃勃、优雅危险、充满欺骗性的魅力。

