-- ----------------------------
-- Table structure for model_configs
-- ----------------------------
DROP TABLE IF EXISTS "public"."model_configs";
CREATE TABLE "public"."model_configs" (
  "id" int8 NOT NULL DEFAULT nextval('model_configs_id_seq'::regclass),
  "model_key" text COLLATE "pg_catalog"."default" NOT NULL,
  "capability" "public"."Capability" NOT NULL,
  "provider" text COLLATE "pg_catalog"."default" NOT NULL,
  "endpoint" text COLLATE "pg_catalog"."default" NOT NULL,
  "enabled" bool NOT NULL DEFAULT true,
  "is_default" bool NOT NULL DEFAULT false,
  "allow_front_select" bool NOT NULL DEFAULT false,
  "default_params" jsonb NOT NULL,
  "timeout_sec" int4 NOT NULL DEFAULT 90,
  "created_at" timestamp(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "updated_at" timestamp(3) NOT NULL
)
;
COMMENT ON COLUMN "public"."model_configs"."id" IS '主键ID。';
COMMENT ON COLUMN "public"."model_configs"."model_key" IS '模型标识（在同一能力下唯一）。';
COMMENT ON COLUMN "public"."model_configs"."capability" IS '所属图片能力类型。';
COMMENT ON COLUMN "public"."model_configs"."provider" IS '模型提供方。';
COMMENT ON COLUMN "public"."model_configs"."endpoint" IS '模型调用地址。';
COMMENT ON COLUMN "public"."model_configs"."enabled" IS '是否启用。';
COMMENT ON COLUMN "public"."model_configs"."is_default" IS '是否默认模型。';
COMMENT ON COLUMN "public"."model_configs"."allow_front_select" IS '是否允许前端手动选择。';
COMMENT ON COLUMN "public"."model_configs"."default_params" IS '模型默认参数（JSON）。';
COMMENT ON COLUMN "public"."model_configs"."timeout_sec" IS '模型调用超时时间（秒）。';
COMMENT ON COLUMN "public"."model_configs"."created_at" IS '创建时间。';
COMMENT ON COLUMN "public"."model_configs"."updated_at" IS '更新时间（由应用层维护）。';
COMMENT ON TABLE "public"."model_configs" IS '模型配置表：记录各能力可用模型、默认参数和开关。';

