-- ----------------------------
-- Function structure for check_source_portrait_valid
-- ----------------------------
DROP FUNCTION IF EXISTS "public"."check_source_portrait_valid"();
CREATE FUNCTION "public"."check_source_portrait_valid"()
  RETURNS "pg_catalog"."trigger" AS $BODY$
DECLARE
  v_is_selected BOOLEAN;
  v_capability  "public"."Capability";
BEGIN
  -- 为空时不校验
  IF NEW."source_portrait_id" IS NULL THEN
    RETURN NEW;
  END IF;

  -- UPDATE 场景下 source_portrait_id 未变化则跳过
  IF TG_OP = 'UPDATE'
     AND OLD."source_portrait_id" IS NOT DISTINCT FROM NEW."source_portrait_id" THEN
    RETURN NEW;
  END IF;

  SELECT "is_selected_portrait", "capability"
    INTO v_is_selected, v_capability
    FROM "public"."image_results"
   WHERE "id" = NEW."source_portrait_id";

  IF NOT FOUND THEN
    RAISE EXCEPTION
      'source_portrait_id=% 不存在于 image_results',
      NEW."source_portrait_id";
  END IF;

  IF v_capability <> 'PORTRAIT' THEN
    RAISE EXCEPTION
      'source_portrait_id=% 引用的图片 capability=%，必须是 PORTRAIT',
      NEW."source_portrait_id", v_capability;
  END IF;

  IF v_is_selected IS NOT TRUE THEN
    RAISE EXCEPTION
      'source_portrait_id=% 引用的图片尚未被选中（is_selected_portrait=false）',
      NEW."source_portrait_id";
  END IF;

  RETURN NEW;
END;
$BODY$
  LANGUAGE plpgsql VOLATILE
  COST 100;
COMMENT ON FUNCTION "public"."check_source_portrait_valid"() IS '校验 job_items.source_portrait_id 必须引用 capability=PORTRAIT 且 is_selected_portrait=TRUE 的 image_results 行。';

-- ----------------------------
-- Function structure for prevent_invalid_referenced_portrait
-- ----------------------------
DROP FUNCTION IF EXISTS "public"."prevent_invalid_referenced_portrait"();
CREATE FUNCTION "public"."prevent_invalid_referenced_portrait"()
  RETURNS "pg_catalog"."trigger" AS $BODY$
BEGIN
  IF NEW."is_selected_portrait" IS TRUE
     AND NEW."capability" = 'PORTRAIT'::"public"."Capability" THEN
    RETURN NEW;
  END IF;

  IF EXISTS (
    SELECT 1
      FROM "public"."job_items"
     WHERE "source_portrait_id" = OLD."id"
     LIMIT 1
  ) THEN
    RAISE EXCEPTION
      'image_results.id=% 已被 job_items.source_portrait_id 引用，不能取消选中或改为非 PORTRAIT',
      OLD."id";
  END IF;

  RETURN NEW;
END;
$BODY$
  LANGUAGE plpgsql VOLATILE
  COST 100;
COMMENT ON FUNCTION "public"."prevent_invalid_referenced_portrait"() IS '禁止已被 job_items.source_portrait_id 引用的 image_results 行被更新成非已选 PORTRAIT。';

